function policyHistToEntries(history,p){
  const all=[
    ...(p.lastEvaluated?[{when:p.lastEvaluated+" · 14:32",who:"system",action:`Policy evaluated — ${p.compliancePct}% compliance`,type:"eval"}]:[]),
    ...(p.schedule?[{when:"2026-05-19 · 08:00",who:"system",action:`Scheduled evaluation — ${p.violations} violation${p.violations!==1?"s":""} detected`,type:"eval"}]:[]),
    ...(history||[]).map(h=>({...h,type:"history"})),
  ];
  return all.map((h,i)=>{
    const a=h.action.toLowerCase();
    const cat=h.type==="eval"?"SYSTEM":
      a.includes("deprecat")||a.includes("activat")||a.includes("publish")||a.includes("approv")||a.includes("submit")||a.includes("review")?"CERT":
      a.includes("rule")?"SCHEMA":a.includes("link")||a.includes("asset")?"LINEAGE":"EDIT";
    return{id:`p${i}`,timestamp:h.when,category:cat,action:h.action,
      details:h.type==="eval"?`Compliance: ${p.compliancePct}%  ·  Violations: ${p.violations}`:"",
      actor:h.who,isSystem:h.who==="system"||h.type==="eval",note:null,diff:null};
  });
}

// ─────────────────────────────────────────────
// AuditLogTable — universal audit log component
// ─────────────────────────────────────────────
const AuditLogTable=({entries=[],pageSize=20,hideActorFilter=false})=>{
  const [search,    setSearch]    =useState("");
  const [catSel,    setCatSel]    =useState([]);   // [] = all
  const [actSel,    setActSel]    =useState([]);   // [] = all; values: "Users","System"
  const [page,      setPage]      =useState(1);
  const [expanded,  setExpanded]  =useState(null);
  const [openDrop,  setOpenDrop]  =useState(null); // "cat"|"act"|null

  useEffect(()=>setPage(1),[search,catSel,actSel]);

  const cats=useMemo(()=>[...new Set(entries.map(e=>e.category))].filter(Boolean),[entries]);

  const toggleCat=c=>setCatSel(prev=>prev.includes(c)?prev.filter(x=>x!==c):[...prev,c]);
  const toggleAct=a=>setActSel(prev=>prev.includes(a)?prev.filter(x=>x!==a):[...prev,a]);

  const filtered=useMemo(()=>{
    const q=search.toLowerCase();
    return entries.filter(e=>{
      if(q&&!(e.action||"").toLowerCase().includes(q)&&!(e.details||"").toLowerCase().includes(q)&&!(e.actor||"").toLowerCase().includes(q))return false;
      if(catSel.length>0&&!catSel.includes(e.category))return false;
      if(actSel.length>0){
        const wantUsers=actSel.includes("Users");
        const wantSystem=actSel.includes("System");
        if(wantUsers&&wantSystem){}  // both checked = show all
        else if(wantSystem&&!e.isSystem)return false;
        else if(wantUsers&&e.isSystem)return false;
      }
      return true;
    });
  },[entries,search,catSel,actSel]);

  const totalPages=Math.max(1,Math.ceil(filtered.length/pageSize));
  const paged=filtered.slice((page-1)*pageSize,page*pageSize);

  const exportCsv=()=>{
    const rows=[["Timestamp","Category","Action","Details","Actor"],
      ...filtered.map(e=>[e.timestamp,e.category,e.action,e.details||"",e.actor])];
    const csv=rows.map(r=>r.map(c=>`"${String(c).replace(/"/g,'""')}"`).join(",")).join("\n");
    const blob=new Blob([csv],{type:"text/csv"});
    const url=URL.createObjectURL(blob);
    const a=document.createElement("a");a.href=url;a.download="audit-log.csv";a.click();URL.revokeObjectURL(url);
  };

  const initials=actor=>{if(!actor)return"?";return actor==="system"?"SYS":actor.split(".").map(p=>p[0]?.toUpperCase()||"").join("").slice(0,2);};

  // helper: chevron svg
  const ChevDown=()=><svg width="10" height="10" viewBox="0 0 10 10" fill="none"><path d="M2 3.5l3 3 3-3" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round" strokeLinejoin="round"/></svg>;

  // helper: checkbox row
  const ChkRow=({checked,onToggle,label,color,bg,border})=>(
    <div onClick={onToggle} style={{display:"flex",alignItems:"center",gap:9,padding:"7px 10px",borderRadius:6,cursor:"pointer",transition:"background .1s",userSelect:"none"}}
      onMouseEnter={e=>e.currentTarget.style.background=T.bgHover} onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
      <div style={{width:15,height:15,borderRadius:4,flexShrink:0,border:`1.5px solid ${checked?(color||T.accent):T.border}`,background:checked?(color||T.accent):"transparent",display:"flex",alignItems:"center",justifyContent:"center",transition:"all .1s"}}>
        {checked&&<svg width="9" height="9" viewBox="0 0 9 9" fill="none"><path d="M1.5 4.5l2 2 4-4" stroke="#fff" strokeWidth="1.4" strokeLinecap="round" strokeLinejoin="round"/></svg>}
      </div>
      <span style={{fontSize:12.5,color:checked?(color||T.text):T.textSub,fontWeight:checked?600:400,flex:1}}>{label}</span>
    </div>
  );

  // dropdown label helpers
  const catLabel=catSel.length===0?"Category":catSel.length===1?catSel[0]:`Category (${catSel.length})`;
  const actLabel=actSel.length===0?"Actor":actSel.length===1?actSel[0]:`Actor (${actSel.length})`;

  return(
    <div className="fadeIn" onClick={()=>setOpenDrop(null)}>
      {/* ── Toolbar ── */}
      <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:14}}>
        {/* Search */}
        <div style={{position:"relative",flex:"1 1 200px",minWidth:180}} onClick={e=>e.stopPropagation()}>
          <div style={{position:"absolute",left:10,top:"50%",transform:"translateY(-50%)",color:T.textMuted,pointerEvents:"none",display:"flex"}}>{Ic.search(13)}</div>
          <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search action, details, actor…"
            style={{width:"100%",paddingLeft:32,paddingRight:search?28:10,height:34,borderRadius:8,border:`1px solid ${search?T.accent:T.border}`,background:T.bgElevated,color:T.text,fontSize:12.5,outline:"none",boxSizing:"border-box",fontFamily:"inherit",transition:"border-color .15s"}}
            onFocus={e=>e.target.style.borderColor=T.accent} onBlur={e=>e.target.style.borderColor=search?T.accent:T.border}/>
          {search&&<button onClick={()=>setSearch("")} style={{position:"absolute",right:8,top:"50%",transform:"translateY(-50%)",background:"none",border:"none",cursor:"pointer",color:T.textMuted,fontSize:15,lineHeight:1}}>×</button>}
        </div>

        {/* Category multi-select dropdown */}
        <div style={{position:"relative"}} onClick={e=>e.stopPropagation()}>
          <button onClick={()=>setOpenDrop(d=>d==="cat"?null:"cat")}
            style={{height:34,padding:"0 10px 0 12px",borderRadius:8,border:`1px solid ${catSel.length>0?T.accent:T.border}`,
              background:catSel.length>0?T.accentDim:openDrop==="cat"?T.bgElevated:"transparent",
              color:catSel.length>0?T.accent:T.textSub,cursor:"pointer",display:"flex",alignItems:"center",gap:6,
              fontSize:12.5,fontFamily:"inherit",fontWeight:catSel.length>0?600:400,whiteSpace:"nowrap",transition:"all .15s"}}>
            {catLabel}
            <ChevDown/>
          </button>
          {openDrop==="cat"&&(
            <div style={{position:"absolute",top:"calc(100% + 5px)",left:0,zIndex:1000,minWidth:200,background:T.bgSurface,border:`1px solid ${T.border}`,borderRadius:10,boxShadow:"0 8px 24px rgba(0,0,0,.13)",padding:"6px 4px",overflow:"hidden"}}>
              {/* Select all / Clear row */}
              <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"4px 10px 6px",borderBottom:`1px solid ${T.border}`,marginBottom:4}}>
                <span style={{fontSize:11,fontWeight:700,color:T.textMuted,textTransform:"uppercase",letterSpacing:"0.07em"}}>Category</span>
                {catSel.length>0
                  ?<button onClick={()=>setCatSel([])} style={{fontSize:11,color:T.accent,background:"none",border:"none",cursor:"pointer",padding:0,fontFamily:"inherit"}}>Clear</button>
                  :<button onClick={()=>setCatSel([...cats])} style={{fontSize:11,color:T.textMuted,background:"none",border:"none",cursor:"pointer",padding:0,fontFamily:"inherit"}}>Select all</button>
                }
              </div>
              {cats.map(c=>{
                const m=AUDIT_CAT_META[c];
                return <ChkRow key={c} checked={catSel.includes(c)} onToggle={()=>toggleCat(c)} label={c} color={m?.color} bg={m?.bg} border={m?.border}/>;
              })}
            </div>
          )}
        </div>

        {/* Actor multi-select dropdown — hidden when all entries are user-scoped */}
        {!hideActorFilter&&(
        <div style={{position:"relative"}} onClick={e=>e.stopPropagation()}>
          <button onClick={()=>setOpenDrop(d=>d==="act"?null:"act")}
            style={{height:34,padding:"0 10px 0 12px",borderRadius:8,border:`1px solid ${actSel.length>0?T.accent:T.border}`,
              background:actSel.length>0?T.accentDim:openDrop==="act"?T.bgElevated:"transparent",
              color:actSel.length>0?T.accent:T.textSub,cursor:"pointer",display:"flex",alignItems:"center",gap:6,
              fontSize:12.5,fontFamily:"inherit",fontWeight:actSel.length>0?600:400,whiteSpace:"nowrap",transition:"all .15s"}}>
            {actLabel}
            <ChevDown/>
          </button>
          {openDrop==="act"&&(
            <div style={{position:"absolute",top:"calc(100% + 5px)",left:0,zIndex:1000,minWidth:180,background:T.bgSurface,border:`1px solid ${T.border}`,borderRadius:10,boxShadow:"0 8px 24px rgba(0,0,0,.13)",padding:"6px 4px",overflow:"hidden"}}>
              <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"4px 10px 6px",borderBottom:`1px solid ${T.border}`,marginBottom:4}}>
                <span style={{fontSize:11,fontWeight:700,color:T.textMuted,textTransform:"uppercase",letterSpacing:"0.07em"}}>Actor</span>
                {actSel.length>0&&<button onClick={()=>setActSel([])} style={{fontSize:11,color:T.accent,background:"none",border:"none",cursor:"pointer",padding:0,fontFamily:"inherit"}}>Clear</button>}
              </div>
              <ChkRow checked={actSel.includes("Users")} onToggle={()=>toggleAct("Users")} label="Users"/>
              <ChkRow checked={actSel.includes("System")} onToggle={()=>toggleAct("System")} label="System"/>
            </div>
          )}
        </div>
        )}

        {/* Export */}
        <button onClick={exportCsv}
          style={{height:34,padding:"0 12px",borderRadius:8,fontSize:11.5,border:`1px solid ${T.border}`,background:"transparent",color:T.textMuted,cursor:"pointer",display:"flex",alignItems:"center",gap:5,fontFamily:"inherit",whiteSpace:"nowrap",marginLeft:"auto",transition:"all .15s"}}
          onMouseEnter={e=>{e.currentTarget.style.borderColor=T.accent;e.currentTarget.style.color=T.accent;}}
          onMouseLeave={e=>{e.currentTarget.style.borderColor=T.border;e.currentTarget.style.color=T.textMuted;}}>
          <svg width="11" height="11" viewBox="0 0 14 14" fill="none"><path d="M7 2v7M4 6l3 3 3-3M2 11h10" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round" strokeLinejoin="round"/></svg>
          Export CSV
        </button>
      </div>

      {/* ── Table ── */}
      <div style={{border:`1px solid ${T.border}`,borderRadius:10,overflow:"hidden"}}>
        {/* Header row */}
        {(()=>{const hdrs=hideActorFilter?["Timestamp","Category","Action","Details",""] :["Timestamp","Category","Action","Details","Actor",""];const lastIdx=hdrs.length-1;return(
        <div style={{display:"grid",gridTemplateColumns:hideActorFilter?"190px 86px 1fr 1fr 28px":"190px 86px 1fr 1fr 150px 28px",background:T.bgElevated,borderBottom:`1px solid ${T.border}`,padding:"0 16px"}}>
          {hdrs.map((h,i)=>(
            <div key={i} style={{padding:"9px 0",paddingRight:i<lastIdx?12:0,fontSize:10.5,fontWeight:700,color:T.textMuted,textTransform:"uppercase",letterSpacing:"0.07em"}}>{h}</div>
          ))}
        </div>
        );})()}

        {paged.length===0&&(
          <div style={{padding:"36px",textAlign:"center",fontSize:12.5,color:T.textMuted}}>No audit entries match your filters.</div>
        )}

        {paged.map((entry,i)=>{
          const m=AUDIT_CAT_META[entry.category]||AUDIT_CAT_META.EDIT;
          const isExp=expanded===entry.id;
          const hasExp=!!(entry.note||entry.diff);
          const isLast=i===paged.length-1;
          return(
            <React.Fragment key={entry.id}>
              <div
                onClick={()=>hasExp&&setExpanded(isExp?null:entry.id)}
                style={{display:"grid",gridTemplateColumns:hideActorFilter?"190px 86px 1fr 1fr 28px":"190px 86px 1fr 1fr 150px 28px",padding:"0 16px",
                  borderBottom:isLast&&!isExp?"none":`1px solid ${T.border}`,
                  background:isExp?T.bgElevated:"transparent",
                  cursor:hasExp?"pointer":"default",transition:"background .1s"}}
                onMouseEnter={e=>{if(!isExp)e.currentTarget.style.background=T.bgHover;}}
                onMouseLeave={e=>{if(!isExp)e.currentTarget.style.background=isExp?T.bgElevated:"transparent";}}>
                {/* Timestamp */}
                <div style={{padding:"12px 12px 12px 0",display:"flex",alignItems:"center"}}>
                  <span style={{fontFamily:"'Geist Mono',monospace",fontSize:11,color:T.textSub,whiteSpace:"nowrap"}}>{entry.timestamp}</span>
                </div>
                {/* Category badge */}
                <div style={{padding:"12px 12px 12px 0",display:"flex",alignItems:"center"}}>
                  <span style={{fontSize:9.5,fontWeight:700,padding:"2px 7px",borderRadius:4,background:m.bg,color:m.color,border:`1px solid ${m.border}`,letterSpacing:"0.06em",whiteSpace:"nowrap"}}>{entry.category}</span>
                </div>
                {/* Action */}
                <div style={{padding:"12px 12px 12px 0",display:"flex",alignItems:"center"}}>
                  <span style={{fontSize:12.5,fontWeight:600,color:T.text}}>{entry.action}</span>
                </div>
                {/* Details */}
                <div style={{padding:"12px 12px 12px 0",display:"flex",alignItems:"center",minWidth:0}}>
                  <span style={{fontSize:12,color:T.textSub,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{entry.details||"—"}</span>
                </div>
                {/* Actor — hidden in user-scoped contexts */}
                {!hideActorFilter&&(
                <div style={{padding:"12px 0",display:"flex",alignItems:"center",gap:7,minWidth:0}}>
                  <div style={{width:22,height:22,borderRadius:6,flexShrink:0,display:"flex",alignItems:"center",justifyContent:"center",fontSize:9,fontWeight:700,
                    background:entry.isSystem?"rgba(107,114,128,.15)":T.accentDim,
                    color:entry.isSystem?"#6b7280":T.accent}}>
                    {initials(entry.actor)}
                  </div>
                  <span style={{fontSize:11.5,fontFamily:"'Geist Mono',monospace",color:entry.isSystem?"#6b7280":T.textSub,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{entry.actor}</span>
                </div>
                )}
                {/* Expand chevron */}
                <div style={{display:"flex",alignItems:"center",justifyContent:"center"}}>
                  {hasExp&&<svg width="12" height="12" viewBox="0 0 12 12" fill="none" style={{color:T.textMuted,transition:"transform .15s",transform:isExp?"rotate(180deg)":"rotate(0deg)"}}><path d="M2 4l4 4 4-4" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round" strokeLinejoin="round"/></svg>}
                </div>
              </div>

              {/* Expanded row */}
              {isExp&&(
                <div style={{padding:"12px 16px 14px 16px",background:T.bgElevated,borderBottom:isLast?"none":`1px solid ${T.border}`}}>
                  {entry.diff&&(
                    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:entry.note?10:0}}>
                      <div>
                        <div style={{fontSize:10,fontWeight:700,color:T.textMuted,textTransform:"uppercase",letterSpacing:"0.07em",marginBottom:5}}>Before</div>
                        <div style={{padding:"8px 12px",background:"rgba(225,29,72,.06)",border:"1px solid rgba(225,29,72,.2)",borderRadius:7,fontSize:12,color:T.textSub,fontFamily:"'Geist Mono',monospace",lineHeight:1.5,wordBreak:"break-all"}}>{entry.diff.before}</div>
                      </div>
                      <div>
                        <div style={{fontSize:10,fontWeight:700,color:T.textMuted,textTransform:"uppercase",letterSpacing:"0.07em",marginBottom:5}}>After</div>
                        <div style={{padding:"8px 12px",background:"rgba(22,163,74,.06)",border:"1px solid rgba(22,163,74,.2)",borderRadius:7,fontSize:12,color:T.textSub,fontFamily:"'Geist Mono',monospace",lineHeight:1.5,wordBreak:"break-all"}}>{entry.diff.after}</div>
                      </div>
                    </div>
                  )}
                  {entry.note&&<div style={{fontSize:12,color:T.textSub,padding:"8px 12px",background:T.bgSurface,borderRadius:7,border:`1px solid ${T.border}`}}><span style={{fontWeight:600,color:T.textMuted,marginRight:6}}>Note:</span>{entry.note}</div>}
                </div>
              )}
            </React.Fragment>
          );
        })}
      </div>

      {/* ── Pagination ── */}
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginTop:14,padding:"0 2px"}}>
        <span style={{fontSize:11.5,color:T.textMuted}}>{filtered.length} {filtered.length===1?"entry":"entries"}{page>1||totalPages>1?` · page ${page} of ${totalPages}`:""}</span>
        {totalPages>1&&(
          <div style={{display:"flex",gap:4,alignItems:"center"}}>
            <button onClick={()=>setPage(p=>Math.max(1,p-1))} disabled={page===1}
              style={{padding:"4px 10px",borderRadius:6,border:`1px solid ${T.border}`,background:"transparent",color:page===1?T.border:T.textSub,cursor:page===1?"not-allowed":"pointer",fontSize:12,fontFamily:"inherit"}}>← Prev</button>
            {(()=>{
              const start=Math.max(1,Math.min(page-2,totalPages-4));
              const end=Math.min(totalPages,start+4);
              return Array.from({length:end-start+1},(_,i)=>start+i).map(pg=>(
                <button key={pg} onClick={()=>setPage(pg)}
                  style={{width:30,height:28,borderRadius:6,border:`1px solid ${pg===page?T.accent:T.border}`,
                    background:pg===page?T.accentDim:"transparent",color:pg===page?T.accent:T.textSub,
                    cursor:"pointer",fontSize:12,fontFamily:"inherit",fontWeight:pg===page?700:400}}>
                  {pg}
                </button>
              ));
            })()}
            <button onClick={()=>setPage(p=>Math.min(totalPages,p+1))} disabled={page===totalPages}
              style={{padding:"4px 10px",borderRadius:6,border:`1px solid ${T.border}`,background:"transparent",color:page===totalPages?T.border:T.textSub,cursor:page===totalPages?"not-allowed":"pointer",fontSize:12,fontFamily:"inherit"}}>Next →</button>
          </div>
        )}
      </div>
    </div>
  );
};

const AssetActivityTab = ()=>(
  <Card2 className="fadeIn">
    <div style={{padding:16}}>
      <AuditLogTable entries={ASSET_AUDIT_ENTRIES}/>
    </div>
  </Card2>
);

const AssetCommentsTab = ({asset,onToast})=>{
  const seed = COMMENTS_BY_ASSET[asset?.name]||[];
  const [comments,setComments]=useState(seed);
  const [newComment,setNewComment]=useState("");
  const submit=()=>{
    if(!newComment.trim())return;
    setComments([...comments,{id:Date.now(),user:"maya.chen",avatar:"MC",text:newComment,time:"Just now",resolved:false}]);
    setNewComment("");
    onToast("Comment posted","success");
  };
  return <div className="fadeIn">
    <div style={{display:"flex",flexDirection:"column",gap:10,marginBottom:16}}>
      {comments.map(c=>(
        <Card2 key={c.id} style={{opacity:c.resolved?.7:1}}>
          <div style={{padding:14}}>
            <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:10}}>
              <div style={{width:26,height:26,borderRadius:7,background:T.bgHover,display:"flex",alignItems:"center",justifyContent:"center",fontSize:10,fontWeight:700,color:T.accent}}>{c.avatar}</div>
              <span style={{fontSize:12,fontWeight:500,color:T.text}}>{c.user}</span>
              <span style={{fontSize:11,color:T.textMuted}}>{c.time}</span>
              {c.resolved&&<Badge color={T.green} bg={T.accentDim} style={{marginLeft:"auto"}}>Resolved</Badge>}
              <div style={{marginLeft:"auto",display:"flex",gap:6}}>
                {!c.resolved&&<button onClick={()=>setComments(comments.map(cc=>cc.id===c.id?{...cc,resolved:true}:cc))} style={{background:"transparent",border:"none",color:T.textMuted,cursor:"pointer",fontSize:11,display:"flex",alignItems:"center",gap:4}}>{Ic.check(12)} Resolve</button>}
              </div>
            </div>
            <p style={{fontSize:13,color:T.textSub,lineHeight:1.7}}>{c.text}</p>
          </div>
        </Card2>
      ))}
    </div>
    <Card2>
      <div style={{padding:14}}>
        <div style={{fontSize:12,color:T.textSub,marginBottom:8}}>Add a comment</div>
        <Input2 multiline rows={3} placeholder="Leave a comment, ask a question, or flag an issue…" value={newComment} onChange={e=>setNewComment(e.target.value)}/>
        <div style={{display:"flex",justifyContent:"flex-end",marginTop:10}}>
          <Btn variant="primary" icon={Ic.comment(12)} onClick={submit}>Post Comment</Btn>
        </div>
      </div>
    </Card2>
  </div>;
};

