// ASSET DETAIL
// ─────────────────────────────────────────────
// ── Container asset detail (Database / Catalog / Schema / Bucket / Container / Folder) ──
const ContainerAssetDetail = ({asset, assetStack, onBack, onAsset, onToast}) => {
  const navFn = useNav();
  const [tab,          setTab]         = useState("overview");
  const [data,         setData]        = useState({...asset, owners:asset.owners||[asset.owner], stewards:asset.stewards||(asset.steward?[asset.steward]:[]), tags:[...(asset.tags||[])]});
  const [certOpen,       setCertOpen]       = useState(false);
  const [editModal,      setEditModal]      = useState(null);
  const [certModal,      setCertModal]      = useState(false);
  const [certNote,       setCertNote]       = useState("");
  const [domainOpen,     setDomainOpen]     = useState(false);
  const [domainSearch,   setDomainSearch]   = useState("");
  const [ownersOpen,     setOwnersOpen]     = useState(false);
  const [ownersSearch,   setOwnersSearch]   = useState("");
  const [stewardsOpen,   setStewardsOpen]   = useState(false);
  const [stewardsSearch, setStewardsSearch] = useState("");
  const [tagsOpen,       setTagsOpen]       = useState(false);
  const [tagsSearch,     setTagsSearch]     = useState("");
  const [showAllOwners,  setShowAllOwners]  = useState(false);
  const [showAllStewards,setShowAllStewards]= useState(false);
  const [showAllTags,    setShowAllTags]    = useState(false);
  const [assetGlTerms,   setAssetGlTerms]  = useState([]);
  const [assetGlOpen,    setAssetGlOpen]   = useState(false);
  const [assetGlSearch,  setAssetGlSearch] = useState("");
  const [editDesc,       setEditDesc]       = useState(false);
  const [descVal,      setDescVal]     = useState(asset.description||"");
  const [editNotes,    setEditNotes]   = useState(false);
  const [notesVal,     setNotesVal]    = useState(`The ${asset.name} ${asset.type.toLowerCase()} is part of the ${asset.domain||"Platform"} domain.\n\nManaged by ${asset.owner||"the data team"} and refreshed on a ${asset.slaFreshness||"regular"} schedule.`);
  const [contSearch,   setContSearch]  = useState("");

  const children  = ASSETS.filter(a=>a.parentId===asset.id);
  const stackCrumbs = assetStack.slice(0,-1);

  const DOMAINS_LIST = ["Commerce","Finance","Product","Marketing","ML","Engineering"];
  const USERS_LIST   = ["maya.chen","sarah.kim","alex.wu","dev.patel","lisa.ray","priya.nair","james.oh"];
  const ava = name => (name||"?").split(".").map(s=>s[0]?.toUpperCase()||"").join("");

  const CMETA = {
    "Draft":      {color:"#6b7280",bg:"rgba(107,114,128,.1)", border:"rgba(107,114,128,.25)",icon:"◐"},
    "In Review":  {color:"#d97706",bg:"rgba(217,119,6,.12)",  border:"rgba(217,119,6,.3)",   icon:"⏳"},
    "Approved":   {color:"#16a34a",bg:"rgba(22,163,74,.12)",  border:"rgba(22,163,74,.3)",   icon:"✓"},
    "Rejected":   {color:"#e11d48",bg:"rgba(225,29,72,.12)",  border:"rgba(225,29,72,.3)",   icon:"✕"},
    "Deprecated": {color:"#7c3aed",bg:"rgba(124,58,237,.1)",  border:"rgba(124,58,237,.25)", icon:"—"},
  };
  const cm = CMETA[data.cert]||CMETA["Draft"];
  const owners   = Array.isArray(data.owners)  ? data.owners   : (data.owner   ? [data.owner]   : []);
  const stewards = Array.isArray(data.stewards) ? data.stewards : (data.steward ? [data.steward] : []);

  useEffect(()=>{
    if(!certOpen) return;
    const close=()=>setCertOpen(false);
    document.addEventListener("mousedown",close);
    return ()=>document.removeEventListener("mousedown",close);
  },[certOpen]);

  const handleCertify = () => { setData(d=>({...d,cert:"Approved"})); setCertModal(false); onToast(`${asset.name} certified successfully`,"success"); };

  const MetaLabel = ({children,onEdit})=>(
    <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:8}}>
      <div style={{fontSize:10.5,fontWeight:700,color:T.textMuted,textTransform:"uppercase",letterSpacing:"0.08em"}}>{children}</div>
      {onEdit&&<button onClick={onEdit} style={{background:"none",border:"none",cursor:"pointer",color:T.textMuted,padding:"2px 3px",display:"flex",borderRadius:4,transition:"all .12s"}}
        onMouseEnter={e=>{e.currentTarget.style.color=T.accent;e.currentTarget.style.background=T.accentDim;}}
        onMouseLeave={e=>{e.currentTarget.style.color=T.textMuted;e.currentTarget.style.background="none";}}>
        <svg width="11" height="11" viewBox="0 0 14 14" fill="none"><path d="M9.5 2.5l2 2L4 12H2v-2L9.5 2.5z" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round" strokeLinejoin="round"/></svg>
      </button>}
    </div>
  );

  const FILE_FORMAT_COLORS = {CSV:"#16a34a",Parquet:"#0891b2",JSON:"#d97706",ORC:"#7c3aed"};
  const TAG_C = {
    PII:{bg:"rgba(225,29,72,.1)",color:"#e11d48",border:"rgba(225,29,72,.25)"},
    revenue:{bg:"rgba(37,99,235,.08)",color:"#2563eb",border:"rgba(37,99,235,.2)"},
    finance:{bg:"rgba(37,99,235,.08)",color:"#2563eb",border:"rgba(37,99,235,.2)"},
    KPI:{bg:"rgba(22,163,74,.08)",color:"#16a34a",border:"rgba(22,163,74,.2)"},
    sensitive:{bg:"rgba(124,58,237,.08)",color:"#7c3aed",border:"rgba(124,58,237,.2)"},
    events:{bg:"rgba(6,182,212,.08)",color:"#0891b2",border:"rgba(6,182,212,.2)"},
    model:{bg:"rgba(99,102,241,.08)",color:"#6366f1",border:"rgba(99,102,241,.2)"},
    etl:{bg:"rgba(245,158,11,.08)",color:"#d97706",border:"rgba(245,158,11,.2)"},
  };
  const tc = tag => TAG_C[tag]||{bg:T.bgElevated,color:T.textSub,border:T.border};

  const CHILD_COLS = [
    {key:"name", label:"Name", render:(v,r)=>(
      <div style={{display:"flex",alignItems:"center",gap:8}}>
        <ServiceIcon service={r.service} size={16}/>
        <div style={{flex:1,minWidth:0}}>
          <div style={{display:"flex",alignItems:"center",gap:5}}>
            <span style={{fontSize:12.5,fontWeight:500,color:T.text,fontFamily:"'Geist Mono',monospace"}}>{v}</span>
            {r.fileFormat&&<span style={{fontSize:9,fontWeight:700,padding:"1px 4px",borderRadius:3,background:`${FILE_FORMAT_COLORS[r.fileFormat]||T.textMuted}18`,color:FILE_FORMAT_COLORS[r.fileFormat]||T.textMuted,border:`1px solid ${FILE_FORMAT_COLORS[r.fileFormat]||T.textMuted}33`}}>{r.fileFormat}</span>}
            {CONTAINER_TYPES.has(r.type)&&<span style={{fontSize:9,fontWeight:700,padding:"1px 6px",borderRadius:3,background:T.accentDim,color:T.accent,border:`1px solid ${T.accent}33`,letterSpacing:"0.03em"}}>Browse →</span>}
          </div>
          {r.db&&<div style={{fontSize:10,color:T.textMuted,fontFamily:"'Geist Mono',monospace"}}>{r.db}</div>}
        </div>
      </div>
    )},
    {key:"type",    label:"Type",    render:v=><TypeBadge type={v}/>},
    {key:"domain",  label:"Domain",  render:v=><span style={{fontSize:11.5,color:T.textSub}}>{v}</span>},
    {key:"owner",   label:"Owner",   render:v=><span style={{fontSize:11.5,color:T.textMuted,fontFamily:"'Geist Mono',monospace"}}>{v}</span>},
    {key:"cert",    label:"Cert",    render:(v,r)=>["Object","Blob","Folder"].includes(r.type)?<span style={{color:T.textMuted}}>—</span>:<CertBadge cert={v}/>},
    {key:"quality", label:"Quality", render:(v,r)=>["Object","Blob","Bucket","Container","Folder"].includes(r.type)?<span style={{color:T.textMuted}}>—</span>:<QScore score={v}/>},
    {key:"size",    label:"Size",    render:(v,r)=>v&&v!=="—"?<span style={{fontSize:11,fontFamily:"'Geist Mono',monospace",color:T.textSub}}>{v}</span>:r.rows&&r.rows!=="—"?<span style={{fontSize:11,fontFamily:"'Geist Mono',monospace",color:T.textSub}}>{r.rows} rows</span>:<span style={{color:T.textMuted}}>—</span>},
    {key:"updated", label:"Updated", render:v=><span style={{fontSize:11,color:T.textMuted}}>{v}</span>},
  ];

  const filteredChildren = children.filter(c=>
    !contSearch || c.name.toLowerCase().includes(contSearch.toLowerCase()) || (c.type||"").toLowerCase().includes(contSearch.toLowerCase())
  );

  // child quality stats
  const scoredChildren = children.filter(c=>typeof c.quality==="number");
  const avgQuality = scoredChildren.length ? Math.round(scoredChildren.reduce((s,c)=>s+c.quality,0)/scoredChildren.length) : null;
  const childTypeCounts = children.reduce((acc,c)=>{ acc[c.type]=(acc[c.type]||0)+1; return acc; },{});

  return (
    <div className="fadeUp" style={{height:"100%",display:"flex",flexDirection:"column"}}>
      <Topbar breadcrumb={[
        {label:"Data Catalog", onClick:()=>{ onBack(); stackCrumbs.forEach(()=>onBack()); }},
        ...stackCrumbs.map((a,i)=>({label:a.name, onClick:()=>{ const popCount=assetStack.length-1-i; for(let j=0;j<popCount;j++) onBack(); }})),
        {label:asset.name}
      ]}/>

      {/* ── Asset header ── */}
      <div style={{background:T.bgSurface,borderBottom:`1px solid ${T.border}`,flexShrink:0,padding:"16px 28px 0"}}>
        <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:8}}>
          <TypeBadge type={asset.type}/>
          <span style={{fontSize:11.5,color:T.textMuted,fontFamily:"'Geist Mono',monospace"}}>{asset.db||asset.connectionLabel}</span>
        </div>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",gap:12,marginBottom:14}}>
          <h2 style={{fontSize:22,fontWeight:700,fontFamily:"'Geist Mono',monospace",color:T.text,letterSpacing:"-0.04em",margin:0}}>{data.name}</h2>
          <div style={{display:"flex",gap:7,alignItems:"center",flexShrink:0}}>
            {data.cert!=="Approved"&&(
              <button onClick={()=>setCertModal(true)}
                style={{display:"inline-flex",alignItems:"center",gap:6,padding:"6px 14px",borderRadius:8,background:"#16a34a12",border:"1px solid rgba(22,163,74,.3)",color:"#16a34a",fontSize:12.5,fontWeight:600,cursor:"pointer",transition:"opacity .1s"}}
                onMouseEnter={e=>e.currentTarget.style.opacity=".8"} onMouseLeave={e=>e.currentTarget.style.opacity="1"}>
                {Ic.cert(12)} Certify
              </button>
            )}
            <button onClick={()=>onToast("Edit panel coming soon","success")}
              style={{display:"inline-flex",alignItems:"center",gap:6,padding:"6px 14px",borderRadius:8,background:T.bgElevated,border:`1px solid ${T.border}`,color:T.textSub,fontSize:12.5,fontWeight:500,cursor:"pointer",transition:"all .1s"}}
              onMouseEnter={e=>{e.currentTarget.style.borderColor=T.accent;e.currentTarget.style.color=T.accent;}}
              onMouseLeave={e=>{e.currentTarget.style.borderColor=T.border;e.currentTarget.style.color=T.textSub;}}>
              {Ic.edit(11)} Edit
            </button>
          </div>
        </div>
        <div style={{display:"flex",marginBottom:-1}}>
          {[{k:"overview",l:"Overview"},{k:"assets",l:`Assets (${children.length})`}].map(t=>(
            <button key={t.k} onClick={()=>setTab(t.k)}
              style={{padding:"9px 16px",background:"transparent",border:"none",borderBottom:`2px solid ${tab===t.k?T.accent:"transparent"}`,color:tab===t.k?T.text:T.textMuted,fontSize:13,fontWeight:tab===t.k?600:400,cursor:"pointer",transition:"all .12s",whiteSpace:"nowrap"}}>
              {t.l}
            </button>
          ))}
        </div>
      </div>

      {/* ── Body ── */}
      <div style={{flex:1,display:"flex",overflow:"hidden"}}>

        {/* Main content */}
        <div style={{flex:1,overflowY:"auto",padding:24,minWidth:0}}>

          {tab==="overview"&&(
            <div style={{display:"flex",flexDirection:"column",gap:16,maxWidth:900}}>

              {/* Description */}
              <Card2>
                <div style={{padding:"14px 16px"}}>
                  <SH title="Description" action={
                    editDesc
                      ? <div style={{display:"flex",gap:6}}>
                          <Btn small ghost onClick={()=>{setData(d=>({...d,description:descVal}));setEditDesc(false);onToast("Description saved","success");}}>Save</Btn>
                          <Btn small ghost onClick={()=>{setDescVal(data.description||asset.description||"");setEditDesc(false);}}>Cancel</Btn>
                        </div>
                      : <Btn small ghost icon={Ic.edit(11)} onClick={()=>setEditDesc(true)}>Edit</Btn>
                  }/>
                  {editDesc
                    ? <textarea value={descVal} onChange={e=>setDescVal(e.target.value)} rows={3}
                        style={{width:"100%",padding:"9px 12px",background:T.bgElevated,border:`1.5px solid ${T.accent}`,borderRadius:8,color:T.text,fontSize:13,outline:"none",resize:"vertical",lineHeight:1.7,fontFamily:"inherit",boxSizing:"border-box"}}/>
                    : <p style={{fontSize:13,color:descVal?T.textSub:T.textMuted,lineHeight:1.8,margin:0,fontStyle:descVal?"normal":"italic"}}>{descVal||"No description. Click Edit to add one."}</p>
                  }
                </div>
              </Card2>

              {/* Contents summary */}
              {children.length>0&&(
                <Card2>
                  <div style={{padding:"14px 16px"}}>
                    <SH title="Asset Summary"/>
                    <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(120px,1fr))",gap:10,marginBottom:16}}>
                      <div style={{background:T.bgElevated,borderRadius:8,padding:"12px 14px",border:`1px solid ${T.border}`}}>
                        <div style={{fontSize:22,fontWeight:700,color:T.text,fontFamily:"'Geist Mono',monospace",lineHeight:1}}>{children.length}</div>
                        <div style={{fontSize:11,color:T.textMuted,marginTop:4}}>Direct children</div>
                      </div>
                      {avgQuality!==null&&(
                        <div style={{background:T.bgElevated,borderRadius:8,padding:"12px 14px",border:`1px solid ${T.border}`}}>
                          <div style={{fontSize:22,fontWeight:700,color:avgQuality>=80?T.green:avgQuality>=60?"#d97706":T.rose,fontFamily:"'Geist Mono',monospace",lineHeight:1}}>{avgQuality}</div>
                          <div style={{fontSize:11,color:T.textMuted,marginTop:4}}>Avg quality</div>
                        </div>
                      )}
                      <div style={{background:T.bgElevated,borderRadius:8,padding:"12px 14px",border:`1px solid ${T.border}`}}>
                        <div style={{fontSize:22,fontWeight:700,color:T.green,fontFamily:"'Geist Mono',monospace",lineHeight:1}}>{children.filter(c=>c.cert==="Approved").length}</div>
                        <div style={{fontSize:11,color:T.textMuted,marginTop:4}}>Certified</div>
                      </div>
                    </div>
                    {Object.keys(childTypeCounts).length>0&&(
                      <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
                        {Object.entries(childTypeCounts).map(([type,count])=>(
                          <button key={type} onClick={()=>setTab("assets")}
                            style={{display:"inline-flex",alignItems:"center",gap:6,padding:"4px 10px",borderRadius:6,background:T.bgElevated,border:`1px solid ${T.border}`,cursor:"pointer",transition:"all .1s"}}
                            onMouseEnter={e=>{e.currentTarget.style.borderColor=T.accent;e.currentTarget.style.background=T.accentDim;}}
                            onMouseLeave={e=>{e.currentTarget.style.borderColor=T.border;e.currentTarget.style.background=T.bgElevated;}}>
                            <TypeBadge type={type}/>
                            <span style={{fontSize:12,color:T.textSub,fontWeight:500}}>{count}</span>
                          </button>
                        ))}
                      </div>
                    )}
                  </div>
                </Card2>
              )}

              {/* Governance */}
              {(()=>{
                const govPols = DEMO_POLICIES_GLOBAL.filter(p=>{
                  const domainMatch = (p.scope?.domains||[]).includes(asset.domain);
                  const nameMatch   = (p.links||[]).some(l=>l.target===asset.name);
                  return domainMatch||nameMatch;
                });
                if(!govPols.length) return null;
                const LC_COLOR = {Active:T.green,"In Review":T.amber,Draft:T.textMuted,Approved:T.blue,Deprecated:T.rose};
                const govRegs = [...new Set(govPols.flatMap(p=>p.regulations||[]))];
                const regMeta = r => REGS_META.find(rm=>rm.name===r||rm.name.startsWith(r)||r.toLowerCase().includes(rm.id));
                const REG_TYPE_COLOR = {Privacy:T.violet,Healthcare:T.rose,Financial:T.amber,Security:T.blue};
                return (
                  <Card2>
                    <div style={{padding:"14px 16px"}}>
                      <SH title="Governance"/>
                      <div style={{marginBottom:12}}>
                        <div style={{fontSize:10,fontWeight:700,color:T.textMuted,textTransform:"uppercase",letterSpacing:"0.07em",marginBottom:8}}>Governing Policies</div>
                        {govPols.map(p=>{
                          const lcc = LC_COLOR[p.lifecycle]||T.textMuted;
                          return (
                            <div key={p.id}
                              onClick={()=>navFn("policymanager",{policyId:p.id})}
                              onMouseEnter={e=>e.currentTarget.style.background=T.bgHover}
                              onMouseLeave={e=>e.currentTarget.style.background=T.bgElevated}
                              style={{display:"flex",alignItems:"center",gap:10,padding:"9px 12px",background:T.bgElevated,border:`1px solid ${T.border}`,borderRadius:8,marginBottom:6,cursor:"pointer",transition:"background .1s"}}>
                              <div style={{width:7,height:7,borderRadius:"50%",background:lcc,flexShrink:0}}/>
                              <div style={{flex:1,minWidth:0}}>
                                <div style={{fontSize:12,fontWeight:600,color:T.text,lineHeight:1.4}}>{p.name}</div>
                                <div style={{fontSize:10.5,color:T.textMuted,marginTop:1}}>{p.category} · {p.severity} severity</div>
                              </div>
                              <span style={{fontSize:10,fontWeight:700,padding:"2px 7px",borderRadius:99,background:`${lcc}15`,color:lcc,border:`1px solid ${lcc}25`,flexShrink:0,whiteSpace:"nowrap"}}>{p.lifecycle}</span>
                              <svg width="12" height="12" viewBox="0 0 12 12" fill="none" style={{flexShrink:0,color:T.textMuted}}><path d="M2.5 6h7M6.5 3l3 3-3 3" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round" strokeLinejoin="round"/></svg>
                            </div>
                          );
                        })}
                      </div>
                      {govRegs.length>0&&(
                        <div>
                          <div style={{fontSize:10,fontWeight:700,color:T.textMuted,textTransform:"uppercase",letterSpacing:"0.07em",marginBottom:8}}>Applicable Regulations</div>
                          <div style={{display:"flex",flexWrap:"wrap",gap:6}}>
                            {govRegs.map(r=>{
                              const rm = regMeta(r);
                              const rc = rm ? REG_TYPE_COLOR[rm.type]||T.accent : T.accent;
                              return (
                                <span key={r} style={{display:"inline-flex",alignItems:"center",gap:5,fontSize:11.5,padding:"4px 10px",borderRadius:6,background:`${rc}12`,color:rc,border:`1px solid ${rc}25`,fontWeight:600}}>
                                  <svg width="10" height="10" viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.4"><path d="M8 1L2 4v4c0 3.5 2.7 5.5 6 6.5C11.3 13.5 14 11.5 14 8V4L8 1z"/></svg>
                                  {r}{rm&&<span style={{fontSize:9.5,color:`${rc}99`,fontWeight:400,marginLeft:1}}>· {rm.jurisdiction}</span>}
                                </span>
                              );
                            })}
                          </div>
                        </div>
                      )}
                    </div>
                  </Card2>
                );
              })()}

              {/* Notes */}
              <Card2>
                <div style={{padding:"14px 16px"}}>
                  <SH title="Notes" action={
                    editNotes
                      ? <div style={{display:"flex",gap:6}}>
                          <Btn small ghost onClick={()=>{setEditNotes(false);onToast("Notes saved","success");}}>Save</Btn>
                          <Btn small ghost onClick={()=>setEditNotes(false)}>Cancel</Btn>
                        </div>
                      : <Btn small ghost icon={Ic.edit(11)} onClick={()=>setEditNotes(true)}>Edit</Btn>
                  }/>
                  {editNotes
                    ? <textarea value={notesVal} onChange={e=>setNotesVal(e.target.value)} rows={5}
                        style={{width:"100%",padding:"9px 12px",background:T.bgElevated,border:`1.5px solid ${T.accent}`,borderRadius:8,color:T.text,fontSize:13,outline:"none",resize:"vertical",lineHeight:1.75,fontFamily:"'Geist Mono',monospace",boxSizing:"border-box"}}/>
                    : <div style={{fontSize:13,color:T.textSub,lineHeight:1.9,whiteSpace:"pre-wrap"}}>{notesVal}</div>
                  }
                </div>
              </Card2>

            </div>
          )}

          {tab==="assets"&&(
            <div style={{display:"flex",flexDirection:"column",gap:12}}>
              <div style={{position:"relative",maxWidth:400}}>
                <svg width="13" height="13" viewBox="0 0 14 14" fill="none" style={{position:"absolute",left:9,top:"50%",transform:"translateY(-50%)",color:T.textMuted,pointerEvents:"none"}}><circle cx="6" cy="6" r="4.5" stroke="currentColor" strokeWidth="1.3"/><path d="M10 10l2.5 2.5" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round"/></svg>
                <input value={contSearch} onChange={e=>setContSearch(e.target.value)} placeholder={`Search ${children.length} assets…`}
                  style={{width:"100%",padding:"7px 10px 7px 28px",background:T.bgElevated,border:`1.5px solid ${contSearch?T.accent:T.border}`,borderRadius:8,color:T.text,fontSize:12.5,outline:"none",boxSizing:"border-box",transition:"border-color .15s"}}
                  onFocus={e=>e.target.style.borderColor=T.accent} onBlur={e=>e.target.style.borderColor=contSearch?T.accent:T.border}/>
                {contSearch&&<button onClick={()=>setContSearch("")} style={{position:"absolute",right:8,top:"50%",transform:"translateY(-50%)",background:"none",border:"none",cursor:"pointer",color:T.textMuted,fontSize:16,lineHeight:1}}>×</button>}
              </div>
              {filteredChildren.length===0
                ? <div style={{textAlign:"center",padding:"40px 0",color:T.textMuted,fontSize:13}}>{contSearch?"No assets match your search":"No child assets found"}</div>
                : <Card2 style={{padding:0,overflow:"hidden"}}>
                    <DataTable cols={CHILD_COLS} rows={filteredChildren} onRowClick={r=>onAsset(r)}/>
                  </Card2>
              }
            </div>
          )}
        </div>

        {/* ── Right metadata sidebar — Overview tab only ── */}
        {tab==="overview"&&<div style={{width:260,flexShrink:0,borderLeft:`1px solid ${T.border}`,background:T.bgSurface,overflowY:"auto"}}>

          {/* DETAILS */}
          <div style={{padding:"16px",borderBottom:`1px solid ${T.border}`}}>
            <MetaLabel>Details</MetaLabel>
            {[
              {l:"Connection", v:<div style={{display:"flex",alignItems:"center",gap:6}}><ServiceIcon service={asset.service} size={14}/><span style={{fontSize:12,color:T.textSub}}>{asset.connectionLabel}</span></div>},
              {l:"Size",       v:<span style={{fontSize:12,fontFamily:"'Geist Mono',monospace",color:T.text}}>{data.size||"—"}</span>},
              {l:"Children",   v:<span style={{fontSize:12,fontFamily:"'Geist Mono',monospace",color:T.text}}>{children.length}</span>},
              {l:"Freshness",  v:<span style={{fontSize:12,color:T.textSub}}>{data.slaFreshness||"—"}</span>},
              {l:"Updated",    v:<span style={{fontSize:12,color:T.textMuted}}>{data.updated||"—"}</span>},
            ].map(m=>(
              <div key={m.l} style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:8,fontSize:12}}>
                <span style={{color:T.textMuted}}>{m.l}</span>{m.v}
              </div>
            ))}
          </div>

          {/* CERTIFICATE */}
          <div style={{padding:"16px",borderBottom:`1px solid ${T.border}`}}>
            <MetaLabel onEdit={()=>setEditModal("cert")}>Certificate</MetaLabel>
            <div style={{display:"inline-flex",alignItems:"center",gap:6,padding:"4px 12px 4px 9px",borderRadius:5,background:cm.bg,borderTop:`1px solid ${cm.border}`,borderRight:`1px solid ${cm.border}`,borderBottom:`1px solid ${cm.border}`,borderLeft:`3px solid ${cm.color}`}}>
              <span style={{fontSize:13}}>{cm.icon}</span>
              <span style={{fontSize:12,color:cm.color,fontWeight:600}}>{data.cert||"Draft"}</span>
            </div>
          </div>

          {/* DOMAIN */}
          <div style={{padding:"16px",borderBottom:`1px solid ${T.border}`}}>
            <MetaLabel onEdit={()=>{setDomainOpen(p=>!p);setDomainSearch("");}}>Domain</MetaLabel>
            {data.domain?(
              <div style={{display:"inline-flex",alignItems:"center",padding:"4px 12px 4px 9px",borderRadius:5,background:`${T.accent}0f`,borderTop:`1px solid ${T.accent}20`,borderRight:`1px solid ${T.accent}20`,borderBottom:`1px solid ${T.accent}20`,borderLeft:`3px solid ${T.accent}`}}>
                <span style={{fontSize:12,color:T.accent,fontWeight:600}}>{data.domain}</span>
              </div>
            ):(
              <span style={{fontSize:12,color:T.textMuted,fontStyle:"italic"}}>No domain set</span>
            )}
            {domainOpen&&(
              <div style={{marginTop:8,background:T.bgSurface,border:`1px solid ${T.accent}40`,borderRadius:8,overflow:"hidden",boxShadow:"0 4px 12px rgba(0,0,0,.12)"}}>
                <div style={{padding:"6px 8px",borderBottom:`1px solid ${T.border}`}}>
                  <input autoFocus placeholder="Search domains…" value={domainSearch} onChange={e=>setDomainSearch(e.target.value)}
                    style={{width:"100%",padding:"5px 8px",background:T.bgElevated,border:`1px solid ${T.border}`,borderRadius:6,color:T.text,fontSize:12,outline:"none",boxSizing:"border-box"}}
                    onFocus={e=>e.target.style.borderColor=T.accent} onBlur={e=>e.target.style.borderColor=T.border}/>
                </div>
                <div style={{maxHeight:180,overflowY:"auto"}}>
                  {DOMAINS_LIST.filter(d=>!domainSearch||d.toLowerCase().includes(domainSearch.toLowerCase())).map(d=>(
                    <button key={d} onClick={()=>{setData(dd=>({...dd,domain:d}));setDomainOpen(false);onToast(`Domain set to ${d}`,"success");}}
                      style={{width:"100%",display:"flex",alignItems:"center",justifyContent:"space-between",padding:"8px 12px",background:data.domain===d?T.accentDim:"transparent",border:"none",cursor:"pointer",fontSize:12.5,color:data.domain===d?T.accent:T.textSub,fontWeight:data.domain===d?600:400,transition:"background .1s"}}
                      onMouseEnter={e=>{if(data.domain!==d)e.currentTarget.style.background=T.bgHover;}} onMouseLeave={e=>{if(data.domain!==d)e.currentTarget.style.background="transparent";}}>
                      {d}
                      {data.domain===d&&<svg width="12" height="12" viewBox="0 0 14 14" fill="none"><path d="M2.5 7.5l3 3 6-6" stroke={T.accent} strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round"/></svg>}
                    </button>
                  ))}
                </div>
              </div>
            )}
          </div>

          {/* OWNERS */}
          <div style={{padding:"16px",borderBottom:`1px solid ${T.border}`}}>
            <MetaLabel onEdit={()=>{setOwnersOpen(p=>!p);setOwnersSearch("");}}>Owners</MetaLabel>
            <div style={{display:"flex",flexWrap:"wrap",gap:5}}>
              {owners.length===0&&<span style={{fontSize:12,color:T.textMuted,fontStyle:"italic"}}>No owners assigned</span>}
              {(showAllOwners?owners:owners.slice(0,3)).map((o,i)=>(
                <div key={i} style={{display:"inline-flex",alignItems:"center",gap:5,padding:"3px 10px 3px 6px",borderRadius:5,background:`${T.accent}0f`,borderTop:`1px solid ${T.accent}20`,borderRight:`1px solid ${T.accent}20`,borderBottom:`1px solid ${T.accent}20`,borderLeft:`3px solid ${T.accent}`}}>
                  <div style={{width:18,height:18,borderRadius:3,background:T.accentDim,display:"flex",alignItems:"center",justifyContent:"center",fontSize:7,fontWeight:700,color:T.accent,flexShrink:0}}>{ava(o)}</div>
                  <span style={{fontSize:12,color:T.accent,fontWeight:500}}>{o}</span>
                </div>
              ))}
              {owners.length>3&&!showAllOwners&&<span onClick={()=>setShowAllOwners(true)} style={{display:"inline-flex",alignItems:"center",fontSize:11.5,padding:"3px 10px",borderRadius:5,background:T.bgElevated,border:`1px solid ${T.border}`,color:T.textMuted,cursor:"pointer",fontWeight:600}}>+{owners.length-3} more</span>}
              {owners.length>3&&showAllOwners&&<span onClick={()=>setShowAllOwners(false)} style={{display:"inline-flex",alignItems:"center",fontSize:11.5,padding:"3px 10px",borderRadius:5,background:T.bgElevated,border:`1px solid ${T.border}`,color:T.textMuted,cursor:"pointer",fontWeight:600}}>− less</span>}
            </div>
            {ownersOpen&&(
              <div style={{marginTop:8,background:T.bgSurface,border:`1px solid ${T.accent}40`,borderRadius:8,overflow:"hidden",boxShadow:"0 4px 12px rgba(0,0,0,.12)"}}>
                <div style={{padding:"6px 8px",borderBottom:`1px solid ${T.border}`}}>
                  <input autoFocus placeholder="Search users…" value={ownersSearch} onChange={e=>setOwnersSearch(e.target.value)}
                    style={{width:"100%",padding:"5px 8px",background:T.bgElevated,border:`1px solid ${T.border}`,borderRadius:6,color:T.text,fontSize:12,outline:"none",boxSizing:"border-box"}}
                    onFocus={e=>e.target.style.borderColor=T.accent} onBlur={e=>e.target.style.borderColor=T.border}/>
                </div>
                <div style={{maxHeight:180,overflowY:"auto"}}>
                  {USERS_LIST.filter(u=>!ownersSearch||u.toLowerCase().includes(ownersSearch.toLowerCase())).map(u=>{
                    const sel=owners.includes(u);
                    return <button key={u} onClick={()=>{if(sel){const no=owners.filter(x=>x!==u);setData(d=>({...d,owners:no,owner:no[0]||""}));}else setData(d=>({...d,owners:[...owners,u],owner:owners[0]||u}));}}
                      style={{width:"100%",display:"flex",alignItems:"center",gap:8,padding:"7px 12px",background:sel?T.accentDim:"transparent",border:"none",cursor:"pointer",textAlign:"left",transition:"background .1s"}}
                      onMouseEnter={e=>{if(!sel)e.currentTarget.style.background=T.bgHover;}} onMouseLeave={e=>{if(!sel)e.currentTarget.style.background="transparent";}}>
                      <div style={{width:22,height:22,borderRadius:5,background:T.accentDim,border:`1px solid ${T.accent}33`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:8,fontWeight:700,color:T.accent,flexShrink:0}}>{ava(u)}</div>
                      <span style={{flex:1,fontSize:12,color:sel?T.accent:T.text,fontWeight:sel?600:400}}>{u}</span>
                      {sel&&<svg width="12" height="12" viewBox="0 0 14 14" fill="none"><path d="M2.5 7.5l3 3 6-6" stroke={T.accent} strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round"/></svg>}
                    </button>;
                  })}
                </div>
                <div style={{padding:"6px 8px",borderTop:`1px solid ${T.border}`,display:"flex",justifyContent:"flex-end"}}>
                  <button onClick={()=>setOwnersOpen(false)} style={{padding:"4px 12px",borderRadius:5,background:T.accent,border:"none",color:"#fff",fontSize:11.5,fontWeight:600,cursor:"pointer"}}>Done</button>
                </div>
              </div>
            )}
          </div>

          {/* STEWARDS */}
          <div style={{padding:"16px",borderBottom:`1px solid ${T.border}`}}>
            <MetaLabel onEdit={()=>{setStewardsOpen(p=>!p);setStewardsSearch("");}}>Stewards</MetaLabel>
            <div style={{display:"flex",flexWrap:"wrap",gap:5}}>
              {stewards.length===0&&<span style={{fontSize:12,color:T.textMuted,fontStyle:"italic"}}>No stewards assigned</span>}
              {(showAllStewards?stewards:stewards.slice(0,3)).map((s,i)=>(
                <div key={i} style={{display:"inline-flex",alignItems:"center",gap:5,padding:"3px 10px 3px 6px",borderRadius:5,background:"rgba(217,119,6,.08)",borderTop:"1px solid rgba(217,119,6,.2)",borderRight:"1px solid rgba(217,119,6,.2)",borderBottom:"1px solid rgba(217,119,6,.2)",borderLeft:"3px solid #d97706"}}>
                  <div style={{width:18,height:18,borderRadius:"50%",background:"rgba(217,119,6,.15)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:7,fontWeight:700,color:"#d97706",flexShrink:0}}>{ava(s)}</div>
                  <span style={{fontSize:12,color:"#d97706",fontWeight:500}}>{s}</span>
                </div>
              ))}
              {stewards.length>3&&!showAllStewards&&<span onClick={()=>setShowAllStewards(true)} style={{display:"inline-flex",alignItems:"center",fontSize:11.5,padding:"3px 10px",borderRadius:5,background:T.bgElevated,border:`1px solid ${T.border}`,color:T.textMuted,cursor:"pointer",fontWeight:600}}>+{stewards.length-3} more</span>}
              {stewards.length>3&&showAllStewards&&<span onClick={()=>setShowAllStewards(false)} style={{display:"inline-flex",alignItems:"center",fontSize:11.5,padding:"3px 10px",borderRadius:5,background:T.bgElevated,border:`1px solid ${T.border}`,color:T.textMuted,cursor:"pointer",fontWeight:600}}>− less</span>}
            </div>
            {stewardsOpen&&(
              <div style={{marginTop:8,background:T.bgSurface,border:"1px solid rgba(217,119,6,.3)",borderRadius:8,overflow:"hidden",boxShadow:"0 4px 12px rgba(0,0,0,.12)"}}>
                <div style={{padding:"6px 8px",borderBottom:`1px solid ${T.border}`}}>
                  <input autoFocus placeholder="Search users…" value={stewardsSearch} onChange={e=>setStewardsSearch(e.target.value)}
                    style={{width:"100%",padding:"5px 8px",background:T.bgElevated,border:`1px solid ${T.border}`,borderRadius:6,color:T.text,fontSize:12,outline:"none",boxSizing:"border-box"}}
                    onFocus={e=>e.target.style.borderColor="#d97706"} onBlur={e=>e.target.style.borderColor=T.border}/>
                </div>
                <div style={{maxHeight:180,overflowY:"auto"}}>
                  {USERS_LIST.filter(u=>!stewardsSearch||u.toLowerCase().includes(stewardsSearch.toLowerCase())).map(u=>{
                    const sel=stewards.includes(u);
                    return <button key={u} onClick={()=>{if(sel){const ns=stewards.filter(x=>x!==u);setData(d=>({...d,stewards:ns,steward:ns[0]||""}));}else setData(d=>({...d,stewards:[...stewards,u],steward:stewards[0]||u}));}}
                      style={{width:"100%",display:"flex",alignItems:"center",gap:8,padding:"7px 12px",background:sel?"rgba(217,119,6,.08)":"transparent",border:"none",cursor:"pointer",textAlign:"left",transition:"background .1s"}}
                      onMouseEnter={e=>{if(!sel)e.currentTarget.style.background=T.bgHover;}} onMouseLeave={e=>{if(!sel)e.currentTarget.style.background="transparent";}}>
                      <div style={{width:22,height:22,borderRadius:"50%",background:"rgba(217,119,6,.15)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:8,fontWeight:700,color:"#d97706",flexShrink:0}}>{ava(u)}</div>
                      <span style={{flex:1,fontSize:12,color:sel?"#d97706":T.text,fontWeight:sel?600:400}}>{u}</span>
                      {sel&&<svg width="12" height="12" viewBox="0 0 14 14" fill="none"><path d="M2.5 7.5l3 3 6-6" stroke="#d97706" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round"/></svg>}
                    </button>;
                  })}
                </div>
                <div style={{padding:"6px 8px",borderTop:`1px solid ${T.border}`,display:"flex",justifyContent:"flex-end"}}>
                  <button onClick={()=>setStewardsOpen(false)} style={{padding:"4px 12px",borderRadius:5,background:"#d97706",border:"none",color:"#fff",fontSize:11.5,fontWeight:600,cursor:"pointer"}}>Done</button>
                </div>
              </div>
            )}
          </div>

          {/* TAGS */}
          <div style={{padding:"16px",borderBottom:`1px solid ${T.border}`}}>
            <MetaLabel onEdit={()=>{setTagsOpen(p=>!p);setTagsSearch("");}}>Tags</MetaLabel>
            <div style={{display:"flex",flexWrap:"wrap",gap:5}}>
              {(data.tags||[]).length===0&&<span style={{fontSize:12,color:T.textMuted,fontStyle:"italic"}}>No tags added</span>}
              {(showAllTags?data.tags||[]:(data.tags||[]).slice(0,3)).map(t=>{const c=tc(t);return(
                <span key={t} style={{display:"inline-flex",alignItems:"center",fontSize:11.5,padding:"4px 10px 4px 9px",borderRadius:5,background:c.bg,borderTop:`1px solid ${c.border}`,borderRight:`1px solid ${c.border}`,borderBottom:`1px solid ${c.border}`,borderLeft:`3px solid ${c.color}`,color:c.color,fontWeight:600}}>{t}</span>
              );})}
              {(data.tags||[]).length>3&&!showAllTags&&<span onClick={()=>setShowAllTags(true)} style={{display:"inline-flex",alignItems:"center",fontSize:11.5,padding:"3px 10px",borderRadius:5,background:T.bgElevated,border:`1px solid ${T.border}`,color:T.textMuted,cursor:"pointer",fontWeight:600}}>+{(data.tags||[]).length-3} more</span>}
              {(data.tags||[]).length>3&&showAllTags&&<span onClick={()=>setShowAllTags(false)} style={{display:"inline-flex",alignItems:"center",fontSize:11.5,padding:"3px 10px",borderRadius:5,background:T.bgElevated,border:`1px solid ${T.border}`,color:T.textMuted,cursor:"pointer",fontWeight:600}}>− less</span>}
            </div>
            {tagsOpen&&(
              <div style={{marginTop:8,background:T.bgSurface,border:`1px solid ${T.border}`,borderRadius:8,overflow:"hidden",boxShadow:"0 4px 12px rgba(0,0,0,.12)"}}>
                <div style={{padding:"6px 8px",borderBottom:`1px solid ${T.border}`}}>
                  <input autoFocus placeholder="Search tags…" value={tagsSearch} onChange={e=>setTagsSearch(e.target.value)}
                    style={{width:"100%",padding:"5px 8px",background:T.bgElevated,border:`1px solid ${T.border}`,borderRadius:6,color:T.text,fontSize:12,outline:"none",boxSizing:"border-box"}}
                    onFocus={e=>e.target.style.borderColor=T.accent} onBlur={e=>e.target.style.borderColor=T.border}/>
                </div>
                <div style={{padding:"8px",display:"flex",flexWrap:"wrap",gap:5,maxHeight:160,overflowY:"auto"}}>
                  {["PII","revenue","finance","KPI","events","sensitive","dimension","model","etl","marketing"]
                    .filter(s=>!tagsSearch||s.toLowerCase().includes(tagsSearch.toLowerCase()))
                    .map(s=>{
                      const sel=(data.tags||[]).includes(s); const c=tc(s);
                      return <button key={s} onClick={()=>setData(d=>({...d,tags:sel?d.tags.filter(x=>x!==s):[...(d.tags||[]),s]}))}
                        style={{display:"inline-flex",alignItems:"center",gap:4,padding:"4px 10px",borderRadius:5,fontSize:11.5,cursor:"pointer",transition:"all .1s",background:sel?c.bg:T.bgElevated,borderTop:`1px solid ${sel?c.border:T.border}`,borderRight:`1px solid ${sel?c.border:T.border}`,borderBottom:`1px solid ${sel?c.border:T.border}`,borderLeft:`3px solid ${sel?c.color:T.border}`,color:sel?c.color:T.textSub,fontWeight:sel?600:400}}>
                        {sel&&<svg width="10" height="10" viewBox="0 0 14 14" fill="none"><path d="M2.5 7.5l3 3 6-6" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round"/></svg>}
                        {s}
                      </button>;
                    })}
                </div>
                <div style={{padding:"6px 8px",borderTop:`1px solid ${T.border}`,display:"flex",justifyContent:"flex-end"}}>
                  <button onClick={()=>setTagsOpen(false)} style={{padding:"4px 12px",borderRadius:5,background:T.accent,border:"none",color:"#fff",fontSize:11.5,fontWeight:600,cursor:"pointer"}}>Done</button>
                </div>
              </div>
            )}
          </div>

          {/* BUSINESS GLOSSARY */}
          <div style={{padding:"16px",borderBottom:`1px solid ${T.border}`}}>
            <MetaLabel onEdit={()=>{setAssetGlOpen(p=>!p);setAssetGlSearch("");}}>Business Glossary</MetaLabel>
            <div style={{display:"flex",flexWrap:"wrap",gap:5}}>
              {assetGlTerms.length===0&&<span style={{fontSize:12,color:T.textMuted,fontStyle:"italic"}}>No terms linked</span>}
              {assetGlTerms.slice(0,3).map((t,i)=><span key={i} title={t} style={{display:"inline-flex",alignItems:"center",gap:4,fontSize:11.5,padding:"4px 10px 4px 9px",borderRadius:5,background:"rgba(139,92,246,.08)",borderTop:"1px solid rgba(139,92,246,.2)",borderRight:"1px solid rgba(139,92,246,.2)",borderBottom:"1px solid rgba(139,92,246,.2)",borderLeft:"3px solid #8b5cf6",color:"#8b5cf6",fontWeight:600}}>{t.length>10?t.slice(0,10)+"…":t}<button onClick={()=>setAssetGlTerms(prev=>prev.filter((_,j)=>j!==i))} style={{background:"none",border:"none",cursor:"pointer",color:"inherit",padding:0,lineHeight:1,display:"flex",opacity:.6}} onMouseEnter={e=>e.currentTarget.style.opacity="1"} onMouseLeave={e=>e.currentTarget.style.opacity=".6"}>{Ic.x(7)}</button></span>)}
              {assetGlTerms.length>3&&<span title={assetGlTerms.slice(3).join(", ")} style={{display:"inline-flex",alignItems:"center",fontSize:11.5,padding:"3px 10px",borderRadius:5,background:T.bgElevated,border:`1px solid ${T.border}`,color:T.textMuted,cursor:"default",fontWeight:600}}>+{assetGlTerms.length-3}</span>}
            </div>
            {assetGlOpen&&(
              <div style={{marginTop:8,background:T.bgSurface,border:"1px solid rgba(139,92,246,.3)",borderRadius:8,overflow:"hidden",boxShadow:"0 4px 12px rgba(0,0,0,.12)"}}>
                <div style={{padding:"6px 8px",borderBottom:`1px solid ${T.border}`}}>
                  <input autoFocus placeholder="Search glossary terms…" value={assetGlSearch} onChange={e=>setAssetGlSearch(e.target.value)}
                    style={{width:"100%",padding:"5px 8px",background:T.bgElevated,border:`1px solid ${T.border}`,borderRadius:6,color:T.text,fontSize:12,outline:"none",boxSizing:"border-box"}}
                    onFocus={e=>e.target.style.borderColor="#8b5cf6"} onBlur={e=>e.target.style.borderColor=T.border}/>
                </div>
                <div style={{maxHeight:200,overflowY:"auto"}}>
                  {GLOSSARY_TERMS.filter(t=>!assetGlSearch||t.term.toLowerCase().includes(assetGlSearch.toLowerCase())||t.abbr?.toLowerCase().includes(assetGlSearch.toLowerCase())).map(t=>{
                    const sel=assetGlTerms.includes(t.term);
                    return(<button key={t.id} onClick={()=>setAssetGlTerms(prev=>sel?prev.filter(x=>x!==t.term):[...prev,t.term])}
                      style={{width:"100%",display:"flex",alignItems:"center",gap:8,padding:"8px 12px",background:sel?"rgba(139,92,246,.06)":"transparent",border:"none",cursor:"pointer",textAlign:"left",transition:"background .1s"}}
                      onMouseEnter={e=>{if(!sel)e.currentTarget.style.background=T.bgHover;}} onMouseLeave={e=>{if(!sel)e.currentTarget.style.background="transparent";}}>
                      <div style={{flex:1,minWidth:0}}>
                        <div style={{fontSize:12,fontWeight:600,color:sel?"#8b5cf6":T.text}}>{t.term}</div>
                        <div style={{fontSize:10.5,color:T.textMuted,display:"flex",gap:5,marginTop:1}}>
                          {t.abbr&&t.abbr!=="—"&&<span style={{fontFamily:"'Geist Mono',monospace"}}>{t.abbr}</span>}
                          <span>{t.domain}</span>
                        </div>
                      </div>
                      {sel&&<svg width="12" height="12" viewBox="0 0 14 14" fill="none"><path d="M2.5 7.5l3 3 6-6" stroke="#8b5cf6" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round"/></svg>}
                    </button>);
                  })}
                  {GLOSSARY_TERMS.filter(t=>!assetGlSearch||t.term.toLowerCase().includes(assetGlSearch.toLowerCase())).length===0&&<div style={{padding:"12px",fontSize:12,color:T.textMuted,textAlign:"center"}}>No terms match</div>}
                </div>
                <div style={{padding:"6px 8px",borderTop:`1px solid ${T.border}`,display:"flex",justifyContent:"flex-end"}}>
                  <button onClick={()=>setAssetGlOpen(false)} style={{padding:"4px 12px",borderRadius:5,background:"#8b5cf6",border:"none",color:"#fff",fontSize:11.5,fontWeight:600,cursor:"pointer"}}>Done</button>
                </div>
              </div>
            )}
          </div>

          {/* ACTIONS */}
          <div style={{padding:"16px"}}>
            <MetaLabel>Actions</MetaLabel>
            {[
              {l:"Request Access", fn:()=>onToast("Access request sent","success")},
              {l:"Copy Link",      fn:()=>onToast("Link copied","success")},
              {l:"Browse Assets",fn:()=>setTab("assets")},
            ].map((a,i,arr)=>(
              <button key={i} onClick={a.fn}
                style={{width:"100%",display:"flex",alignItems:"center",justifyContent:"space-between",padding:"8px 0",background:"none",border:"none",borderBottom:i<arr.length-1?`1px solid ${T.border}`:"none",color:T.textSub,fontSize:12.5,cursor:"pointer",transition:"color .1s"}}
                onMouseEnter={e=>e.currentTarget.style.color=T.accent} onMouseLeave={e=>e.currentTarget.style.color=T.textSub}>
                {a.l}
                <svg width="9" height="9" viewBox="0 0 10 10" fill="none"><path d="M3 2l4 3-4 3" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round"/></svg>
              </button>
            ))}
          </div>

        </div>}
      </div>

      {/* Certificate edit modal (centered — cert is a single-step action) */}
      {editModal==="cert"&&(
        <>
          <div onClick={()=>setEditModal(null)} style={{position:"fixed",inset:0,zIndex:500,background:"rgba(0,0,0,.4)"}}/>
          <div style={{position:"fixed",top:"50%",left:"50%",transform:"translate(-50%,-50%)",zIndex:501,background:T.bgSurface,border:`1px solid ${T.border}`,borderRadius:14,boxShadow:"0 24px 64px rgba(0,0,0,.4)",width:280,display:"flex",flexDirection:"column",overflow:"hidden"}}>
            <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"14px 16px",borderBottom:`1px solid ${T.border}`}}>
              <span style={{fontSize:13.5,fontWeight:700,color:T.text}}>Edit Certificate</span>
              <button onClick={()=>setEditModal(null)} style={{background:"none",border:"none",cursor:"pointer",color:T.textMuted,padding:3,display:"flex",borderRadius:5}} onMouseEnter={e=>e.currentTarget.style.color=T.text} onMouseLeave={e=>e.currentTarget.style.color=T.textMuted}>
                <svg width="12" height="12" viewBox="0 0 10 10" fill="none"><path d="M1.5 1.5l7 7M8.5 1.5l-7 7" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round"/></svg>
              </button>
            </div>
            <div style={{overflowY:"auto"}}>
              {Object.entries(CMETA).map(([c,m])=>(
                <button key={c} onClick={()=>{setData(d=>({...d,cert:c}));setEditModal(null);onToast(`Certification set to ${c}`,"success");}}
                  style={{width:"100%",display:"flex",alignItems:"center",gap:12,padding:"11px 16px",background:data.cert===c?m.bg:"transparent",border:"none",cursor:"pointer",transition:"background .1s"}}
                  onMouseEnter={e=>{if(data.cert!==c)e.currentTarget.style.background=T.bgHover;}}
                  onMouseLeave={e=>{if(data.cert!==c)e.currentTarget.style.background="transparent";}}>
                  <span style={{fontSize:16}}>{m.icon}</span>
                  <span style={{flex:1,fontSize:13,fontWeight:600,color:m.color}}>{c}</span>
                  {data.cert===c&&<svg width="13" height="13" viewBox="0 0 14 14" fill="none"><path d="M2.5 7.5l3 3 6-6" stroke={m.color} strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round"/></svg>}
                </button>
              ))}
            </div>
          </div>
        </>
      )}

      {/* Certification Modal */}
      <Modal open={certModal} onClose={()=>setCertModal(false)} title={`Certify "${asset.name}"`}>
        <p style={{fontSize:13,color:T.textSub,marginBottom:16}}>Certifying marks this asset as trusted and production-ready. This action is logged and visible to all users.</p>
        <div style={{display:"flex",flexDirection:"column",gap:12}}>
          {[
            {label:"Description documented", done:!!(descVal)},
            {label:"Owner assigned",          done:owners.length>0},
            {label:"Steward assigned",        done:stewards.length>0},
            {label:"Domain set",              done:!!(data.domain)},
          ].map((c,i)=>(
            <div key={i} style={{display:"flex",alignItems:"center",gap:10,padding:"8px 12px",background:c.done?T.accentDim:T.bgElevated,border:`1px solid ${c.done?"rgba(238,36,36,0.2)":T.border}`,borderRadius:8}}>
              <span style={{color:c.done?T.accent:T.textMuted}}>{c.done?Ic.check(14):Ic.x(14)}</span>
              <span style={{fontSize:13,color:c.done?T.text:T.textSub}}>{c.label}</span>
              {!c.done&&<span style={{fontSize:11,color:T.amber,marginLeft:"auto"}}>Required</span>}
            </div>
          ))}
        </div>
        <div style={{marginTop:16}}>
          <div style={{fontSize:12,color:T.textSub,marginBottom:6}}>Certification notes</div>
          <Input2 multiline rows={3} placeholder="Add notes for the certification record…" value={certNote} onChange={e=>setCertNote(e.target.value)}/>
        </div>
        <div style={{display:"flex",gap:8,marginTop:20,justifyContent:"flex-end"}}>
          <Btn onClick={()=>setCertModal(false)}>Cancel</Btn>
          <Btn variant="primary" icon={Ic.cert(13)} onClick={handleCertify}>Certify Asset</Btn>
        </div>
      </Modal>
    </div>
  );
};

// ── Detail page for file assets (Object / Blob) ──
const FileAssetDetail = ({asset, onBack, onToast}) => {
  const [desc,      setDesc]      = useState(asset.description||"");
  const [editing,   setEditing]   = useState(false);
  const [tab,       setTab]       = useState("overview");
  const FILE_FORMAT_COLORS = {CSV:"#16a34a",Parquet:"#0891b2",JSON:"#d97706",JSON_LINES:"#d97706",ORC:"#7c3aed",Avro:"#0891b2",Delta:"#ff3621"};
  const fc = FILE_FORMAT_COLORS[asset.fileFormat]||"#6b7280";

  const SLabel = ({children})=>(
    <div style={{fontSize:10,fontWeight:700,color:T.textMuted,textTransform:"uppercase",letterSpacing:"0.07em",marginBottom:7}}>{children}</div>
  );
  const MetaRow = ({label,value,mono})=>(
    <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",padding:"8px 0",borderBottom:`1px solid ${T.border}`,fontSize:12,gap:16}}>
      <span style={{color:T.textMuted,flexShrink:0}}>{label}</span>
      <span style={{color:T.text,textAlign:"right",fontFamily:mono?"'Geist Mono',monospace":"inherit",fontSize:mono?11.5:12}}>{value||"—"}</span>
    </div>
  );
  const Avatar = ({name,size=22})=>{
    const initials = (name||"").split(".").map(s=>s[0]?.toUpperCase()||"").join("").slice(0,2);
    return <div style={{width:size,height:size,borderRadius:Math.floor(size/3),background:T.accentDim,border:`1px solid ${T.accent}33`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:size*0.32,fontWeight:700,color:T.accent,flexShrink:0}}>{initials}</div>;
  };

  const TABS = [{id:"overview",label:"Overview"},{id:"properties",label:"Properties"},{id:"lineage",label:"Lineage"}];

  const formatDate = (iso) => {
    if(!iso) return "—";
    try { return new Date(iso).toLocaleDateString("en-US",{month:"short",day:"numeric",year:"numeric",hour:"2-digit",minute:"2-digit"}); }
    catch{ return iso; }
  };

  const usageColor = {High:T.accent,Med:T.amber,Low:T.textMuted}[asset.usage]||T.textMuted;

  return (
    <div className="fadeUp" style={{height:"100%",display:"flex",flexDirection:"column"}}>
      <Topbar breadcrumb={[{label:"Data Catalog",onClick:onBack},{label:asset.name}]}/>

      {/* ── Hero header ── */}
      <div style={{background:T.bgSurface,borderBottom:`1px solid ${T.border}`,flexShrink:0,padding:"20px 28px 0"}}>
        <div style={{display:"flex",alignItems:"flex-start",gap:16,marginBottom:16}}>
          {/* Service icon */}
          <div style={{width:52,height:52,borderRadius:13,background:`${fc}12`,border:`1.5px solid ${fc}30`,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,marginTop:2}}>
            <ServiceIcon service={asset.service} size={30}/>
          </div>
          <div style={{flex:1,minWidth:0}}>
            <div style={{display:"flex",alignItems:"center",gap:7,marginBottom:6,flexWrap:"wrap"}}>
              <TypeBadge type={asset.type}/>
              {asset.fileFormat&&<span style={{fontSize:10,fontWeight:700,padding:"2px 7px",borderRadius:4,background:`${fc}18`,color:fc,border:`1px solid ${fc}33`}}>{asset.fileFormat}</span>}
              <CertBadge cert={asset.cert}/>
              <TierBadge tier={asset.tier}/>
              <span style={{fontSize:10,fontWeight:600,padding:"2px 8px",borderRadius:4,background:T.bgElevated,color:usageColor,border:`1px solid ${T.border}`}}>Usage: {asset.usage}</span>
              {asset.slaFreshness&&<span style={{fontSize:10,fontWeight:600,padding:"2px 8px",borderRadius:4,background:"rgba(99,102,241,.08)",color:T.accent,border:`1px solid ${T.accent}22`}}>SLA {asset.slaFreshness}</span>}
            </div>
            <h2 style={{fontSize:18,fontWeight:700,fontFamily:"'Geist Mono',monospace",color:T.text,letterSpacing:"-0.03em",margin:"0 0 6px",lineHeight:1.2}}>{asset.name}</h2>
            {/* Path breadcrumb */}
            <div style={{display:"flex",alignItems:"center",gap:4,flexWrap:"wrap"}}>
              <span style={{fontSize:11,color:T.textMuted}}>{asset.connectionLabel}</span>
              {(asset.path||[]).map((seg,i)=>(
                <React.Fragment key={i}>
                  <svg width="8" height="8" viewBox="0 0 10 10" fill="none" style={{color:T.textMuted,flexShrink:0,opacity:.5}}><path d="M3 2l4 3-4 3" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/></svg>
                  <span style={{fontSize:11,fontFamily:"'Geist Mono',monospace",color:T.textMuted}}>{seg}</span>
                </React.Fragment>
              ))}
              <svg width="8" height="8" viewBox="0 0 10 10" fill="none" style={{color:T.textMuted,flexShrink:0,opacity:.5}}><path d="M3 2l4 3-4 3" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/></svg>
              <span style={{fontSize:11,fontFamily:"'Geist Mono',monospace",color:T.text,fontWeight:600}}>{asset.name}</span>
            </div>
          </div>
          <div style={{display:"flex",gap:6,flexShrink:0,marginTop:4}}>
            <Btn ghost small onClick={()=>onToast("Copied link","success")}>Copy Link</Btn>
            <Btn variant="primary" small onClick={()=>onToast("Editing…","info")}>Edit</Btn>
          </div>
        </div>

        {/* Tab bar */}
        <div style={{display:"flex",gap:0,borderTop:`1px solid ${T.border}`,marginLeft:-28,marginRight:-28,paddingLeft:28}}>
          {TABS.map(t=>(
            <button key={t.id} onClick={()=>setTab(t.id)} style={{padding:"10px 16px",background:"transparent",border:"none",marginBottom:-1,borderBottom:`2px solid ${tab===t.id?T.accent:"transparent"}`,color:tab===t.id?T.text:T.textSub,fontSize:12.5,fontWeight:tab===t.id?600:400,cursor:"pointer",transition:"all .12s",whiteSpace:"nowrap"}}>
              {t.label}
            </button>
          ))}
        </div>
      </div>

      {/* ── Body ── */}
      <div style={{flex:1,overflow:"auto",padding:"24px 28px",display:"flex",gap:22,alignItems:"flex-start"}}>

        {/* ── OVERVIEW TAB ── */}
        {tab==="overview"&&<>
          <div style={{flex:1,minWidth:0,display:"flex",flexDirection:"column",gap:14}}>

            {/* Description */}
            <Card2 style={{padding:"16px 18px"}}>
              <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:10}}>
                <span style={{fontSize:13,fontWeight:600,color:T.text}}>Description</span>
                <button onClick={()=>{ if(editing)onToast("Description saved","success"); setEditing(e=>!e); }}
                  style={{fontSize:11.5,color:editing?T.accent:T.textMuted,background:"none",border:`1px solid ${editing?T.accent:T.border}`,borderRadius:6,cursor:"pointer",padding:"3px 10px",transition:"all .15s"}}>
                  {editing?"Save":"Edit"}
                </button>
              </div>
              {editing
                ? <textarea value={desc} onChange={e=>setDesc(e.target.value)} rows={4}
                    style={{width:"100%",background:T.bgElevated,border:`1.5px solid ${T.accent}`,borderRadius:7,color:T.text,fontSize:13,padding:"9px 11px",resize:"vertical",outline:"none",boxSizing:"border-box",fontFamily:"inherit",lineHeight:1.6}}/>
                : <p style={{fontSize:13,color:desc?T.textSub:T.textMuted,lineHeight:1.7,margin:0,fontStyle:desc?"normal":"italic"}}>{desc||"No description yet — click Edit to add one."}</p>
              }
            </Card2>

            {/* Tags */}
            <Card2 style={{padding:"16px 18px"}}>
              <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:10}}>
                <span style={{fontSize:13,fontWeight:600,color:T.text}}>Tags</span>
                <button onClick={()=>onToast("Tag editor coming soon","info")} style={{fontSize:11,color:T.textMuted,background:"none",border:`1px solid ${T.border}`,borderRadius:6,cursor:"pointer",padding:"2px 8px",display:"flex",alignItems:"center",gap:4}}>
                  <svg width="9" height="9" viewBox="0 0 10 10" fill="none"><path d="M5 1v8M1 5h8" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round"/></svg> Add
                </button>
              </div>
              {(asset.tags||[]).length===0
                ? <span style={{fontSize:12,color:T.textMuted,fontStyle:"italic"}}>No tags applied</span>
                : <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
                    {asset.tags.map(t=>{const c=tc(t);return(
                      <span key={t} style={{display:"inline-flex",alignItems:"center",fontSize:11.5,padding:"4px 10px 4px 9px",borderRadius:5,background:c.bg,borderTop:`1px solid ${c.border}`,borderRight:`1px solid ${c.border}`,borderBottom:`1px solid ${c.border}`,borderLeft:`3px solid ${c.color}`,color:c.color,fontWeight:600}}>{t}</span>
                    );})}
                  </div>
              }
            </Card2>

            {/* Ownership */}
            <Card2 style={{padding:"16px 18px"}}>
              <span style={{fontSize:13,fontWeight:600,color:T.text,display:"block",marginBottom:12}}>Ownership</span>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:16}}>
                <div>
                  <SLabel>Owners</SLabel>
                  <div style={{display:"flex",flexDirection:"column",gap:6}}>
                    {(asset.owners||[asset.owner]).map(o=>(
                      <div key={o} style={{display:"flex",alignItems:"center",gap:8}}>
                        <Avatar name={o}/>
                        <span style={{fontSize:12,color:T.textSub}}>{o}</span>
                      </div>
                    ))}
                  </div>
                </div>
                <div>
                  <SLabel>Stewards</SLabel>
                  <div style={{display:"flex",flexDirection:"column",gap:6}}>
                    {(asset.stewards||[asset.steward]).filter(Boolean).map(s=>(
                      <div key={s} style={{display:"flex",alignItems:"center",gap:8}}>
                        <Avatar name={s}/>
                        <span style={{fontSize:12,color:T.textSub}}>{s}</span>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            </Card2>
          </div>

          {/* Sidebar */}
          <div style={{width:234,flexShrink:0,display:"flex",flexDirection:"column",gap:12}}>
            <Card2 style={{padding:"14px 16px"}}>
              <SLabel>Connection</SLabel>
              <div style={{display:"flex",alignItems:"center",gap:9}}>
                <ServiceIcon service={asset.service} size={22}/>
                <span style={{fontSize:12,color:T.textSub,lineHeight:1.3}}>{asset.connectionLabel}</span>
              </div>
            </Card2>
            <Card2 style={{padding:"14px 16px"}}>
              <SLabel>File Info</SLabel>
              {asset.fileFormat&&<div style={{display:"flex",justifyContent:"space-between",marginBottom:7}}>
                <span style={{fontSize:12,color:T.textMuted}}>Format</span>
                <span style={{fontSize:11.5,fontWeight:700,padding:"1px 7px",borderRadius:4,background:`${fc}15`,color:fc,border:`1px solid ${fc}30`,fontFamily:"'Geist Mono',monospace"}}>{asset.fileFormat}</span>
              </div>}
              <div style={{display:"flex",justifyContent:"space-between",marginBottom:7}}>
                <span style={{fontSize:12,color:T.textMuted}}>Size</span>
                <span style={{fontSize:12,color:T.text,fontFamily:"'Geist Mono',monospace"}}>{asset.size||"—"}</span>
              </div>
              {asset.storageClass&&<div style={{display:"flex",justifyContent:"space-between",marginBottom:7}}>
                <span style={{fontSize:12,color:T.textMuted}}>Storage Class</span>
                <span style={{fontSize:11.5,color:T.textSub,fontFamily:"'Geist Mono',monospace"}}>{asset.storageClass}</span>
              </div>}
              {asset.accessTier&&<div style={{display:"flex",justifyContent:"space-between",marginBottom:7}}>
                <span style={{fontSize:12,color:T.textMuted}}>Access Tier</span>
                <span style={{fontSize:11.5,color:T.textSub,fontFamily:"'Geist Mono',monospace"}}>{asset.accessTier}</span>
              </div>}
              <div style={{display:"flex",justifyContent:"space-between"}}>
                <span style={{fontSize:12,color:T.textMuted}}>Modified</span>
                <span style={{fontSize:11,color:T.textSub}}>{asset.updated}</span>
              </div>
            </Card2>
            <Card2 style={{padding:"14px 16px"}}>
              <SLabel>Classification</SLabel>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8}}>
                <span style={{fontSize:12,color:T.textMuted}}>Domain</span>
                <span style={{fontSize:11.5,fontWeight:600,color:T.text}}>{asset.domain}</span>
              </div>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8}}>
                <span style={{fontSize:12,color:T.textMuted}}>Cert</span>
                <CertBadge cert={asset.cert}/>
              </div>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                <span style={{fontSize:12,color:T.textMuted}}>Tier</span>
                <TierBadge tier={asset.tier}/>
              </div>
            </Card2>
          </div>
        </>}

        {/* ── PROPERTIES TAB ── */}
        {tab==="properties"&&(
          <div style={{flex:1,maxWidth:700}}>
            <Card2 style={{padding:"18px 20px"}}>
              <h3 style={{fontSize:13,fontWeight:600,color:T.text,margin:"0 0 4px"}}>File Properties</h3>
              <MetaRow label="File Name"      value={asset.name}        mono/>
              <MetaRow label="Format"         value={asset.fileFormat}  mono/>
              <MetaRow label="Size"           value={asset.size}        mono/>
              <MetaRow label="Last Modified"  value={formatDate(asset.lastModified)} mono/>
              {asset.storageClass&&<MetaRow label="Storage Class" value={asset.storageClass} mono/>}
              {asset.accessTier&&<MetaRow label="Access Tier"     value={asset.accessTier}   mono/>}
              <MetaRow label="Domain"         value={asset.domain}/>
              <MetaRow label="Owner"          value={asset.owner}/>
              <MetaRow label="Steward"        value={asset.steward}/>
              <MetaRow label="Certification"  value={asset.cert}/>
              <MetaRow label="Tier"           value={asset.tier ? `Tier ${asset.tier}` : null}/>
              <MetaRow label="Usage"          value={asset.usage}/>
              <MetaRow label="SLA Freshness"  value={asset.slaFreshness}/>
              <MetaRow label="Connection"     value={asset.connectionLabel}/>
              <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",padding:"8px 0",fontSize:12,gap:16}}>
                <span style={{color:T.textMuted,flexShrink:0}}>Full Path</span>
                <span style={{fontFamily:"'Geist Mono',monospace",fontSize:11,color:T.text,textAlign:"right",wordBreak:"break-all"}}>{asset.db}</span>
              </div>
            </Card2>
          </div>
        )}

        {/* ── LINEAGE TAB ── */}
        {tab==="lineage"&&(
          <div style={{flex:1}}>
            <Card2 style={{padding:"18px 20px"}}>
              <h3 style={{fontSize:13,fontWeight:600,color:T.text,margin:"0 0 16px"}}>Storage Path</h3>
              <div style={{display:"flex",alignItems:"center",gap:0,flexWrap:"wrap",padding:"16px",background:T.bgElevated,borderRadius:8,border:`1px solid ${T.border}`}}>
                {/* Connection node */}
                <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:6}}>
                  <div style={{width:44,height:44,borderRadius:11,background:`${fc}12`,border:`1.5px solid ${fc}30`,display:"flex",alignItems:"center",justifyContent:"center"}}>
                    <ServiceIcon service={asset.service} size={24}/>
                  </div>
                  <span style={{fontSize:10,color:T.textMuted,textAlign:"center",maxWidth:80,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{asset.connectionLabel}</span>
                </div>
                {/* Path segments */}
                {(asset.path||[]).map((seg,i)=>(
                  <React.Fragment key={i}>
                    <div style={{width:32,height:1,background:T.border,flexShrink:0,margin:"0 4px",marginBottom:20}}/>
                    <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:6}}>
                      <div style={{width:44,height:44,borderRadius:11,background:T.bgSurface,border:`1.5px solid ${T.border}`,display:"flex",alignItems:"center",justifyContent:"center",color:T.textMuted}}>
                        <svg width="18" height="18" viewBox="0 0 20 20" fill="none"><path d="M3 6a1 1 0 011-1h4l2 2h6a1 1 0 011 1v7a1 1 0 01-1 1H4a1 1 0 01-1-1V6z" stroke="currentColor" strokeWidth="1.4" strokeLinejoin="round"/></svg>
                      </div>
                      <span style={{fontSize:10,color:T.textMuted,textAlign:"center",maxWidth:80,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",fontFamily:"'Geist Mono',monospace"}}>{seg}</span>
                    </div>
                  </React.Fragment>
                ))}
                {/* File node (current) */}
                <div style={{width:32,height:1,background:T.accent,flexShrink:0,margin:"0 4px",marginBottom:20,opacity:.6}}/>
                <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:6}}>
                  <div style={{width:44,height:44,borderRadius:11,background:`${fc}15`,border:`2px solid ${fc}55`,display:"flex",alignItems:"center",justifyContent:"center",color:fc,boxShadow:`0 0 0 3px ${fc}10`}}>
                    <svg width="18" height="18" viewBox="0 0 20 20" fill="none"><path d="M5 3h7l4 4v10a1 1 0 01-1 1H5a1 1 0 01-1-1V4a1 1 0 011-1z" stroke="currentColor" strokeWidth="1.4" strokeLinejoin="round"/><path d="M12 3v4h4" stroke="currentColor" strokeWidth="1.4" strokeLinejoin="round"/></svg>
                  </div>
                  <span style={{fontSize:10,color:T.text,fontWeight:700,textAlign:"center",maxWidth:100,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",fontFamily:"'Geist Mono',monospace"}}>{asset.name}</span>
                </div>
              </div>
              <div style={{marginTop:16,padding:"12px 16px",background:T.bgElevated,borderRadius:8,border:`1px solid ${T.border}`}}>
                <div style={{fontSize:11,fontWeight:700,color:T.textMuted,textTransform:"uppercase",letterSpacing:"0.07em",marginBottom:8}}>Full Path</div>
                <div style={{fontSize:12,fontFamily:"'Geist Mono',monospace",color:T.textSub,wordBreak:"break-all",lineHeight:1.6}}>{asset.db}</div>
              </div>
            </Card2>
          </div>
        )}
      </div>
    </div>
  );
};

const CONTAINER_TYPES = new Set(["Database","Catalog","Schema","Bucket","Container","Folder"]);
const AssetDetail = ({asset, assetStack=[], onBack, onAsset, onToast, onNav}) => {
  if(CONTAINER_TYPES.has(asset.type)) return <ContainerAssetDetail asset={asset} assetStack={assetStack} onBack={onBack} onAsset={onAsset} onToast={onToast}/>;
  if(asset.type==="Object"||asset.type==="Blob") return <FileAssetDetail asset={asset} onBack={onBack} onToast={onToast}/>;
  return <AssetDetailFull asset={asset} assetStack={assetStack} onBack={onBack} onToast={onToast} onNav={onNav}/>;
};

const AssetDetailFull = ({asset, assetStack=[], onBack, onToast, onNav}) => {
  const [tab,        setTab]       = useState("overview");
  const [selCol,     setSelCol]    = useState(null);
  const [colPanelTab,setColPanelTab]=useState("overview");
  const [data,         setData]        = useState({...asset,owners:asset.owners||[asset.owner],stewards:asset.stewards||(asset.steward?[asset.steward]:[]),tags:[...(asset.tags||[])]});
  const [certOpen,       setCertOpen]       = useState(false);
  const [editModal,      setEditModal]      = useState(null);
  const [certModal,      setCertModal]      = useState(false);
  const [certNote,       setCertNote]       = useState("");
  const [domainOpen,     setDomainOpen]     = useState(false);
  const [domainSearch,   setDomainSearch]   = useState("");
  const [ownersOpen,     setOwnersOpen]     = useState(false);
  const [ownersSearch,   setOwnersSearch]   = useState("");
  const [stewardsOpen,   setStewardsOpen]   = useState(false);
  const [stewardsSearch, setStewardsSearch] = useState("");
  const [tagsOpen,       setTagsOpen]       = useState(false);
  const [tagsSearch,     setTagsSearch]     = useState("");
  const [colTagsMap,       setColTagsMap]       = useState({});
  const [colTagModalOpen,  setColTagModalOpen]  = useState(false);
  const [colTagModalSearch,setColTagModalSearch]= useState("");
  const [showAllColTags,   setShowAllColTags]   = useState(false);
  const [colGlTermsMap,    setColGlTermsMap]    = useState({});
  const [colGlOpen,        setColGlOpen]        = useState(false);
  const [colGlSearch,      setColGlSearch]      = useState("");
  const [colSelectTestOpen,setColSelectTestOpen] = useState(false);
  const [colSelectTestIds, setColSelectTestIds]  = useState(new Set());
  const [colTestsMap,      setColTestsMap]       = useState({});
  const [showAllOwners,  setShowAllOwners]  = useState(false);
  const [showAllStewards,setShowAllStewards]= useState(false);
  const [showAllTags,    setShowAllTags]    = useState(false);
  const [assetGlTerms,   setAssetGlTerms]  = useState([]);
  const [assetGlOpen,    setAssetGlOpen]   = useState(false);
  const [assetGlSearch,  setAssetGlSearch] = useState("");

  const DOMAINS_LIST = ["Commerce","Finance","Product","Marketing","ML","Engineering"];
  const USERS_LIST   = ["maya.chen","sarah.kim","alex.wu","dev.patel","lisa.ray","priya.nair","james.oh"];
  const ava          = name => (name||"?").split(".").map(s=>s[0]?.toUpperCase()||"").join("");

  // cert meta inline
  const CMETA = {
    "Draft":       {color:"#6b7280",bg:"rgba(107,114,128,.1)", border:"rgba(107,114,128,.25)",icon:"◐"},
    "In Review":   {color:"#d97706",bg:"rgba(217,119,6,.12)",  border:"rgba(217,119,6,.3)",   icon:"⏳"},
    "Approved":    {color:"#16a34a",bg:"rgba(22,163,74,.12)",  border:"rgba(22,163,74,.3)",   icon:"✓"},
    "Rejected":    {color:"#e11d48",bg:"rgba(225,29,72,.12)",  border:"rgba(225,29,72,.3)",   icon:"✕"},
    "Deprecated":  {color:"#7c3aed",bg:"rgba(124,58,237,.1)",  border:"rgba(124,58,237,.25)", icon:"—"},
  };

  const cm = CMETA[data.cert]||CMETA["Draft"];
  const owners   = Array.isArray(data.owners)  ? data.owners   : (data.owner   ? [data.owner]   : []);
  const stewards = Array.isArray(data.stewards) ? data.stewards : (data.steward ? [data.steward] : []);

  useEffect(()=>{
    if(!certOpen) return;
    const close=()=>setCertOpen(false);
    document.addEventListener("mousedown",close);
    return ()=>document.removeEventListener("mousedown",close);
  },[certOpen]);

  const tabs=[
    {key:"overview",label:"Overview"},{key:"schema",label:"Schema"},{key:"lineage",label:"Lineage"},
    {key:"observability",label:"Observability"},{key:"contract",label:"Contract"},{key:"usage",label:"Usage"},
    {key:"activity",label:"Audit Logs"},
  ];

  const handleCertify=()=>{
    setData(d=>({...d,cert:"Approved"}));
    setCertModal(false);
    onToast(`${asset.name} certified successfully`,"success");
  };

  const TAG_C_FULL = {
    PII:{bg:"rgba(225,29,72,.1)",color:"#e11d48",border:"rgba(225,29,72,.25)"},
    revenue:{bg:"rgba(37,99,235,.08)",color:"#2563eb",border:"rgba(37,99,235,.2)"},
    finance:{bg:"rgba(37,99,235,.08)",color:"#2563eb",border:"rgba(37,99,235,.2)"},
    KPI:{bg:"rgba(22,163,74,.08)",color:"#16a34a",border:"rgba(22,163,74,.2)"},
    sensitive:{bg:"rgba(124,58,237,.08)",color:"#7c3aed",border:"rgba(124,58,237,.2)"},
    events:{bg:"rgba(6,182,212,.08)",color:"#0891b2",border:"rgba(6,182,212,.2)"},
    model:{bg:"rgba(99,102,241,.08)",color:"#6366f1",border:"rgba(99,102,241,.2)"},
    etl:{bg:"rgba(245,158,11,.08)",color:"#d97706",border:"rgba(245,158,11,.2)"},
  };
  const tcFull = tag => TAG_C_FULL[tag]||{bg:T.bgElevated,color:T.textSub,border:T.border};

  const MetaLabel = ({children,onEdit})=>(
    <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:8}}>
      <div style={{fontSize:10.5,fontWeight:700,color:T.textMuted,textTransform:"uppercase",letterSpacing:"0.08em"}}>{children}</div>
      {onEdit&&<button onClick={onEdit} style={{background:"none",border:"none",cursor:"pointer",color:T.textMuted,padding:"2px 3px",display:"flex",borderRadius:4,transition:"all .12s"}}
        onMouseEnter={e=>{e.currentTarget.style.color=T.accent;e.currentTarget.style.background=T.accentDim;}}
        onMouseLeave={e=>{e.currentTarget.style.color=T.textMuted;e.currentTarget.style.background="none";}}>
        <svg width="11" height="11" viewBox="0 0 14 14" fill="none"><path d="M9.5 2.5l2 2L4 12H2v-2L9.5 2.5z" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round" strokeLinejoin="round"/></svg>
      </button>}
    </div>
  );

  return <div className="fadeUp" style={{height:"100%",display:"flex",flexDirection:"column"}}>
    <Topbar breadcrumb={[{label:"Data Catalog",onClick:onBack},{label:asset.name}]}/>

    {/* ── Asset header ── */}
    <div style={{background:T.bgSurface,borderBottom:`1px solid ${T.border}`,flexShrink:0,padding:"16px 28px 0"}}>
      {/* type + db path */}
      <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:8}}>
        <TypeBadge type={data.type}/>
        <span style={{fontSize:11.5,color:T.textMuted,fontFamily:"'Geist Mono',monospace"}}>{data.db}</span>
      </div>
      {/* name + actions */}
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",gap:12,marginBottom:14}}>
        <h2 style={{fontSize:22,fontWeight:700,fontFamily:"'Geist Mono',monospace",color:T.text,letterSpacing:"-0.04em",margin:0}}>{data.name}</h2>
        <div style={{display:"flex",gap:7,alignItems:"center",flexShrink:0}}>
          {data.cert!=="Approved"&&(
            <button onClick={()=>setCertModal(true)}
              style={{display:"inline-flex",alignItems:"center",gap:6,padding:"6px 14px",borderRadius:8,background:"#16a34a12",border:"1px solid rgba(22,163,74,.3)",color:"#16a34a",fontSize:12.5,fontWeight:600,cursor:"pointer",transition:"opacity .1s"}}
              onMouseEnter={e=>e.currentTarget.style.opacity=".8"} onMouseLeave={e=>e.currentTarget.style.opacity="1"}>
              {Ic.cert(12)} Certify
            </button>
          )}
          <button onClick={()=>onToast("Edit panel coming soon","success")}
            style={{display:"inline-flex",alignItems:"center",gap:6,padding:"6px 14px",borderRadius:8,background:T.bgElevated,border:`1px solid ${T.border}`,color:T.textSub,fontSize:12.5,fontWeight:500,cursor:"pointer",transition:"all .1s"}}
            onMouseEnter={e=>{e.currentTarget.style.borderColor=T.accent;e.currentTarget.style.color=T.accent;}}
            onMouseLeave={e=>{e.currentTarget.style.borderColor=T.border;e.currentTarget.style.color=T.textSub;}}>
            {Ic.edit(11)} Edit
          </button>
        </div>
      </div>
      {/* tab bar */}
      <div style={{display:"flex",marginBottom:-1}}>
        {tabs.map(t=>(
          <button key={t.key} onClick={()=>setTab(t.key)}
            style={{padding:"9px 16px",background:"transparent",border:"none",borderBottom:`2px solid ${tab===t.key?T.accent:"transparent"}`,color:tab===t.key?T.text:T.textMuted,fontSize:13,fontWeight:tab===t.key?600:400,cursor:"pointer",transition:"all .12s",whiteSpace:"nowrap"}}>
            {t.label}
          </button>
        ))}
      </div>
    </div>

    {/* ── Body: content + right sidebar ── */}
    <div style={{flex:1,display:"flex",overflow:"hidden"}}>

      {/* Main content */}
      <div style={{flex:1,overflowY:"auto",padding:24,minWidth:0}}>
        {tab==="overview"  && <AssetOverview asset={asset} data={data} setData={setData} onToast={onToast}/>}
        {tab==="schema"    && <AssetSchema asset={asset} selCol={selCol} onColClick={c=>{ setSelCol(selCol?.name===c?.name?null:c); }} onToast={onToast}/>}
        {tab==="observability" && <AssetObservabilityTab asset={data} onToast={onToast} onNav={onNav}/>}
        {tab==="contract"      && <AssetContractTab asset={data} onToast={onToast}/>}
        {tab==="usage"     && <AssetUsageTab/>}
        {tab==="lineage"   && <AssetLineageFull asset={data}/>}
        {tab==="activity"  && <AuditLogTable entries={ASSET_AUDIT_ENTRIES}/>}
      </div>

      {/* ── Column detail panel — Schema tab only ── */}
      {tab==="schema"&&selCol&&(()=>{
        const prof=COL_PROFILES[selCol.name]||null;
        const colTests=colTestsMap[selCol.name]!==undefined?colTestsMap[selCol.name]:DQ_TEST_CASES.filter(tc=>tc.col&&selCol.name&&tc.col.toLowerCase()===selCol.name.toLowerCase());
        const setColTests=(updater)=>setColTestsMap(p=>{const cur=p[selCol.name]!==undefined?p[selCol.name]:DQ_TEST_CASES.filter(tc=>tc.col&&selCol.name&&tc.col.toLowerCase()===selCol.name.toLowerCase());const next=typeof updater==="function"?updater(cur):updater;return{...p,[selCol.name]:next};});
        const tcSuccess=colTests.filter(t=>t.status==="Success").length;
        const tcFailed=colTests.filter(t=>t.status==="Failed").length;
        const tcAborted=colTests.filter(t=>t.status==="Aborted").length;
        const SC={Success:T.green,Failed:T.rose,Aborted:T.amber};
        const SI={Success:"✓",Failed:"✕",Aborted:"⚠"};
        const StatBar=({pct,color})=>(
          <div style={{width:"100%",height:4,background:T.bgHover,borderRadius:2,overflow:"hidden",marginTop:4}}>
            <div style={{width:`${Math.min(100,pct||0)}%`,height:"100%",background:color,borderRadius:2,transition:"width .3s"}}/>
          </div>
        );
        const DimChip=({dim})=>{
          const dc={Accuracy:{c:"#38bdf8",bg:"rgba(56,189,248,.1)"},Completeness:{c:"#4ade80",bg:"rgba(74,222,128,.1)"},Consistency:{c:"#34d399",bg:"rgba(52,211,153,.1)"},Timeliness:{c:"#facc15",bg:"rgba(250,204,21,.1)"},Validity:{c:"#818cf8",bg:"rgba(129,140,248,.1)"},Uniqueness:{c:"#fb923c",bg:"rgba(251,146,60,.1)"}};
          const s=dc[dim]||{c:T.textMuted,bg:T.bgHover};
          return <span style={{fontSize:10,fontWeight:600,padding:"1px 6px",borderRadius:3,background:s.bg,color:s.c,border:`1px solid ${s.c}33`}}>{dim}</span>;
        };
        const colTabs=[{k:"overview",l:"Overview"},{k:"quality",l:`Quality (${colTests.length})`}];
        return (
          <div style={{width:320,flexShrink:0,borderLeft:`1px solid ${T.border}`,background:T.bgSurface,display:"flex",flexDirection:"column",overflow:"hidden"}}>
            {/* ── Header: just column name + close ── */}
            <div style={{padding:"12px 14px 0",borderBottom:`1px solid ${T.border}`,flexShrink:0}}>
              <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:8}}>
                <span style={{fontSize:14,fontWeight:700,fontFamily:"'Geist Mono',monospace",color:T.text,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{selCol.name}</span>
                <button onClick={()=>{setSelCol(null);setColPanelTab("overview");}} style={{background:"none",border:"none",cursor:"pointer",color:T.textMuted,fontSize:20,lineHeight:1,flexShrink:0,padding:"0 0 0 8px"}}>×</button>
              </div>
              <div style={{display:"flex",gap:0}}>
                {colTabs.map(t=>(
                  <button key={t.k} onClick={()=>setColPanelTab(t.k)}
                    style={{padding:"7px 12px",background:"none",border:"none",borderBottom:`2px solid ${colPanelTab===t.k?T.accent:"transparent"}`,color:colPanelTab===t.k?T.accent:T.textSub,fontSize:12,fontWeight:colPanelTab===t.k?700:400,cursor:"pointer",transition:"all .12s",whiteSpace:"nowrap"}}>
                    {t.l}
                  </button>
                ))}
              </div>
            </div>

            {/* ── Tab content ── */}
            <div style={{overflowY:"auto",flex:1}}>

              {/* ── Overview: metadata + profile stats ── */}
              {colPanelTab==="overview"&&(
                <div style={{padding:14,display:"flex",flexDirection:"column",gap:14}}>

                  {/* Description */}
                  <div>
                    <div style={{fontSize:10,fontWeight:700,color:T.textMuted,textTransform:"uppercase",letterSpacing:"0.07em",marginBottom:6}}>Description</div>
                    {selCol.desc
                      ? <p style={{fontSize:12.5,color:T.textSub,lineHeight:1.65,margin:0,padding:"10px 12px",background:T.bgElevated,borderRadius:7,border:`1px solid ${T.border}`}}>{selCol.desc}</p>
                      : <p style={{fontSize:12,color:T.textMuted,fontStyle:"italic",margin:0}}>No description provided.</p>}
                  </div>

                  {/* Details */}
                  <div>
                    <div style={{fontSize:10,fontWeight:700,color:T.textMuted,textTransform:"uppercase",letterSpacing:"0.07em",marginBottom:6}}>Details</div>
                    <div style={{background:T.bgElevated,borderRadius:8,border:`1px solid ${T.border}`,overflow:"hidden"}}>
                      {[
                        {l:"Data Type",   v:<span style={{fontFamily:"'Geist Mono',monospace",fontSize:12,color:T.blue,fontWeight:600}}>{selCol.type}</span>},
                        {l:"Nullable",    v:<span style={{fontSize:11,color:selCol.nullable?T.amber:T.green,fontWeight:600}}>{selCol.nullable?"Yes":"No"}</span>},
                        {l:"Primary Key", v:<span style={{fontSize:11,color:selCol.pk?T.amber:T.textMuted,fontWeight:600}}>{selCol.pk?"Yes":"No"}</span>},
                      ].map((r,i)=>(
                        <div key={r.l} style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"8px 12px",borderBottom:i<2?`1px solid ${T.border}`:"none"}}>
                          <span style={{fontSize:11.5,color:T.textMuted}}>{r.l}</span>{r.v}
                        </div>
                      ))}
                    </div>
                  </div>

                  {/* Stats — rendered from COL_PROFILES */}
                  {prof&&(
                    <div>
                      <div style={{fontSize:10,fontWeight:700,color:T.textMuted,textTransform:"uppercase",letterSpacing:"0.07em",marginBottom:8}}>Stats</div>
                      <div style={{background:T.bgElevated,borderRadius:8,border:`1px solid ${T.border}`,overflow:"hidden"}}>

                        {/* Null % */}
                        <div style={{padding:"9px 12px",borderBottom:`1px solid ${T.border}`}}>
                          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:5}}>
                            <span style={{fontSize:11,color:T.textMuted}}>Null %</span>
                            <div style={{display:"flex",alignItems:"baseline",gap:5}}>
                              <span style={{fontSize:11,fontWeight:700,color:prof.nullPct>5?T.rose:T.green}}>{prof.nullPct}%</span>
                              {prof.nullCount&&prof.nullCount!=="0"&&<span style={{fontSize:9.5,color:T.textMuted}}>{prof.nullCount} rows</span>}
                            </div>
                          </div>
                          <div style={{height:4,background:T.bgHover,borderRadius:2,overflow:"hidden"}}>
                            <div style={{width:`${Math.min(100,prof.nullPct)}%`,height:"100%",background:prof.nullPct>5?T.rose:T.green,borderRadius:2,transition:"width .3s"}}/>
                          </div>
                        </div>

                        {/* Distinct % */}
                        <div style={{padding:"9px 12px",borderBottom:(prof.dataType==="numeric"&&prof.min!=null)||prof.topValues||prof.samples?`1px solid ${T.border}`:"none"}}>
                          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:5}}>
                            <span style={{fontSize:11,color:T.textMuted}}>Distinct %</span>
                            <div style={{display:"flex",alignItems:"baseline",gap:5}}>
                              <span style={{fontSize:11,fontWeight:700,color:T.blue}}>{prof.distinctPct}%</span>
                              {prof.distinctCount&&<span style={{fontSize:9.5,color:T.textMuted}}>{prof.distinctCount} values</span>}
                            </div>
                          </div>
                          <div style={{height:4,background:T.bgHover,borderRadius:2,overflow:"hidden"}}>
                            <div style={{width:`${Math.min(100,prof.distinctPct)}%`,height:"100%",background:T.blue,borderRadius:2,transition:"width .3s"}}/>
                          </div>
                        </div>

                        {/* Min / Max / Avg — numeric only */}
                        {prof.dataType==="numeric"&&prof.min!=null&&(
                          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",borderBottom:prof.topValues?`1px solid ${T.border}`:"none"}}>
                            {[{l:"Min",v:prof.min},{l:"Max",v:prof.max},{l:"Avg",v:prof.avg||"—"}].map((s,i)=>(
                              <div key={s.l} style={{padding:"9px 10px",borderRight:i<2?`1px solid ${T.border}`:"none",textAlign:"center"}}>
                                <div style={{fontSize:9,color:T.textMuted,textTransform:"uppercase",letterSpacing:"0.06em",marginBottom:3}}>{s.l}</div>
                                <div style={{fontSize:11,fontFamily:"'Geist Mono',monospace",color:T.text,fontWeight:600}}>{s.v}</div>
                              </div>
                            ))}
                          </div>
                        )}

                        {/* Top Values — categorical and string columns with topValues */}
                        {prof.topValues&&(
                          <div style={{padding:"9px 12px",borderBottom:prof.samples?`1px solid ${T.border}`:"none"}}>
                            <div style={{fontSize:9,color:T.textMuted,textTransform:"uppercase",letterSpacing:"0.06em",marginBottom:8}}>Top Values</div>
                            {prof.topValues.map((v,i)=>{
                              const pct=parseFloat(v.match(/\((\d+)/)?.[1]||0);
                              const label=v.replace(/\s*\(.*\)/,"");
                              return(
                                <div key={i} style={{marginBottom:i<prof.topValues.length-1?7:0}}>
                                  <div style={{display:"flex",justifyContent:"space-between",marginBottom:3}}>
                                    <span style={{fontSize:10.5,color:T.textSub,fontWeight:500}}>{label}</span>
                                    <span style={{fontSize:10,color:T.textMuted}}>{pct}%</span>
                                  </div>
                                  <div style={{height:3,background:T.bgHover,borderRadius:2,overflow:"hidden"}}>
                                    <div style={{width:`${pct}%`,height:"100%",background:T.violet,borderRadius:2,transition:"width .3s"}}/>
                                  </div>
                                </div>
                              );
                            })}
                          </div>
                        )}

                        {/* Length Stats — string columns only */}
                        {prof.samples&&(
                          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",borderBottom:`1px solid ${T.border}`}}>
                            {[{l:"Min Len",v:prof.minLen},{l:"Max Len",v:prof.maxLen},{l:"Avg Len",v:prof.avgLen}].map((s,i)=>(
                              <div key={s.l} style={{padding:"9px 10px",borderRight:i<2?`1px solid ${T.border}`:"none",textAlign:"center"}}>
                                <div style={{fontSize:9,color:T.textMuted,textTransform:"uppercase",letterSpacing:"0.06em",marginBottom:3}}>{s.l}</div>
                                <div style={{fontSize:11,fontFamily:"'Geist Mono',monospace",color:T.text,fontWeight:600}}>{s.v}</div>
                              </div>
                            ))}
                          </div>
                        )}

                        {/* Sample Values — string columns only */}
                        {prof.samples&&(
                          <div style={{padding:"9px 12px"}}>
                            <div style={{fontSize:9,color:T.textMuted,textTransform:"uppercase",letterSpacing:"0.06em",marginBottom:8}}>Sample Values</div>
                            <div style={{display:"flex",flexWrap:"wrap",gap:5}}>
                              {prof.samples.map((s,i)=>(
                                <span key={i} style={{fontSize:10.5,padding:"3px 9px",borderRadius:5,background:T.bgHover,border:`1px solid ${T.border}`,color:T.textSub,fontFamily:"'Geist Mono',monospace"}}>{s}</span>
                              ))}
                            </div>
                          </div>
                        )}

                      </div>
                    </div>
                  )}

                  {/* Certificate — inherited from parent table, read-only */}
                  {(()=>{
                    const cert = data.cert||asset.cert||"Draft";
                    const cm   = CERT_META[cert]||CERT_META.Draft;
                    return (
                      <div>
                        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:6}}>
                          <div style={{fontSize:10,fontWeight:700,color:T.textMuted,textTransform:"uppercase",letterSpacing:"0.07em"}}>Certificate</div>
                          <span style={{fontSize:9.5,color:T.textMuted,fontStyle:"italic"}}>Inherited</span>
                        </div>
                        <div style={{display:"inline-flex",alignItems:"center",gap:6,padding:"4px 12px 4px 9px",borderRadius:5,background:cm.bg,borderTop:`1px solid ${cm.border}`,borderRight:`1px solid ${cm.border}`,borderBottom:`1px solid ${cm.border}`,borderLeft:`3px solid ${cm.color}`}}>
                          <span style={{fontSize:12}}>{cm.icon}</span>
                          <span style={{fontSize:12,color:cm.color,fontWeight:600}}>{cert}</span>
                        </div>
                      </div>
                    );
                  })()}

                  {/* Domain — inherited from parent table, read-only */}
                  <div>
                    <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:6}}>
                      <div style={{fontSize:10,fontWeight:700,color:T.textMuted,textTransform:"uppercase",letterSpacing:"0.07em"}}>Domain</div>
                      <span style={{fontSize:9.5,color:T.textMuted,fontStyle:"italic"}}>Inherited</span>
                    </div>
                    <div style={{display:"inline-flex",alignItems:"center",padding:"4px 12px 4px 9px",borderRadius:5,background:`${T.accent}0f`,borderTop:`1px solid ${T.accent}20`,borderRight:`1px solid ${T.accent}20`,borderBottom:`1px solid ${T.accent}20`,borderLeft:`3px solid ${T.accent}`}}>
                      <span style={{fontSize:12,color:T.accent,fontWeight:600}}>{asset.domain||data.domain||"—"}</span>
                    </div>
                  </div>

                  {/* Owners — inherited from parent table, read-only */}
                  {(()=>{
                    const colAva = name => (name||"").split(".").map(s=>s[0]?.toUpperCase()||"").join("");
                    const owners = data.owners||[];
                    return (
                      <div>
                        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:6}}>
                          <div style={{fontSize:10,fontWeight:700,color:T.textMuted,textTransform:"uppercase",letterSpacing:"0.07em"}}>Owners</div>
                          <span style={{fontSize:9.5,color:T.textMuted,fontStyle:"italic"}}>Inherited</span>
                        </div>
                        {owners.length===0
                          ? <span style={{fontSize:12,color:T.textMuted,fontStyle:"italic"}}>No owners assigned</span>
                          : <div style={{display:"flex",flexWrap:"wrap",gap:5}}>
                              {owners.map((o,i)=>(
                                <div key={i} style={{display:"inline-flex",alignItems:"center",gap:5,padding:"3px 10px 3px 6px",borderRadius:5,background:`${T.accent}0f`,borderTop:`1px solid ${T.accent}20`,borderRight:`1px solid ${T.accent}20`,borderBottom:`1px solid ${T.accent}20`,borderLeft:`3px solid ${T.accent}`}}>
                                  <div style={{width:18,height:18,borderRadius:3,background:T.accentDim,display:"flex",alignItems:"center",justifyContent:"center",fontSize:7,fontWeight:700,color:T.accent,flexShrink:0}}>{colAva(o)}</div>
                                  <span style={{fontSize:12,color:T.accent,fontWeight:500}}>{o}</span>
                                </div>
                              ))}
                            </div>}
                      </div>
                    );
                  })()}

                  {/* Stewards — inherited from parent table, read-only */}
                  {(()=>{
                    const colAva = name => (name||"").split(".").map(s=>s[0]?.toUpperCase()||"").join("");
                    const stewards = data.stewards||[];
                    return (
                      <div>
                        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:6}}>
                          <div style={{fontSize:10,fontWeight:700,color:T.textMuted,textTransform:"uppercase",letterSpacing:"0.07em"}}>Stewards</div>
                          <span style={{fontSize:9.5,color:T.textMuted,fontStyle:"italic"}}>Inherited</span>
                        </div>
                        {stewards.length===0
                          ? <span style={{fontSize:12,color:T.textMuted,fontStyle:"italic"}}>No stewards assigned</span>
                          : <div style={{display:"flex",flexWrap:"wrap",gap:5}}>
                              {stewards.map((s,i)=>(
                                <div key={i} style={{display:"inline-flex",alignItems:"center",gap:5,padding:"3px 10px 3px 6px",borderRadius:5,background:"rgba(217,119,6,.08)",borderTop:"1px solid rgba(217,119,6,.2)",borderRight:"1px solid rgba(217,119,6,.2)",borderBottom:"1px solid rgba(217,119,6,.2)",borderLeft:"3px solid #d97706"}}>
                                  <div style={{width:18,height:18,borderRadius:"50%",background:"rgba(217,119,6,.15)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:7,fontWeight:700,color:"#d97706",flexShrink:0}}>{colAva(s)}</div>
                                  <span style={{fontSize:12,color:"#d97706",fontWeight:500}}>{s}</span>
                                </div>
                              ))}
                            </div>}
                      </div>
                    );
                  })()}

                  {/* Tags — column-level, user can add */}
                  {(()=>{
                    const COL_TAG_C={PII:{bg:"rgba(225,29,72,.1)",color:"#e11d48",border:"rgba(225,29,72,.25)"},revenue:{bg:"rgba(37,99,235,.08)",color:"#2563eb",border:"rgba(37,99,235,.2)"},finance:{bg:"rgba(37,99,235,.08)",color:"#2563eb",border:"rgba(37,99,235,.2)"},KPI:{bg:"rgba(22,163,74,.08)",color:"#16a34a",border:"rgba(22,163,74,.2)"},sensitive:{bg:"rgba(124,58,237,.08)",color:"#7c3aed",border:"rgba(124,58,237,.2)"},events:{bg:"rgba(6,182,212,.08)",color:"#0891b2",border:"rgba(6,182,212,.2)"},model:{bg:"rgba(99,102,241,.08)",color:"#6366f1",border:"rgba(99,102,241,.2)"},etl:{bg:"rgba(245,158,11,.08)",color:"#d97706",border:"rgba(245,158,11,.2)"},dimension:{bg:"rgba(16,185,129,.08)",color:"#059669",border:"rgba(16,185,129,.2)"},marketing:{bg:"rgba(236,72,153,.08)",color:"#db2777",border:"rgba(236,72,153,.2)"}};
                    const ctc=tag=>COL_TAG_C[tag]||{bg:T.bgElevated,color:T.textSub,border:T.border};
                    const colTags=colTagsMap[selCol.name]||[];
                    const visibleTags=showAllColTags?colTags:colTags.slice(0,3);
                    return (
                      <div style={{position:"relative"}}>
                        <MetaLabel onEdit={()=>{setColTagModalOpen(true);setColTagModalSearch("");}}>Tags</MetaLabel>
                        <div style={{display:"flex",flexWrap:"wrap",gap:5}}>
                          {colTags.length===0&&<span style={{fontSize:12,color:T.textMuted,fontStyle:"italic"}}>No tags added</span>}
                          {visibleTags.map(t=>{const c=ctc(t);return(
                            <span key={t} style={{display:"inline-flex",alignItems:"center",fontSize:11.5,padding:"4px 10px 4px 9px",borderRadius:5,background:c.bg,borderTop:`1px solid ${c.border}`,borderRight:`1px solid ${c.border}`,borderBottom:`1px solid ${c.border}`,borderLeft:`3px solid ${c.color}`,color:c.color,fontWeight:600}}>{t}</span>
                          );})}
                          {colTags.length>3&&!showAllColTags&&<span onClick={()=>setShowAllColTags(true)} style={{display:"inline-flex",alignItems:"center",fontSize:11.5,padding:"3px 10px",borderRadius:5,background:T.bgElevated,border:`1px solid ${T.border}`,color:T.textMuted,cursor:"pointer",fontWeight:600}}>+{colTags.length-3} more</span>}
                          {colTags.length>3&&showAllColTags&&<span onClick={()=>setShowAllColTags(false)} style={{display:"inline-flex",alignItems:"center",fontSize:11.5,padding:"3px 10px",borderRadius:5,background:T.bgElevated,border:`1px solid ${T.border}`,color:T.textMuted,cursor:"pointer",fontWeight:600}}>− less</span>}
                        </div>
                        {colTagModalOpen&&(
                          <div style={{marginTop:8,background:T.bgSurface,border:`1px solid ${T.border}`,borderRadius:8,overflow:"hidden",boxShadow:"0 4px 12px rgba(0,0,0,.12)"}}>
                            <div style={{padding:"5px 7px",borderBottom:`1px solid ${T.border}`}}>
                              <input autoFocus placeholder="Search tags…" value={colTagModalSearch} onChange={e=>setColTagModalSearch(e.target.value)} style={{width:"100%",padding:"4px 7px",background:T.bgElevated,border:`1px solid ${T.border}`,borderRadius:5,color:T.text,fontSize:11.5,outline:"none",boxSizing:"border-box"}} onFocus={e=>e.target.style.borderColor=T.accent} onBlur={e=>e.target.style.borderColor=T.border}/>
                            </div>
                            <div style={{padding:"7px",display:"flex",flexWrap:"wrap",gap:4,maxHeight:140,overflowY:"auto"}}>
                              {["PII","revenue","finance","KPI","events","sensitive","dimension","model","etl","marketing"]
                                .filter(s=>!colTagModalSearch||s.toLowerCase().includes(colTagModalSearch.toLowerCase()))
                                .map(s=>{
                                  const sel=colTags.includes(s); const c=ctc(s);
                                  return <button key={s} onClick={()=>setColTagsMap(m=>({...m,[selCol.name]:sel?(m[selCol.name]||[]).filter(x=>x!==s):[...(m[selCol.name]||[]),s]}))}
                                    style={{display:"inline-flex",alignItems:"center",gap:3,padding:"3px 8px",borderRadius:4,fontSize:11,cursor:"pointer",transition:"all .1s",background:sel?c.bg:T.bgElevated,borderTop:`1px solid ${sel?c.border:T.border}`,borderRight:`1px solid ${sel?c.border:T.border}`,borderBottom:`1px solid ${sel?c.border:T.border}`,borderLeft:`3px solid ${sel?c.color:T.border}`,color:sel?c.color:T.textSub,fontWeight:sel?600:400}}>
                                    {sel&&<svg width="9" height="9" viewBox="0 0 14 14" fill="none"><path d="M2.5 7.5l3 3 6-6" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round"/></svg>}
                                    {s}
                                  </button>;
                                })}
                            </div>
                            <div style={{padding:"5px 7px",borderTop:`1px solid ${T.border}`,display:"flex",justifyContent:"flex-end"}}>
                              <button onClick={()=>setColTagModalOpen(false)} style={{padding:"3px 10px",borderRadius:4,background:T.accent,border:"none",color:"#fff",fontSize:11,fontWeight:600,cursor:"pointer"}}>Done</button>
                            </div>
                          </div>
                        )}
                      </div>
                    );
                  })()}

                  {/* Business Glossary — column-level, user can link terms */}
                  {(()=>{
                    const colGlTerms = colGlTermsMap[selCol.name]||[];
                    return (
                      <div>
                        <MetaLabel onEdit={()=>{setColGlOpen(p=>!p);setColGlSearch("");}}>Business Glossary</MetaLabel>
                        {colGlTerms.length===0
                          ? <span style={{fontSize:12,color:T.textMuted,fontStyle:"italic"}}>No terms linked</span>
                          : <div style={{display:"flex",flexWrap:"wrap",gap:5}}>
                              {colGlTerms.map((t,i)=>(
                                <span key={i} style={{display:"inline-flex",alignItems:"center",gap:4,fontSize:11.5,padding:"4px 10px 4px 9px",borderRadius:5,background:"rgba(139,92,246,.08)",borderTop:"1px solid rgba(139,92,246,.2)",borderRight:"1px solid rgba(139,92,246,.2)",borderBottom:"1px solid rgba(139,92,246,.2)",borderLeft:"3px solid #8b5cf6",color:"#8b5cf6",fontWeight:600}}>
                                  {t.length>12?t.slice(0,12)+"…":t}
                                  <button onClick={()=>setColGlTermsMap(m=>({...m,[selCol.name]:(m[selCol.name]||[]).filter((_,j)=>j!==i)}))} style={{background:"none",border:"none",cursor:"pointer",color:"inherit",padding:0,lineHeight:1,display:"flex",opacity:.6}} onMouseEnter={e=>e.currentTarget.style.opacity="1"} onMouseLeave={e=>e.currentTarget.style.opacity=".6"}>{Ic.x(7)}</button>
                                </span>
                              ))}
                            </div>}
                        {colGlOpen&&(
                          <div style={{marginTop:8,background:T.bgSurface,border:"1px solid rgba(139,92,246,.3)",borderRadius:8,overflow:"hidden",boxShadow:"0 4px 12px rgba(0,0,0,.12)"}}>
                            <div style={{padding:"5px 7px",borderBottom:`1px solid ${T.border}`}}>
                              <input autoFocus placeholder="Search glossary terms…" value={colGlSearch} onChange={e=>setColGlSearch(e.target.value)} style={{width:"100%",padding:"4px 7px",background:T.bgElevated,border:`1px solid ${T.border}`,borderRadius:5,color:T.text,fontSize:11.5,outline:"none",boxSizing:"border-box"}} onFocus={e=>e.target.style.borderColor="#8b5cf6"} onBlur={e=>e.target.style.borderColor=T.border}/>
                            </div>
                            <div style={{maxHeight:180,overflowY:"auto"}}>
                              {GLOSSARY_TERMS.filter(t=>!colGlSearch||t.term.toLowerCase().includes(colGlSearch.toLowerCase())||t.abbr?.toLowerCase().includes(colGlSearch.toLowerCase())).map(t=>{
                                const sel=colGlTerms.includes(t.term);
                                return(
                                  <button key={t.id} onClick={()=>setColGlTermsMap(m=>({...m,[selCol.name]:sel?(m[selCol.name]||[]).filter(x=>x!==t.term):[...(m[selCol.name]||[]),t.term]}))}
                                    style={{width:"100%",display:"flex",alignItems:"center",gap:8,padding:"7px 10px",background:sel?"rgba(139,92,246,.06)":"transparent",border:"none",cursor:"pointer",textAlign:"left",transition:"background .1s"}}
                                    onMouseEnter={e=>{if(!sel)e.currentTarget.style.background=T.bgHover;}} onMouseLeave={e=>{if(!sel)e.currentTarget.style.background="transparent";}}>
                                    <div style={{flex:1,minWidth:0}}>
                                      <div style={{fontSize:11.5,fontWeight:600,color:sel?"#8b5cf6":T.text}}>{t.term}</div>
                                      <div style={{fontSize:10,color:T.textMuted,display:"flex",gap:5,marginTop:1}}>
                                        {t.abbr&&t.abbr!=="—"&&<span style={{fontFamily:"'Geist Mono',monospace"}}>{t.abbr}</span>}
                                        <span>{t.domain}</span>
                                      </div>
                                    </div>
                                    {sel&&<svg width="11" height="11" viewBox="0 0 14 14" fill="none"><path d="M2.5 7.5l3 3 6-6" stroke="#8b5cf6" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round"/></svg>}
                                  </button>
                                );
                              })}
                              {GLOSSARY_TERMS.filter(t=>!colGlSearch||t.term.toLowerCase().includes(colGlSearch.toLowerCase())).length===0&&<div style={{padding:"12px",fontSize:11.5,color:T.textMuted,textAlign:"center"}}>No terms match</div>}
                            </div>
                            <div style={{padding:"5px 7px",borderTop:`1px solid ${T.border}`,display:"flex",justifyContent:"flex-end"}}>
                              <button onClick={()=>setColGlOpen(false)} style={{padding:"3px 10px",borderRadius:4,background:"#8b5cf6",border:"none",color:"#fff",fontSize:11,fontWeight:600,cursor:"pointer"}}>Done</button>
                            </div>
                          </div>
                        )}
                      </div>
                    );
                  })()}

                </div>
              )}

              {/* ── Quality tab: full table-like experience ── */}
              {colPanelTab==="quality"&&(
                <div style={{display:"flex",flexDirection:"column",height:"100%"}}>
                  {/* Score strip */}
                  {colTests.length>0&&(
                    <div style={{display:"flex",gap:0,borderBottom:`1px solid ${T.border}`,flexShrink:0}}>
                      {[{l:"Passing",v:tcSuccess,c:T.green},{l:"Failing",v:tcFailed,c:T.rose},{l:"Aborted",v:tcAborted,c:T.amber}].map((s,i)=>(
                        <div key={s.l} style={{flex:1,padding:"10px 0",textAlign:"center",borderRight:i<2?`1px solid ${T.border}`:"none"}}>
                          <div style={{fontSize:18,fontWeight:700,color:s.c}}>{s.v}</div>
                          <div style={{fontSize:10,color:T.textMuted}}>{s.l}</div>
                        </div>
                      ))}
                    </div>
                  )}
                  {/* Action bar */}
                  <div style={{padding:"8px 12px",borderBottom:`1px solid ${T.border}`,display:"flex",gap:6,alignItems:"center",flexShrink:0}}>
                    <span style={{fontSize:11,color:T.textMuted,flex:1}}>Tests on <code style={{fontFamily:"'Geist Mono',monospace",color:T.textSub}}>{selCol.name}</code></span>
                    {colTests.length>0&&(
                      <button style={{display:"inline-flex",alignItems:"center",gap:4,padding:"4px 10px",borderRadius:6,background:T.bgElevated,border:`1px solid ${T.border}`,color:T.textSub,fontSize:11,fontWeight:500,cursor:"pointer"}}>
                        <svg width="8" height="8" viewBox="0 0 12 12" fill="none"><path d="M3 2l7 4-7 4V2z" fill="currentColor"/></svg>Run All
                      </button>
                    )}
                    <button onClick={()=>setColSelectTestOpen(true)}
                      style={{display:"inline-flex",alignItems:"center",gap:4,padding:"4px 10px",borderRadius:6,background:T.accent,border:"none",color:"#fff",fontSize:11,fontWeight:600,cursor:"pointer"}}>
                      Select Test
                    </button>
                  </div>
                  {/* Test list */}
                  <div style={{overflowY:"auto",flex:1,padding:10,display:"flex",flexDirection:"column",gap:8}}>
                    {colTests.length===0?(
                      <div style={{textAlign:"center",padding:"36px 16px"}}>
                        <div style={{fontSize:26,marginBottom:8}}>🧪</div>
                        <div style={{fontSize:13,fontWeight:600,color:T.textSub,marginBottom:4}}>No tests yet</div>
                        <div style={{fontSize:11.5,color:T.textMuted,lineHeight:1.6}}>Click <b style={{color:T.accent}}>Select Test</b> to add test cases for this column.</div>
                      </div>
                    ):colTests.map((tc)=>(
                      <div key={tc.id} style={{background:T.bgElevated,borderRadius:8,border:`1.5px solid ${SC[tc.status]}2a`,padding:"10px 12px"}}>
                        <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",gap:6,marginBottom:5}}>
                          <span style={{fontSize:12,fontWeight:600,color:T.text,lineHeight:1.4,flex:1}}>{tc.name}</span>
                          <span style={{display:"inline-flex",alignItems:"center",gap:3,fontSize:10,fontWeight:700,color:SC[tc.status],background:`${SC[tc.status]}18`,padding:"2px 6px",borderRadius:4,border:`1px solid ${SC[tc.status]}33`,flexShrink:0}}>
                            {SI[tc.status]} {tc.status}
                          </span>
                        </div>
                        <div style={{display:"flex",gap:5,marginBottom:8,flexWrap:"wrap"}}>
                          <DimChip dim={tc.dim}/>
                          <span style={{fontSize:10,color:T.textMuted,background:T.bgSurface,padding:"1px 6px",borderRadius:3,border:`1px solid ${T.border}`}}>{tc.defName}</span>
                        </div>
                        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:tc.history?6:0}}>
                          <div>
                            <div style={{fontSize:9,color:T.textMuted,textTransform:"uppercase",letterSpacing:"0.06em",marginBottom:2}}>Last Value</div>
                            <div style={{fontSize:11,fontFamily:"'Geist Mono',monospace",color:T.textSub}}>{tc.lastVal}</div>
                          </div>
                          <div>
                            <div style={{fontSize:9,color:T.textMuted,textTransform:"uppercase",letterSpacing:"0.06em",marginBottom:2}}>Expected</div>
                            <div style={{fontSize:11,fontFamily:"'Geist Mono',monospace",color:T.textSub,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{tc.expected}</div>
                          </div>
                        </div>
                        {tc.history&&tc.history.length>0&&(
                          <div style={{display:"flex",gap:1.5,alignItems:"flex-end",height:16,marginTop:4}}>
                            {tc.history.slice(-15).map((v,idx)=>(
                              <div key={idx} style={{flex:1,borderRadius:"2px 2px 0 0",background:v===1?T.green:v===0?"#f87171":"#fbbf24",height:v===1?"100%":"55%",minHeight:2,opacity:.8}}/>
                            ))}
                          </div>
                        )}
                        <div style={{display:"flex",justifyContent:"flex-end",marginTop:4}}>
                          <span style={{fontSize:10,color:T.textMuted}}>Last run: {tc.lastRun}</span>
                        </div>
                        {tc.failedReason&&<div style={{marginTop:6,fontSize:10.5,color:T.rose,background:"rgba(248,113,113,.08)",padding:"5px 9px",borderRadius:5,border:"1px solid rgba(248,113,113,.2)",lineHeight:1.5}}>{tc.failedReason}</div>}
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>
        );
      })()}

      {/* ── Column Select Test picker ── */}
      {colSelectTestOpen&&selCol&&createPortal(
        <div style={{position:"fixed",inset:0,zIndex:900,background:"rgba(0,0,0,.45)"}} onClick={()=>{setColSelectTestOpen(false);setColSelectTestIds(new Set());}}>
          <div onClick={e=>e.stopPropagation()} className="slideIn" style={{position:"absolute",right:0,top:0,width:440,height:"100%",background:T.bgSurface,borderLeft:`1px solid ${T.border}`,boxShadow:"-8px 0 32px rgba(0,0,0,.28)",display:"flex",flexDirection:"column",overflow:"hidden"}}>
            {/* Header */}
            <div style={{padding:"16px 20px",borderBottom:`1px solid ${T.border}`,display:"flex",alignItems:"center",justifyContent:"space-between",flexShrink:0,background:T.bgElevated}}>
              <div>
                <div style={{fontSize:14,fontWeight:700,color:T.text}}>Select Test Cases</div>
                <div style={{fontSize:11,color:T.textMuted,marginTop:2}}>Column: <span style={{color:T.textSub,fontWeight:500,fontFamily:"'Geist Mono',monospace"}}>{selCol.name}</span></div>
              </div>
              <button onClick={()=>{setColSelectTestOpen(false);setColSelectTestIds(new Set());}} style={{width:30,height:30,borderRadius:8,background:T.bgHover,border:`1px solid ${T.border}`,color:T.textMuted,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}>{Ic.x(11)}</button>
            </div>
            {/* List */}
            <div style={{flex:1,overflowY:"auto",padding:16,display:"flex",flexDirection:"column",gap:8}}>
              {(()=>{
                const filtered=DQ_TEST_CASES.filter(t=>t.col&&selCol.name&&t.col.toLowerCase()===selCol.name.toLowerCase());
                if(filtered.length===0) return (
                  <div style={{textAlign:"center",padding:"40px 20px"}}>
                    <div style={{fontSize:28,marginBottom:10}}>🔍</div>
                    <div style={{fontSize:13,fontWeight:600,color:T.textSub,marginBottom:6}}>No test cases found</div>
                    <div style={{fontSize:11.5,color:T.textMuted,lineHeight:1.6}}>No test cases found for this column.<br/>Create them in the DQ section first.</div>
                  </div>
                );
                return filtered.map(t=>{
                  const isSel=colSelectTestIds.has(t.id);
                  const SC2={Success:"#16a34a",Failed:"#e11d48",Aborted:"#d97706"};
                  const dimC={Accuracy:"#8b5cf6",Completeness:"#3b82f6",Consistency:"#06b6d4",Timeliness:"#f59e0b",Validity:"#10b981",Uniqueness:"#ec4899"};
                  return (
                    <div key={t.id} onClick={()=>setColSelectTestIds(p=>{const n=new Set(p);isSel?n.delete(t.id):n.add(t.id);return n;})}
                      style={{background:isSel?T.accentDim:T.bgElevated,border:`1.5px solid ${isSel?T.accent:T.border}`,borderRadius:9,padding:"10px 12px",cursor:"pointer",transition:"all .15s"}}>
                      <div style={{display:"flex",alignItems:"flex-start",gap:10}}>
                        <input type="checkbox" checked={isSel} onChange={()=>{}} style={{marginTop:2,accentColor:T.accent,cursor:"pointer"}}/>
                        <div style={{flex:1,minWidth:0}}>
                          <div style={{fontSize:12,fontWeight:600,color:T.text,marginBottom:4}}>{t.name}</div>
                          <div style={{display:"flex",gap:5,flexWrap:"wrap"}}>
                            <span style={{fontSize:10,fontWeight:700,color:SC2[t.status]||T.textMuted,background:`${SC2[t.status]||T.bgSurface}18`,padding:"1px 6px",borderRadius:4,border:`1px solid ${SC2[t.status]||T.border}33`}}>{t.status}</span>
                            <span style={{fontSize:10,padding:"1px 6px",borderRadius:4,background:`${dimC[t.dim]||T.textMuted}12`,color:dimC[t.dim]||T.textMuted,fontWeight:600,border:`1px solid ${dimC[t.dim]||T.textMuted}22`}}>{t.dim}</span>
                            <span style={{fontSize:10,color:T.textMuted,background:T.bgSurface,padding:"1px 6px",borderRadius:4,border:`1px solid ${T.border}`}}>{t.defName}</span>
                          </div>
                          <div style={{fontSize:10,color:T.textMuted,marginTop:4}}>Last run: {t.lastRun}</div>
                        </div>
                      </div>
                    </div>
                  );
                });
              })()}
            </div>
            {/* Footer */}
            <div style={{padding:"14px 20px",borderTop:`1px solid ${T.border}`,display:"flex",gap:8,flexShrink:0,background:T.bgSurface}}>
              <button disabled={colSelectTestIds.size===0}
                onClick={()=>{
                  const toAdd=DQ_TEST_CASES.filter(t=>colSelectTestIds.has(t.id));
                  setColTestsMap(p=>{
                    const cur=p[selCol.name]!==undefined?p[selCol.name]:DQ_TEST_CASES.filter(tc=>tc.col&&selCol.name&&tc.col.toLowerCase()===selCol.name.toLowerCase());
                    const existIds=new Set(cur.map(x=>x.id));
                    return {...p,[selCol.name]:[...cur,...toAdd.filter(t=>!existIds.has(t.id))]};
                  });
                  setColSelectTestOpen(false);setColSelectTestIds(new Set());
                }}
                style={{flex:1,padding:"9px",borderRadius:9,background:colSelectTestIds.size>0?T.accent:"rgba(100,100,120,.3)",border:"none",color:"#fff",fontSize:13,fontWeight:700,cursor:colSelectTestIds.size>0?"pointer":"default",transition:"background .15s"}}>
                Add Selected ({colSelectTestIds.size})
              </button>
              <button onClick={()=>{setColSelectTestOpen(false);setColSelectTestIds(new Set());}} style={{padding:"9px 18px",borderRadius:9,background:"transparent",border:`1px solid ${T.border}`,color:T.textSub,fontSize:12.5,cursor:"pointer"}}>Cancel</button>
            </div>
          </div>
        </div>,
        document.body
      )}

      {/* ── Right metadata sidebar — Overview tab only ── */}
      {tab==="overview"&&<div style={{width:260,flexShrink:0,borderLeft:`1px solid ${T.border}`,background:T.bgSurface,overflowY:"auto"}}>

        {/* DETAILS */}
        <div style={{padding:"16px",borderBottom:`1px solid ${T.border}`}}>
          <MetaLabel>Details</MetaLabel>
          {[
            {l:"Quality",   v:<QScore score={data.quality}/>},
            {l:"Freshness", v:<span style={{fontSize:12,color:T.textSub}}>{data.slaFreshness}</span>},
            {l:"Updated",   v:<span style={{fontSize:12,color:T.textMuted}}>{data.updated}</span>},
          ].map(m=>(
            <div key={m.l} style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:8,fontSize:12}}>
              <span style={{color:T.textMuted}}>{m.l}</span>
              {m.v}
            </div>
          ))}
        </div>

        {/* CERTIFICATE */}
        <div style={{padding:"16px",borderBottom:`1px solid ${T.border}`}}>
          <MetaLabel onEdit={()=>setEditModal("cert")}>Certificate</MetaLabel>
          <div style={{display:"inline-flex",alignItems:"center",gap:6,padding:"4px 12px 4px 9px",borderRadius:5,background:cm.bg,borderTop:`1px solid ${cm.border}`,borderRight:`1px solid ${cm.border}`,borderBottom:`1px solid ${cm.border}`,borderLeft:`3px solid ${cm.color}`}}>
            <span style={{fontSize:13}}>{cm.icon}</span>
            <span style={{fontSize:12,color:cm.color,fontWeight:600}}>{data.cert||"Draft"}</span>
          </div>
        </div>

        {/* DOMAIN */}
        <div style={{padding:"16px",borderBottom:`1px solid ${T.border}`}}>
          <MetaLabel onEdit={()=>{setDomainOpen(p=>!p);setDomainSearch("");}}>Domain</MetaLabel>
          {data.domain?(
            <div style={{display:"inline-flex",alignItems:"center",padding:"4px 12px 4px 9px",borderRadius:5,background:`${T.accent}0f`,borderTop:`1px solid ${T.accent}20`,borderRight:`1px solid ${T.accent}20`,borderBottom:`1px solid ${T.accent}20`,borderLeft:`3px solid ${T.accent}`}}>
              <span style={{fontSize:12,color:T.accent,fontWeight:600}}>{data.domain}</span>
            </div>
          ):(
            <span style={{fontSize:12,color:T.textMuted,fontStyle:"italic"}}>No domain set</span>
          )}
          {domainOpen&&(
            <div style={{marginTop:8,background:T.bgSurface,border:`1px solid ${T.accent}40`,borderRadius:8,overflow:"hidden",boxShadow:"0 4px 12px rgba(0,0,0,.12)"}}>
              <div style={{padding:"6px 8px",borderBottom:`1px solid ${T.border}`}}>
                <input autoFocus placeholder="Search domains…" value={domainSearch} onChange={e=>setDomainSearch(e.target.value)}
                  style={{width:"100%",padding:"5px 8px",background:T.bgElevated,border:`1px solid ${T.border}`,borderRadius:6,color:T.text,fontSize:12,outline:"none",boxSizing:"border-box"}}
                  onFocus={e=>e.target.style.borderColor=T.accent} onBlur={e=>e.target.style.borderColor=T.border}/>
              </div>
              <div style={{maxHeight:180,overflowY:"auto"}}>
                {DOMAINS_LIST.filter(d=>!domainSearch||d.toLowerCase().includes(domainSearch.toLowerCase())).map(d=>(
                  <button key={d} onClick={()=>{setData(dd=>({...dd,domain:d}));setDomainOpen(false);onToast(`Domain set to ${d}`,"success");}}
                    style={{width:"100%",display:"flex",alignItems:"center",justifyContent:"space-between",padding:"8px 12px",background:data.domain===d?T.accentDim:"transparent",border:"none",cursor:"pointer",fontSize:12.5,color:data.domain===d?T.accent:T.textSub,fontWeight:data.domain===d?600:400,transition:"background .1s"}}
                    onMouseEnter={e=>{if(data.domain!==d)e.currentTarget.style.background=T.bgHover;}} onMouseLeave={e=>{if(data.domain!==d)e.currentTarget.style.background="transparent";}}>
                    {d}
                    {data.domain===d&&<svg width="12" height="12" viewBox="0 0 14 14" fill="none"><path d="M2.5 7.5l3 3 6-6" stroke={T.accent} strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round"/></svg>}
                  </button>
                ))}
              </div>
            </div>
          )}
        </div>

        {/* OWNERS */}
        <div style={{padding:"16px",borderBottom:`1px solid ${T.border}`}}>
          <MetaLabel onEdit={()=>{setOwnersOpen(p=>!p);setOwnersSearch("");}}>Owners</MetaLabel>
          <div style={{display:"flex",flexWrap:"wrap",gap:5}}>
            {owners.length===0&&<span style={{fontSize:12,color:T.textMuted,fontStyle:"italic"}}>No owners assigned</span>}
            {(showAllOwners?owners:owners.slice(0,3)).map((o,i)=>(
              <div key={i} style={{display:"inline-flex",alignItems:"center",gap:5,padding:"3px 10px 3px 6px",borderRadius:5,background:`${T.accent}0f`,borderTop:`1px solid ${T.accent}20`,borderRight:`1px solid ${T.accent}20`,borderBottom:`1px solid ${T.accent}20`,borderLeft:`3px solid ${T.accent}`}}>
                <div style={{width:18,height:18,borderRadius:3,background:T.accentDim,display:"flex",alignItems:"center",justifyContent:"center",fontSize:7,fontWeight:700,color:T.accent,flexShrink:0}}>{ava(o)}</div>
                <span style={{fontSize:12,color:T.accent,fontWeight:500}}>{o}</span>
              </div>
            ))}
            {owners.length>3&&!showAllOwners&&<span onClick={()=>setShowAllOwners(true)} style={{display:"inline-flex",alignItems:"center",fontSize:11.5,padding:"3px 10px",borderRadius:5,background:T.bgElevated,border:`1px solid ${T.border}`,color:T.textMuted,cursor:"pointer",fontWeight:600}}>+{owners.length-3} more</span>}
            {owners.length>3&&showAllOwners&&<span onClick={()=>setShowAllOwners(false)} style={{display:"inline-flex",alignItems:"center",fontSize:11.5,padding:"3px 10px",borderRadius:5,background:T.bgElevated,border:`1px solid ${T.border}`,color:T.textMuted,cursor:"pointer",fontWeight:600}}>− less</span>}
          </div>
          {ownersOpen&&(
            <div style={{marginTop:8,background:T.bgSurface,border:`1px solid ${T.accent}40`,borderRadius:8,overflow:"hidden",boxShadow:"0 4px 12px rgba(0,0,0,.12)"}}>
              <div style={{padding:"6px 8px",borderBottom:`1px solid ${T.border}`}}>
                <input autoFocus placeholder="Search users…" value={ownersSearch} onChange={e=>setOwnersSearch(e.target.value)}
                  style={{width:"100%",padding:"5px 8px",background:T.bgElevated,border:`1px solid ${T.border}`,borderRadius:6,color:T.text,fontSize:12,outline:"none",boxSizing:"border-box"}}
                  onFocus={e=>e.target.style.borderColor=T.accent} onBlur={e=>e.target.style.borderColor=T.border}/>
              </div>
              <div style={{maxHeight:180,overflowY:"auto"}}>
                {USERS_LIST.filter(u=>!ownersSearch||u.toLowerCase().includes(ownersSearch.toLowerCase())).map(u=>{
                  const sel=owners.includes(u);
                  return <button key={u} onClick={()=>{if(sel){const no=owners.filter(x=>x!==u);setData(d=>({...d,owners:no,owner:no[0]||""}));}else setData(d=>({...d,owners:[...owners,u],owner:owners[0]||u}));}}
                    style={{width:"100%",display:"flex",alignItems:"center",gap:8,padding:"7px 12px",background:sel?T.accentDim:"transparent",border:"none",cursor:"pointer",textAlign:"left",transition:"background .1s"}}
                    onMouseEnter={e=>{if(!sel)e.currentTarget.style.background=T.bgHover;}} onMouseLeave={e=>{if(!sel)e.currentTarget.style.background="transparent";}}>
                    <div style={{width:22,height:22,borderRadius:5,background:T.accentDim,border:`1px solid ${T.accent}33`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:8,fontWeight:700,color:T.accent,flexShrink:0}}>{ava(u)}</div>
                    <span style={{flex:1,fontSize:12,color:sel?T.accent:T.text,fontWeight:sel?600:400}}>{u}</span>
                    {sel&&<svg width="12" height="12" viewBox="0 0 14 14" fill="none"><path d="M2.5 7.5l3 3 6-6" stroke={T.accent} strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round"/></svg>}
                  </button>;
                })}
              </div>
              <div style={{padding:"6px 8px",borderTop:`1px solid ${T.border}`,display:"flex",justifyContent:"flex-end"}}>
                <button onClick={()=>setOwnersOpen(false)} style={{padding:"4px 12px",borderRadius:5,background:T.accent,border:"none",color:"#fff",fontSize:11.5,fontWeight:600,cursor:"pointer"}}>Done</button>
              </div>
            </div>
          )}
        </div>

        {/* STEWARDS */}
        <div style={{padding:"16px",borderBottom:`1px solid ${T.border}`}}>
          <MetaLabel onEdit={()=>{setStewardsOpen(p=>!p);setStewardsSearch("");}}>Stewards</MetaLabel>
          <div style={{display:"flex",flexWrap:"wrap",gap:5}}>
            {stewards.length===0&&<span style={{fontSize:12,color:T.textMuted,fontStyle:"italic"}}>No stewards assigned</span>}
            {(showAllStewards?stewards:stewards.slice(0,3)).map((s,i)=>(
              <div key={i} style={{display:"inline-flex",alignItems:"center",gap:5,padding:"3px 10px 3px 6px",borderRadius:5,background:"rgba(217,119,6,.08)",borderTop:"1px solid rgba(217,119,6,.2)",borderRight:"1px solid rgba(217,119,6,.2)",borderBottom:"1px solid rgba(217,119,6,.2)",borderLeft:"3px solid #d97706"}}>
                <div style={{width:18,height:18,borderRadius:"50%",background:"rgba(217,119,6,.15)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:7,fontWeight:700,color:"#d97706",flexShrink:0}}>{ava(s)}</div>
                <span style={{fontSize:12,color:"#d97706",fontWeight:500}}>{s}</span>
              </div>
            ))}
            {stewards.length>3&&!showAllStewards&&<span onClick={()=>setShowAllStewards(true)} style={{display:"inline-flex",alignItems:"center",fontSize:11.5,padding:"3px 10px",borderRadius:5,background:T.bgElevated,border:`1px solid ${T.border}`,color:T.textMuted,cursor:"pointer",fontWeight:600}}>+{stewards.length-3} more</span>}
            {stewards.length>3&&showAllStewards&&<span onClick={()=>setShowAllStewards(false)} style={{display:"inline-flex",alignItems:"center",fontSize:11.5,padding:"3px 10px",borderRadius:5,background:T.bgElevated,border:`1px solid ${T.border}`,color:T.textMuted,cursor:"pointer",fontWeight:600}}>− less</span>}
          </div>
          {stewardsOpen&&(
            <div style={{marginTop:8,background:T.bgSurface,border:"1px solid rgba(217,119,6,.3)",borderRadius:8,overflow:"hidden",boxShadow:"0 4px 12px rgba(0,0,0,.12)"}}>
              <div style={{padding:"6px 8px",borderBottom:`1px solid ${T.border}`}}>
                <input autoFocus placeholder="Search users…" value={stewardsSearch} onChange={e=>setStewardsSearch(e.target.value)}
                  style={{width:"100%",padding:"5px 8px",background:T.bgElevated,border:`1px solid ${T.border}`,borderRadius:6,color:T.text,fontSize:12,outline:"none",boxSizing:"border-box"}}
                  onFocus={e=>e.target.style.borderColor="#d97706"} onBlur={e=>e.target.style.borderColor=T.border}/>
              </div>
              <div style={{maxHeight:180,overflowY:"auto"}}>
                {USERS_LIST.filter(u=>!stewardsSearch||u.toLowerCase().includes(stewardsSearch.toLowerCase())).map(u=>{
                  const sel=stewards.includes(u);
                  return <button key={u} onClick={()=>{if(sel){const ns=stewards.filter(x=>x!==u);setData(d=>({...d,stewards:ns,steward:ns[0]||""}));}else setData(d=>({...d,stewards:[...stewards,u],steward:stewards[0]||u}));}}
                    style={{width:"100%",display:"flex",alignItems:"center",gap:8,padding:"7px 12px",background:sel?"rgba(217,119,6,.08)":"transparent",border:"none",cursor:"pointer",textAlign:"left",transition:"background .1s"}}
                    onMouseEnter={e=>{if(!sel)e.currentTarget.style.background=T.bgHover;}} onMouseLeave={e=>{if(!sel)e.currentTarget.style.background="transparent";}}>
                    <div style={{width:22,height:22,borderRadius:"50%",background:"rgba(217,119,6,.15)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:8,fontWeight:700,color:"#d97706",flexShrink:0}}>{ava(u)}</div>
                    <span style={{flex:1,fontSize:12,color:sel?"#d97706":T.text,fontWeight:sel?600:400}}>{u}</span>
                    {sel&&<svg width="12" height="12" viewBox="0 0 14 14" fill="none"><path d="M2.5 7.5l3 3 6-6" stroke="#d97706" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round"/></svg>}
                  </button>;
                })}
              </div>
              <div style={{padding:"6px 8px",borderTop:`1px solid ${T.border}`,display:"flex",justifyContent:"flex-end"}}>
                <button onClick={()=>setStewardsOpen(false)} style={{padding:"4px 12px",borderRadius:5,background:"#d97706",border:"none",color:"#fff",fontSize:11.5,fontWeight:600,cursor:"pointer"}}>Done</button>
              </div>
            </div>
          )}
        </div>

        {/* TAGS */}
        <div style={{padding:"16px",borderBottom:`1px solid ${T.border}`}}>
          <MetaLabel onEdit={()=>{setTagsOpen(p=>!p);setTagsSearch("");}}>Tags</MetaLabel>
          <div style={{display:"flex",flexWrap:"wrap",gap:5}}>
            {(data.tags||[]).length===0&&<span style={{fontSize:12,color:T.textMuted,fontStyle:"italic"}}>No tags added</span>}
            {(showAllTags?data.tags||[]:(data.tags||[]).slice(0,3)).map(t=>{const c=tcFull(t);return(
              <span key={t} style={{display:"inline-flex",alignItems:"center",fontSize:11.5,padding:"4px 10px 4px 9px",borderRadius:5,background:c.bg,borderTop:`1px solid ${c.border}`,borderRight:`1px solid ${c.border}`,borderBottom:`1px solid ${c.border}`,borderLeft:`3px solid ${c.color}`,color:c.color,fontWeight:600}}>{t}</span>
            );})}
            {(data.tags||[]).length>3&&!showAllTags&&<span onClick={()=>setShowAllTags(true)} style={{display:"inline-flex",alignItems:"center",fontSize:11.5,padding:"3px 10px",borderRadius:5,background:T.bgElevated,border:`1px solid ${T.border}`,color:T.textMuted,cursor:"pointer",fontWeight:600}}>+{(data.tags||[]).length-3} more</span>}
            {(data.tags||[]).length>3&&showAllTags&&<span onClick={()=>setShowAllTags(false)} style={{display:"inline-flex",alignItems:"center",fontSize:11.5,padding:"3px 10px",borderRadius:5,background:T.bgElevated,border:`1px solid ${T.border}`,color:T.textMuted,cursor:"pointer",fontWeight:600}}>− less</span>}
          </div>
          {tagsOpen&&(
            <div style={{marginTop:8,background:T.bgSurface,border:`1px solid ${T.border}`,borderRadius:8,overflow:"hidden",boxShadow:"0 4px 12px rgba(0,0,0,.12)"}}>
              <div style={{padding:"6px 8px",borderBottom:`1px solid ${T.border}`}}>
                <input autoFocus placeholder="Search tags…" value={tagsSearch} onChange={e=>setTagsSearch(e.target.value)}
                  style={{width:"100%",padding:"5px 8px",background:T.bgElevated,border:`1px solid ${T.border}`,borderRadius:6,color:T.text,fontSize:12,outline:"none",boxSizing:"border-box"}}
                  onFocus={e=>e.target.style.borderColor=T.accent} onBlur={e=>e.target.style.borderColor=T.border}/>
              </div>
              <div style={{padding:"8px",display:"flex",flexWrap:"wrap",gap:5,maxHeight:160,overflowY:"auto"}}>
                {["PII","revenue","finance","KPI","events","sensitive","dimension","model","etl","marketing"]
                  .filter(s=>!tagsSearch||s.toLowerCase().includes(tagsSearch.toLowerCase()))
                  .map(s=>{
                    const sel=(data.tags||[]).includes(s); const c=tcFull(s);
                    return <button key={s} onClick={()=>setData(d=>({...d,tags:sel?d.tags.filter(x=>x!==s):[...(d.tags||[]),s]}))}
                      style={{display:"inline-flex",alignItems:"center",gap:4,padding:"4px 10px",borderRadius:5,fontSize:11.5,cursor:"pointer",transition:"all .1s",background:sel?c.bg:T.bgElevated,borderTop:`1px solid ${sel?c.border:T.border}`,borderRight:`1px solid ${sel?c.border:T.border}`,borderBottom:`1px solid ${sel?c.border:T.border}`,borderLeft:`3px solid ${sel?c.color:T.border}`,color:sel?c.color:T.textSub,fontWeight:sel?600:400}}>
                      {sel&&<svg width="10" height="10" viewBox="0 0 14 14" fill="none"><path d="M2.5 7.5l3 3 6-6" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round"/></svg>}
                      {s}
                    </button>;
                  })}
              </div>
              <div style={{padding:"6px 8px",borderTop:`1px solid ${T.border}`,display:"flex",justifyContent:"flex-end"}}>
                <button onClick={()=>setTagsOpen(false)} style={{padding:"4px 12px",borderRadius:5,background:T.accent,border:"none",color:"#fff",fontSize:11.5,fontWeight:600,cursor:"pointer"}}>Done</button>
              </div>
            </div>
          )}
        </div>

        {/* BUSINESS GLOSSARY */}
        <div style={{padding:"16px",borderBottom:`1px solid ${T.border}`}}>
          <MetaLabel onEdit={()=>{setAssetGlOpen(p=>!p);setAssetGlSearch("");}}>Business Glossary</MetaLabel>
          <div style={{display:"flex",flexWrap:"wrap",gap:5}}>
            {assetGlTerms.length===0&&<span style={{fontSize:12,color:T.textMuted,fontStyle:"italic"}}>No terms linked</span>}
            {assetGlTerms.slice(0,3).map((t,i)=><span key={i} title={t} style={{display:"inline-flex",alignItems:"center",gap:4,fontSize:11.5,padding:"4px 10px 4px 9px",borderRadius:5,background:"rgba(139,92,246,.08)",borderTop:"1px solid rgba(139,92,246,.2)",borderRight:"1px solid rgba(139,92,246,.2)",borderBottom:"1px solid rgba(139,92,246,.2)",borderLeft:"3px solid #8b5cf6",color:"#8b5cf6",fontWeight:600}}>{t.length>10?t.slice(0,10)+"…":t}<button onClick={()=>setAssetGlTerms(prev=>prev.filter((_,j)=>j!==i))} style={{background:"none",border:"none",cursor:"pointer",color:"inherit",padding:0,lineHeight:1,display:"flex",opacity:.6}} onMouseEnter={e=>e.currentTarget.style.opacity="1"} onMouseLeave={e=>e.currentTarget.style.opacity=".6"}>{Ic.x(7)}</button></span>)}
            {assetGlTerms.length>3&&<span title={assetGlTerms.slice(3).join(", ")} style={{display:"inline-flex",alignItems:"center",fontSize:11.5,padding:"3px 10px",borderRadius:5,background:T.bgElevated,border:`1px solid ${T.border}`,color:T.textMuted,cursor:"default",fontWeight:600}}>+{assetGlTerms.length-3}</span>}
          </div>
          {assetGlOpen&&(
            <div style={{marginTop:8,background:T.bgSurface,border:"1px solid rgba(139,92,246,.3)",borderRadius:8,overflow:"hidden",boxShadow:"0 4px 12px rgba(0,0,0,.12)"}}>
              <div style={{padding:"6px 8px",borderBottom:`1px solid ${T.border}`}}>
                <input autoFocus placeholder="Search glossary terms…" value={assetGlSearch} onChange={e=>setAssetGlSearch(e.target.value)}
                  style={{width:"100%",padding:"5px 8px",background:T.bgElevated,border:`1px solid ${T.border}`,borderRadius:6,color:T.text,fontSize:12,outline:"none",boxSizing:"border-box"}}
                  onFocus={e=>e.target.style.borderColor="#8b5cf6"} onBlur={e=>e.target.style.borderColor=T.border}/>
              </div>
              <div style={{maxHeight:200,overflowY:"auto"}}>
                {GLOSSARY_TERMS.filter(t=>!assetGlSearch||t.term.toLowerCase().includes(assetGlSearch.toLowerCase())||t.abbr?.toLowerCase().includes(assetGlSearch.toLowerCase())).map(t=>{
                  const sel=assetGlTerms.includes(t.term);
                  return(<button key={t.id} onClick={()=>setAssetGlTerms(prev=>sel?prev.filter(x=>x!==t.term):[...prev,t.term])}
                    style={{width:"100%",display:"flex",alignItems:"center",gap:8,padding:"8px 12px",background:sel?"rgba(139,92,246,.06)":"transparent",border:"none",cursor:"pointer",textAlign:"left",transition:"background .1s"}}
                    onMouseEnter={e=>{if(!sel)e.currentTarget.style.background=T.bgHover;}} onMouseLeave={e=>{if(!sel)e.currentTarget.style.background="transparent";}}>
                    <div style={{flex:1,minWidth:0}}>
                      <div style={{fontSize:12,fontWeight:600,color:sel?"#8b5cf6":T.text}}>{t.term}</div>
                      <div style={{fontSize:10.5,color:T.textMuted,display:"flex",gap:5,marginTop:1}}>
                        {t.abbr&&t.abbr!=="—"&&<span style={{fontFamily:"'Geist Mono',monospace"}}>{t.abbr}</span>}
                        <span>{t.domain}</span>
                      </div>
                    </div>
                    {sel&&<svg width="12" height="12" viewBox="0 0 14 14" fill="none"><path d="M2.5 7.5l3 3 6-6" stroke="#8b5cf6" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round"/></svg>}
                  </button>);
                })}
                {GLOSSARY_TERMS.filter(t=>!assetGlSearch||t.term.toLowerCase().includes(assetGlSearch.toLowerCase())).length===0&&<div style={{padding:"12px",fontSize:12,color:T.textMuted,textAlign:"center"}}>No terms match</div>}
              </div>
              <div style={{padding:"6px 8px",borderTop:`1px solid ${T.border}`,display:"flex",justifyContent:"flex-end"}}>
                <button onClick={()=>setAssetGlOpen(false)} style={{padding:"4px 12px",borderRadius:5,background:"#8b5cf6",border:"none",color:"#fff",fontSize:11.5,fontWeight:600,cursor:"pointer"}}>Done</button>
              </div>
            </div>
          )}
        </div>

        {/* Certificate edit modal */}
        {editModal==="cert"&&(
          <>
            <div onClick={()=>setEditModal(null)} style={{position:"fixed",inset:0,zIndex:500,background:"rgba(0,0,0,.4)"}}/>
            <div style={{position:"fixed",top:"50%",left:"50%",transform:"translate(-50%,-50%)",zIndex:501,background:T.bgSurface,border:`1px solid ${T.border}`,borderRadius:14,boxShadow:"0 24px 64px rgba(0,0,0,.4)",width:280,display:"flex",flexDirection:"column",overflow:"hidden"}}>
              <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"14px 16px",borderBottom:`1px solid ${T.border}`}}>
                <span style={{fontSize:13.5,fontWeight:700,color:T.text}}>Edit Certificate</span>
                <button onClick={()=>setEditModal(null)} style={{background:"none",border:"none",cursor:"pointer",color:T.textMuted,padding:3,display:"flex",borderRadius:5}} onMouseEnter={e=>e.currentTarget.style.color=T.text} onMouseLeave={e=>e.currentTarget.style.color=T.textMuted}>
                  <svg width="12" height="12" viewBox="0 0 10 10" fill="none"><path d="M1.5 1.5l7 7M8.5 1.5l-7 7" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round"/></svg>
                </button>
              </div>
              <div style={{overflowY:"auto"}}>
                {Object.entries(CMETA).map(([c,m])=>(
                  <button key={c} onClick={()=>{setData(d=>({...d,cert:c}));setEditModal(null);onToast(`Certification set to ${c}`,"success");}}
                    style={{width:"100%",display:"flex",alignItems:"center",gap:12,padding:"11px 16px",background:data.cert===c?m.bg:"transparent",border:"none",cursor:"pointer",transition:"background .1s"}}
                    onMouseEnter={e=>{if(data.cert!==c)e.currentTarget.style.background=T.bgHover;}}
                    onMouseLeave={e=>{if(data.cert!==c)e.currentTarget.style.background="transparent";}}>
                    <span style={{fontSize:16}}>{m.icon}</span>
                    <span style={{flex:1,fontSize:13,fontWeight:600,color:m.color}}>{c}</span>
                    {data.cert===c&&<svg width="13" height="13" viewBox="0 0 14 14" fill="none"><path d="M2.5 7.5l3 3 6-6" stroke={m.color} strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round"/></svg>}
                  </button>
                ))}
              </div>
            </div>
          </>
        )}

        {/* ACTIONS */}
        <div style={{padding:"16px"}}>
          <MetaLabel>Actions</MetaLabel>
          {[
            {l:"Request Access", fn:()=>onToast("Access request sent","success")},
            {l:"Copy Link",      fn:()=>onToast("Link copied","success")},
            {l:"View Lineage",   fn:()=>setTab("lineage")},
          ].map((a,i,arr)=>(
            <button key={i} onClick={a.fn}
              style={{width:"100%",display:"flex",alignItems:"center",justifyContent:"space-between",padding:"8px 0",background:"none",border:"none",borderBottom:i<arr.length-1?`1px solid ${T.border}`:"none",color:T.textSub,fontSize:12.5,cursor:"pointer",transition:"color .1s"}}
              onMouseEnter={e=>e.currentTarget.style.color=T.accent} onMouseLeave={e=>e.currentTarget.style.color=T.textSub}>
              {a.l}
              <svg width="9" height="9" viewBox="0 0 10 10" fill="none"><path d="M3 2l4 3-4 3" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round"/></svg>
            </button>
          ))}
        </div>

      </div>}

    </div>

    {/* Certification Modal */}
    <Modal open={certModal} onClose={()=>setCertModal(false)} title={`Certify "${asset.name}"`}>
      <p style={{fontSize:13,color:T.textSub,marginBottom:16}}>Certifying marks this asset as trusted and production-ready. This action is logged and visible to all users.</p>
      <div style={{display:"flex",flexDirection:"column",gap:12}}>
        {[
          {label:"Schema documented",done:true},
          {label:"PII columns tagged",done:true},
          {label:"Data lineage verified",done:true},
          {label:"Quality rules passing",done:data.quality>=85},
          {label:"Owner assigned",done:true},
          {label:"Retention policy applied",done:false},
        ].map((c,i)=>(
          <div key={i} style={{display:"flex",alignItems:"center",gap:10,padding:"8px 12px",background:c.done?T.accentDim:T.bgElevated,border:`1px solid ${c.done?"rgba(238,36,36,0.2)":T.border}`,borderRadius:8}}>
            <span style={{color:c.done?T.accent:T.textMuted}}>{c.done?Ic.check(14):Ic.x(14)}</span>
            <span style={{fontSize:13,color:c.done?T.text:T.textSub}}>{c.label}</span>
            {!c.done&&<span style={{fontSize:11,color:T.amber,marginLeft:"auto"}}>Required</span>}
          </div>
        ))}
      </div>
      <div style={{marginTop:16}}>
        <div style={{fontSize:12,color:T.textSub,marginBottom:6}}>Certification notes</div>
        <Input2 multiline rows={3} placeholder="Add notes for the certification record…" value={certNote} onChange={e=>setCertNote(e.target.value)}/>
      </div>
      <div style={{display:"flex",gap:8,marginTop:20,justifyContent:"flex-end"}}>
        <Btn onClick={()=>setCertModal(false)}>Cancel</Btn>
        <Btn variant="primary" icon={Ic.cert(13)} onClick={handleCertify}>Certify Asset</Btn>
      </div>
    </Modal>
  </div>;
};
// ─────────────────────────────────────────────
// CATALOG VIEW
// ─────────────────────────────────────────────
const CatalogView = ({onAsset})=>{
  const tagCtx = useTagCtx();
  const [q,         setQ]         = useState("");
  const [view,      setView]      = useState("table");
  const [sortBy,    setSortBy]    = useState("relevance");
  const [panelOpen, setPanelOpen] = useState(true);
  const [selConnTypes,setSelConnTypes]= useState(new Set());
  const [selTypes,   setSelTypes]   = useState(new Set());
  const [selDomains, setSelDomains] = useState(new Set());
  const [selCerts,   setSelCerts]   = useState(new Set());
  const [selTiers,   setSelTiers]   = useState(new Set());
  const [selConns,   setSelConns]   = useState(new Set());
  const [selOwners,  setSelOwners]  = useState(new Set());
  const [selTags,          setSelTags]          = useState(new Set());
  const [selGlossaryTerms, setSelGlossaryTerms] = useState(new Set());
  const [openGroup,  setOpenGroup]  = useState({conntype:true,connection:false,domain:true,type:true,cert:false,tier:false,owner:false,tags:false,glossary:false});
  const PAGE_SIZE = 25;
  const [page, setPage] = useState(1);
  useEffect(()=>{ setPage(1); },[q,selConnTypes,selTypes,selDomains,selCerts,selTiers,selConns,selOwners,selTags,selGlossaryTerms]);
  const DRILLABLE_TYPES = new Set(["Database","Catalog","Schema","Bucket","Container","Folder"]);
  const CONN_TYPE_ASSET_TYPES = {
    snowflake:  ["Database","Schema","Table","View"],
    databricks: ["Catalog","Schema","Table","View"],
    oracle:     ["Database","Schema","Table","View"],
    postgres:   ["Database","Schema","Table","View"],
    mysql:      ["Database","Table","View"],
    s3:         ["Bucket","Folder","Object"],
    azureblob:  ["Container","Blob"],
    airflow:    ["Pipeline"],
  };

  const toggle = (setter, val) => setter(prev => { const next = new Set(prev); next.has(val)?next.delete(val):next.add(val); return next; });
  const sorts = [{v:"relevance",l:"Relevance"},{v:"quality",l:"Quality ↓"},{v:"name",l:"Name A–Z"},{v:"updated",l:"Recently Updated"},{v:"usage",l:"Popularity"}];

  const filtered = ASSETS.filter(a => {
    const mq  = !q || a.name.toLowerCase().includes(q.toLowerCase()) || (a.domain||"").toLowerCase().includes(q.toLowerCase()) || (a.tags||[]).some(t=>t.toLowerCase().includes(q.toLowerCase())) || (a.description||"").toLowerCase().includes(q.toLowerCase()) || (a.db||"").toLowerCase().includes(q.toLowerCase()) || (SCHEMA[a.name]||[]).some(c=>c.name.toLowerCase().includes(q.toLowerCase()));
    const mct = selConnTypes.size===0 || selConnTypes.has(a.service);
    const mt  = selTypes.size===0   || selTypes.has(a.type);
    const md  = selDomains.size===0 || selDomains.has(a.domain);
    const mc  = selCerts.size===0   || selCerts.has(a.cert);
    const mti = selTiers.size===0   || selTiers.has(String(a.tier));
    const ms  = selConns.size===0   || selConns.has(a.connectionLabel);
    const mo  = selOwners.size===0  || selOwners.has(a.owner);
    const mTag= selTags.size===0    || (a.tags||[]).some(t=>selTags.has(t));
    const mGT = selGlossaryTerms.size===0 || GLOSSARY_TERMS.filter(t=>selGlossaryTerms.has(t.id)).some(t=>(t.linkedAssets||[]).some(la=>la.name===a.name));
    return mq&&mct&&mt&&md&&mc&&mti&&ms&&mo&&mTag&&mGT;
  }).sort((a,b)=>{
    if(sortBy==="quality") return b.quality-a.quality;
    if(sortBy==="name")    return a.name.localeCompare(b.name);
    if(sortBy==="usage")   return (b.usage==="High"?2:b.usage==="Med"?1:0)-(a.usage==="High"?2:a.usage==="Med"?1:0);
    return 0;
  });
  const totalPages = Math.ceil(filtered.length / PAGE_SIZE);
  const pagedRows  = filtered.slice((page-1)*PAGE_SIZE, page*PAGE_SIZE);

  const totalActive = selConnTypes.size+selTypes.size+selDomains.size+selCerts.size+selTiers.size+selConns.size+selOwners.size+selTags.size+selGlossaryTerms.size;
  const clearAll = () => { setSelConnTypes(new Set()); setSelTypes(new Set()); setSelDomains(new Set()); setSelCerts(new Set()); setSelTiers(new Set()); setSelConns(new Set()); setSelOwners(new Set()); setSelTags(new Set()); setSelGlossaryTerms(new Set()); };
  const countFor = (field, val) => ASSETS.filter(a => {
    const mq = !q || a.name.toLowerCase().includes(q.toLowerCase());
    if(!mq) return false;
    if(field==="conntype")   return a.service===val;
    if(field==="type")       return a.type===val;
    if(field==="domain")     return a.domain===val;
    if(field==="cert")       return a.cert===val;
    if(field==="tier")       return String(a.tier)===val;
    if(field==="connection") return a.connectionLabel===val;
    if(field==="owner")      return a.owner===val;
    if(field==="glossary")   return (GLOSSARY_TERMS.find(t=>t.id===val)?.linkedAssets||[]).some(la=>la.name===a.name);
    return false;
  }).length;

  const CERT_COLORS = {"Approved":"#16a34a","In Review":"#d97706","Draft":"#6b7280","Rejected":"#e11d48","Deprecated":"#7c3aed"};
  const TIER_META   = {"1":{color:"#ee2424",label:"Critical"},"2":{color:"#d97706",label:"Important"},"3":{color:"#4b4b60",label:"Exploratory"}};
  const CONN_TYPE_LABELS = {cdp:"Solix CDP",ecs:"Solix ECS",snowflake:"Snowflake",databricks:"Databricks",oracle:"Oracle",postgres:"PostgreSQL",mysql:"MySQL",s3:"Amazon S3",azureblob:"Azure Blob",airflow:"Airflow"};
  const allConnTypes = [...new Set(ASSETS.map(a=>a.service))];
  const visibleConns = selConnTypes.size===0 ? [...new Set(ASSETS.map(a=>a.connectionLabel))] : [...new Set(ASSETS.filter(a=>selConnTypes.has(a.service)).map(a=>a.connectionLabel))];
  const ALL_ASSET_TYPES = selConnTypes.size===0
    ? [...new Set(ASSETS.map(a=>a.type))]
    : [...new Set([...selConnTypes].flatMap(ct=>CONN_TYPE_ASSET_TYPES[ct]||[]))].filter(t=>ASSETS.some(a=>a.type===t));

  const FacetGroup = ({id,label,icon,items,sel,onToggle,renderItem,headerNote}) => {
    const open = openGroup[id];
    return (
      <div style={{borderBottom:`1px solid ${T.border}`}}>
        <button onClick={()=>setOpenGroup(p=>({...p,[id]:!p[id]}))} style={{width:"100%",display:"flex",alignItems:"center",gap:8,padding:"9px 14px",background:"transparent",border:"none",cursor:"pointer",textAlign:"left"}}
          onMouseEnter={e=>e.currentTarget.style.background=T.bgHover} onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
          <span style={{color:T.textMuted,display:"flex"}}>{icon}</span>
          <span style={{flex:1,fontSize:11.5,fontWeight:600,color:T.text}}>{label}</span>
          {sel.size>0&&<span style={{fontSize:9.5,fontWeight:700,padding:"1px 5px",borderRadius:99,background:T.accentDim,color:T.accent,border:`1px solid ${T.accent}33`}}>{sel.size}</span>}
          <svg width="10" height="10" viewBox="0 0 10 10" fill="none" style={{color:T.textMuted,transform:open?"none":"rotate(-90deg)",transition:"transform .15s"}}><path d="M1.5 3.5l3.5 3.5 3.5-3.5" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round"/></svg>
        </button>
        {open&&(
          <div style={{padding:"2px 0 6px"}}>
            {headerNote&&<div style={{padding:"3px 14px 5px",fontSize:10,color:T.textMuted,fontStyle:"italic"}}>{headerNote}</div>}
            {items.length===0&&<div style={{padding:"4px 14px",fontSize:11,color:T.textMuted}}>No connections available</div>}
            {items.map(item=>{
              const active = sel.has(item.val);
              return (
                <button key={item.val} onClick={()=>onToggle(item.val)} style={{width:"100%",display:"flex",alignItems:"center",gap:8,padding:"5px 14px 5px 20px",background:active?T.accentDim:"transparent",border:"none",cursor:"pointer",transition:"background .1s"}}
                  onMouseEnter={e=>{if(!active)e.currentTarget.style.background=T.bgHover;}} onMouseLeave={e=>{if(!active)e.currentTarget.style.background="transparent";}}>
                  <div style={{width:13,height:13,borderRadius:3,flexShrink:0,display:"flex",alignItems:"center",justifyContent:"center",background:active?T.accent:"transparent",border:`1.5px solid ${active?T.accent:T.borderLight}`,transition:"all .12s"}}>
                    {active&&<svg width="7" height="7" viewBox="0 0 8 8" fill="none"><path d="M1 4l2 2.5L7 1.5" stroke="white" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/></svg>}
                  </div>
                  <span style={{flex:1,fontSize:11.5,color:active?T.text:T.textSub,fontWeight:active?600:400}}>{renderItem?renderItem(item):item.label}</span>
                  <span style={{fontSize:10.5,color:active?T.accent:T.textMuted,fontWeight:active?700:400}}>{countFor(id,item.val)}</span>
                </button>
              );
            })}
            {sel.size>0&&<button onClick={()=>onToggle(null,"clear")} style={{width:"100%",padding:"2px 14px 2px 20px",background:"transparent",border:"none",cursor:"pointer",textAlign:"left",fontSize:10.5,color:T.textMuted}}
              onMouseEnter={e=>e.currentTarget.style.color=T.rose} onMouseLeave={e=>e.currentTarget.style.color=T.textMuted}>Clear</button>}
          </div>
        )}
      </div>
    );
  };

  const activeChips = [
    ...[...selConnTypes].map(v=>({label:CONN_TYPE_LABELS[v]||v,clear:()=>toggle(setSelConnTypes,v)})),
    ...[...selTypes].map(v=>({label:v,clear:()=>toggle(setSelTypes,v)})),
    ...[...selDomains].map(v=>({label:v,clear:()=>toggle(setSelDomains,v)})),
    ...[...selCerts].map(v=>({label:v,clear:()=>toggle(setSelCerts,v)})),
    ...[...selTiers].map(v=>({label:`Tier ${v}`,clear:()=>toggle(setSelTiers,v)})),
    ...[...selConns].map(v=>({label:v,clear:()=>toggle(setSelConns,v)})),
    ...[...selOwners].map(v=>({label:v,clear:()=>toggle(setSelOwners,v)})),
    ...[...selTags].map(v=>({label:v,clear:()=>toggle(setSelTags,v)})),
    ...[...selGlossaryTerms].map(v=>({label:GLOSSARY_TERMS.find(t=>t.id===v)?.term||v,clear:()=>toggle(setSelGlossaryTerms,v)})),
  ];

  const FILE_FORMAT_COLORS = {CSV:"#16a34a",Parquet:"#0891b2",JSON:"#d97706",ORC:"#7c3aed"};
  const cols=[
    {key:"name",label:"Asset Name",render:(v,r)=>(
      <div style={{display:"flex",alignItems:"center",gap:10}}>
        <ServiceIcon service={r.service} size={18}/>
        <div>
          <div style={{display:"flex",alignItems:"center",gap:6}}>
            <span style={{fontSize:13,fontWeight:500,color:T.text,fontFamily:"'Geist Mono',monospace"}}>{v}</span>
            {DRILLABLE_TYPES.has(r.type)&&<svg width="10" height="10" viewBox="0 0 10 10" fill="none" style={{color:T.textMuted,flexShrink:0}}><path d="M3.5 2l4 3-4 3" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round" strokeLinejoin="round"/></svg>}
            {r.fileFormat&&<span style={{fontSize:9.5,fontWeight:700,padding:"1px 5px",borderRadius:3,background:`${FILE_FORMAT_COLORS[r.fileFormat]||T.textMuted}18`,color:FILE_FORMAT_COLORS[r.fileFormat]||T.textMuted,border:`1px solid ${FILE_FORMAT_COLORS[r.fileFormat]||T.textMuted}33`}}>{r.fileFormat}</span>}
          </div>
          {r.path&&r.path.length>0&&<div style={{fontSize:10,color:T.textMuted,marginTop:2,fontFamily:"'Geist Mono',monospace"}}>{r.path.join(" / ")}</div>}
          {(!r.path||r.path.length===0)&&r.db&&<div style={{fontSize:10,color:T.textMuted,marginTop:1}}>{r.db}</div>}
        </div>
      </div>
    )},
    {key:"type",label:"Type",render:v=><TypeBadge type={v}/>},
    {key:"owner",label:"Owner",render:(v,r)=>{const ol=r.owners||[v];return(<div style={{display:"flex",alignItems:"center"}}>{ol.slice(0,3).map((o,i)=>(<div key={i} title={o} style={{width:24,height:24,borderRadius:"50%",background:T.accentDim,display:"flex",alignItems:"center",justifyContent:"center",fontSize:8,fontWeight:700,color:T.accent,marginLeft:i>0?-7:0,position:"relative",zIndex:3-i,border:`2px solid ${T.bgSurface}`,boxSizing:"border-box",flexShrink:0}}>{o.split(".").map(s=>s[0].toUpperCase()).join("")}</div>))}{ol.length>3&&<div title={`+${ol.length-3} more`} style={{width:24,height:24,borderRadius:"50%",background:T.bgElevated,display:"flex",alignItems:"center",justifyContent:"center",fontSize:8,fontWeight:700,color:T.textMuted,marginLeft:-7,border:`2px solid ${T.bgSurface}`,boxSizing:"border-box",flexShrink:0}}>+{ol.length-3}</div>}</div>);}},
    {key:"quality",label:"Quality",render:(v,r)=>["Object","Blob","Bucket","Container","Folder"].includes(r.type)?<span style={{fontSize:11,color:T.textMuted}}>—</span>:<QScore score={v}/>},
    {key:"updated",label:"Updated",render:v=><span style={{fontSize:11,color:T.textMuted}}>{v}</span>},
  ];

  return (
    <div className="fadeUp" style={{height:"100%",display:"flex",flexDirection:"column"}}>
      <Topbar breadcrumb={[{label:"Data Catalog"}]}/>
      <div style={{flex:1,display:"flex",overflow:"hidden"}}>
        {/* Filter panel */}
        <div style={{width:panelOpen?212:0,minWidth:panelOpen?212:0,flexShrink:0,overflow:"hidden",borderRight:`1px solid ${T.border}`,background:T.bgSurface,display:"flex",flexDirection:"column",transition:"width .2s ease,min-width .2s ease"}}>
          <div style={{padding:"11px 14px 9px",borderBottom:`1px solid ${T.border}`,display:"flex",alignItems:"center",justifyContent:"space-between",flexShrink:0}}>
            <div style={{display:"flex",alignItems:"center",gap:6}}>{Ic.filter(12)}<span style={{fontSize:11.5,fontWeight:700,color:T.text}}>Filters</span>{totalActive>0&&<span style={{fontSize:9.5,fontWeight:700,padding:"1px 5px",borderRadius:99,background:T.accentDim,color:T.accent,border:`1px solid ${T.accent}33`}}>{totalActive}</span>}</div>
            <button onClick={clearAll} disabled={totalActive===0} style={{fontSize:11,color:totalActive>0?T.textMuted:"transparent",background:"none",border:"none",cursor:totalActive>0?"pointer":"default",transition:"color .15s"}} onMouseEnter={e=>{if(totalActive>0)e.currentTarget.style.color=T.rose;}} onMouseLeave={e=>{if(totalActive>0)e.currentTarget.style.color=T.textMuted;}}>Clear all</button>
          </div>
          <div style={{flex:1,overflowY:"auto"}}>
            <FacetGroup id="conntype" label="Connector Type" icon={Ic.plug(11)}
              items={allConnTypes.map(v=>({val:v,label:CONN_TYPE_LABELS[v]||v}))}
              sel={selConnTypes} onToggle={(v,c)=>c?setSelConnTypes(new Set()):toggle(setSelConnTypes,v)}
              renderItem={item=><div style={{display:"flex",alignItems:"center",gap:6}}><ServiceIcon service={item.val} size={13}/><span style={{fontSize:11.5,color:T.textSub}}>{item.label}</span></div>}/>
            <FacetGroup id="connection" label="Connection" icon={Ic.branches(11)}
              items={visibleConns.map(v=>({val:v,label:v,svc:ASSETS.find(a=>a.connectionLabel===v)?.service}))}
              sel={selConns} onToggle={(v,c)=>c?setSelConns(new Set()):toggle(setSelConns,v)}
              renderItem={item=><div style={{display:"flex",alignItems:"center",gap:6}}><ServiceIcon service={item.svc} size={13}/><span style={{fontSize:11,color:T.textSub,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{item.label}</span></div>}
              headerNote={selConnTypes.size>0?`Filtered by ${selConnTypes.size} type${selConnTypes.size>1?"s":""}`:null}/>
            <FacetGroup id="type" label="Asset Type" icon={Ic.catalog(11)}
              items={ALL_ASSET_TYPES.sort().map(v=>({val:v,label:v}))}
              sel={selTypes} onToggle={(v,c)=>c?setSelTypes(new Set()):toggle(setSelTypes,v)}
              renderItem={item=><div style={{display:"flex",alignItems:"center",gap:5}}><TypeBadge type={item.val}/></div>}/>
            <FacetGroup id="domain" label="Domain"
              icon={<svg width="11" height="11" viewBox="0 0 12 12" fill="none"><circle cx="6" cy="6" r="4.5" stroke="currentColor" strokeWidth="1.2"/><path d="M6 1.5c-1.5 1.5-2 3-2 4.5s.5 3 2 4.5M6 1.5c1.5 1.5 2 3 2 4.5s-.5 3-2 4.5M1.5 6h9" stroke="currentColor" strokeWidth="1.1" strokeLinecap="round"/></svg>}
              items={[...new Set(ASSETS.map(a=>a.domain))].filter(Boolean).sort().map(v=>({val:v,label:v}))}
              sel={selDomains} onToggle={(v,c)=>c?setSelDomains(new Set()):toggle(setSelDomains,v)}/>
            <FacetGroup id="owner" label="Owner" icon={Ic.access(11)}
              items={[...new Set(ASSETS.map(a=>a.owner))].map(v=>({val:v,label:v}))}
              sel={selOwners} onToggle={(v,c)=>c?setSelOwners(new Set()):toggle(setSelOwners,v)}
              renderItem={item=><div style={{display:"flex",alignItems:"center",gap:6}}><div style={{width:15,height:15,borderRadius:3,background:T.accentDim,border:`1px solid ${T.accent}33`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:6,fontWeight:700,color:T.accent,flexShrink:0}}>{item.val.split(".").map(s=>s[0].toUpperCase()).join("")}</div><span style={{fontSize:11,color:T.textSub}}>{item.label}</span></div>}/>
            <FacetGroup id="tags" label="Tags" icon={Ic.tag(11)}
              items={[...new Set(ASSETS.flatMap(a=>a.tags||[]))].sort().map(v=>({val:v,label:v}))}
              sel={selTags} onToggle={(v,c)=>c?setSelTags(new Set()):toggle(setSelTags,v)}
              renderItem={item=><div style={{display:"flex",alignItems:"center",gap:6}}><span style={{width:7,height:7,borderRadius:"50%",background:T.accent,display:"block",flexShrink:0,opacity:.7}}/><span style={{fontSize:11,color:T.textSub}}>{item.label}</span></div>}/>
            <FacetGroup id="glossary" label="Business Glossary" icon={Ic.glossary(11)}
              items={GLOSSARY_TERMS.map(t=>({val:t.id,label:t.term,abbr:t.abbr,status:t.status}))}
              sel={selGlossaryTerms} onToggle={(v,c)=>c?setSelGlossaryTerms(new Set()):toggle(setSelGlossaryTerms,v)}
              renderItem={item=>(
                <div style={{display:'flex',alignItems:'center',gap:6,minWidth:0}}>
                  <span style={{flex:1,fontSize:11,color:T.textSub,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{item.label}</span>
                  {item.abbr&&item.abbr!=='—'&&<span style={{fontSize:9.5,color:T.textMuted,fontFamily:"'Geist Mono',monospace",flexShrink:0}}>{item.abbr}</span>}
                </div>
              )}/>
          </div>
        </div>

        {/* Results */}
        <div style={{flex:1,display:"flex",flexDirection:"column",overflow:"hidden",minWidth:0}}>
          <div style={{padding:"8px 16px",borderBottom:`1px solid ${T.border}`,display:"flex",gap:8,alignItems:"center",flexShrink:0,background:T.bgSurface}}>
            {/* Filter toggle — icon only */}
            <button onClick={()=>setPanelOpen(v=>!v)} title={panelOpen?"Hide filters":"Show filters"}
              style={{width:32,height:32,borderRadius:7,background:panelOpen?T.accentDim:"transparent",border:`1px solid ${panelOpen?T.accent+"66":T.border}`,color:panelOpen?T.accent:T.textMuted,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,transition:"all .15s",position:"relative"}}
              onMouseEnter={e=>{if(!panelOpen){e.currentTarget.style.background=T.bgHover;e.currentTarget.style.borderColor=T.borderLight;}}}
              onMouseLeave={e=>{if(!panelOpen){e.currentTarget.style.background="transparent";e.currentTarget.style.borderColor=T.border;}}}>
              {Ic.filter(13)}
              {totalActive>0&&<span style={{position:"absolute",top:-4,right:-4,width:14,height:14,borderRadius:"50%",background:T.accent,color:"#fff",fontSize:8,fontWeight:700,display:"flex",alignItems:"center",justifyContent:"center"}}>{totalActive}</span>}
            </button>
            {/* Search */}
            <div style={{flex:1}}><Input2 placeholder="Search assets, descriptions, owners…" value={q} onChange={e=>setQ(e.target.value)} icon={Ic.search(12)}/></div>
            {/* Sort dropdown */}
            <div style={{display:"flex",alignItems:"center",gap:6,flexShrink:0}}>
              <span style={{fontSize:11,color:T.textMuted,whiteSpace:"nowrap"}}>Sort</span>
              <select value={sortBy} onChange={e=>setSortBy(e.target.value)}
                style={{padding:"5px 28px 5px 10px",borderRadius:7,background:T.bgElevated,border:`1px solid ${T.border}`,color:T.text,fontSize:12,outline:"none",cursor:"pointer",appearance:"none",backgroundImage:`url("data:image/svg+xml,%3Csvg width='10' height='6' viewBox='0 0 10 6' fill='none' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M1 1l4 4 4-4' stroke='%236b7280' stroke-width='1.5' stroke-linecap='round' stroke-linejoin='round'/%3E%3C/svg%3E")`,backgroundRepeat:"no-repeat",backgroundPosition:"right 8px center"}}>
                {sorts.map(s=><option key={s.v} value={s.v}>{s.l}</option>)}
              </select>
            </div>
            {/* View toggle — table / card */}
            <div style={{display:"flex",borderRadius:7,border:`1px solid ${T.border}`,overflow:"hidden",flexShrink:0}}>
              {[
                {v:"table",icon:<svg width="13" height="13" viewBox="0 0 14 14" fill="none"><rect x="1" y="1" width="12" height="2.5" rx=".8" fill="currentColor"/><rect x="1" y="5.25" width="12" height="2.5" rx=".8" fill="currentColor" opacity=".5"/><rect x="1" y="9.5" width="12" height="2.5" rx=".8" fill="currentColor" opacity=".25"/></svg>},
                {v:"card", icon:<svg width="13" height="13" viewBox="0 0 14 14" fill="none"><rect x="1" y="1" width="5.5" height="5.5" rx="1" fill="currentColor"/><rect x="7.5" y="1" width="5.5" height="5.5" rx="1" fill="currentColor" opacity=".5"/><rect x="1" y="7.5" width="5.5" height="5.5" rx="1" fill="currentColor" opacity=".5"/><rect x="7.5" y="7.5" width="5.5" height="5.5" rx="1" fill="currentColor" opacity=".25"/></svg>},
              ].map(btn=>(
                <button key={btn.v} onClick={()=>setView(btn.v)} title={btn.v==="table"?"Table view":"Card view"}
                  style={{padding:"6px 9px",border:"none",background:view===btn.v?T.accent:"transparent",color:view===btn.v?"#fff":T.textMuted,cursor:"pointer",display:"flex",alignItems:"center",transition:"all .15s"}}
                  onMouseEnter={e=>{if(view!==btn.v)e.currentTarget.style.background=T.bgHover;}}
                  onMouseLeave={e=>{if(view!==btn.v)e.currentTarget.style.background="transparent";}}>
                  {btn.icon}
                </button>
              ))}
            </div>
            {/* Result count */}
            <span style={{fontSize:11,color:T.textMuted,whiteSpace:"nowrap",flexShrink:0,fontFamily:"'Geist Mono',monospace"}}><b style={{color:T.text}}>{filtered.length}</b>/{ASSETS.length}</span>
          </div>
          {activeChips.length>0&&(
            <div style={{padding:"6px 20px",borderBottom:`1px solid ${T.border}`,display:"flex",gap:5,flexWrap:"wrap",alignItems:"center",background:T.bgElevated,flexShrink:0}}>
              {activeChips.map((f,i)=>(
                <span key={i} style={{display:"inline-flex",alignItems:"center",gap:4,fontSize:11,padding:"2px 7px",borderRadius:99,background:T.accentDim,border:`1px solid ${T.accent}33`,color:T.accent}}>
                  {f.label}<button onClick={f.clear} style={{background:"none",border:"none",color:T.accent,cursor:"pointer",display:"flex",padding:0,opacity:.65,lineHeight:1}}><svg width="8" height="8" viewBox="0 0 10 10" fill="none"><path d="M1.5 1.5l7 7M8.5 1.5l-7 7" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round"/></svg></button>
                </span>
              ))}
              <button onClick={clearAll} style={{fontSize:10.5,color:T.textMuted,background:"none",border:"none",cursor:"pointer",marginLeft:2}} onMouseEnter={e=>e.currentTarget.style.color=T.rose} onMouseLeave={e=>e.currentTarget.style.color=T.textMuted}>Clear all</button>
            </div>
          )}
          <div style={{flex:1,overflowY:"auto",padding:"18px 20px"}}>
            {filtered.length===0&&<div style={{display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",height:200,gap:8}}><div style={{color:T.textMuted,opacity:.25}}>{Ic.catalog(36)}</div><div style={{fontSize:13,fontWeight:600,color:T.textSub}}>No assets match your filters</div><button onClick={clearAll} style={{fontSize:12,color:T.accent,background:"none",border:"none",cursor:"pointer"}}>Clear all filters</button></div>}
            {view==="table"&&filtered.length>0&&<DataTable cols={cols} rows={pagedRows} onRowClick={r=>onAsset(r)}/>}
            {view==="card"&&filtered.length>0&&(
              <div style={{display:"flex",flexDirection:"column",gap:8}}>
                {pagedRows.map(a=>{
                  // Find glossary terms linked to this asset
                  return (
                    <div key={a.id} style={{background:T.bgSurface,border:`1px solid ${T.border}`,borderRadius:10,cursor:"pointer",transition:"all .15s",overflow:"hidden"}}
                      onMouseEnter={e=>{e.currentTarget.style.borderColor=T.accent+"55";e.currentTarget.style.background=T.bgHover;}}
                      onMouseLeave={e=>{e.currentTarget.style.borderColor=T.border;e.currentTarget.style.background=T.bgSurface;}}>
                      <div onClick={()=>onAsset(a)} style={{display:"flex",alignItems:"center",gap:16,padding:"14px 16px"}}>
                        <ServiceIcon service={a.service} size={32}/>
                        <div style={{flex:"0 0 280px",minWidth:0}}>
                          <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:2}}><span style={{fontSize:13.5,fontWeight:700,color:T.text,fontFamily:"'Geist Mono',monospace",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{a.name}</span></div>
                          <div style={{fontSize:10,color:T.textMuted,marginBottom:4,letterSpacing:"0.02em",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{a.db}</div>
                          <div style={{fontSize:11.5,color:T.textSub,lineHeight:1.45,overflow:"hidden",display:"-webkit-box",WebkitLineClamp:1,WebkitBoxOrient:"vertical"}}>{a.description}</div>
                        </div>
                        <div style={{display:"flex",alignItems:"center",gap:7,flex:1,flexWrap:"wrap",minWidth:0}}>
                          <TypeBadge type={a.type}/>
                        </div>
                        <div style={{display:"flex",alignItems:"center",gap:16,flexShrink:0}}>
                          <div style={{textAlign:"center",width:40}}><div style={{fontSize:15,fontWeight:700,color:a.quality>=90?T.accent:a.quality>=70?T.amber:T.rose,fontFamily:"'Geist Mono',monospace",lineHeight:1}}>{a.quality}</div><div style={{fontSize:9,color:T.textMuted,marginTop:2}}>quality</div></div>
                          <div style={{display:"flex",alignItems:"center"}}>
                            {(a.owners||[a.owner]).slice(0,3).map((o,i)=>(
                              <div key={i} title={o} style={{width:24,height:24,borderRadius:"50%",background:T.accentDim,display:"flex",alignItems:"center",justifyContent:"center",fontSize:8,fontWeight:700,color:T.accent,marginLeft:i>0?-7:0,position:"relative",zIndex:3-i,border:`2px solid ${T.bgSurface}`,boxSizing:"border-box",flexShrink:0}}>{o.split(".").map(s=>s[0].toUpperCase()).join("")}</div>
                            ))}
                            {(a.owners||[a.owner]).length>3&&<div title={`+${(a.owners||[a.owner]).length-3} more`} style={{width:24,height:24,borderRadius:"50%",background:T.bgElevated,display:"flex",alignItems:"center",justifyContent:"center",fontSize:8,fontWeight:700,color:T.textMuted,marginLeft:-7,border:`2px solid ${T.bgSurface}`,boxSizing:"border-box",flexShrink:0}}>+{(a.owners||[a.owner]).length-3}</div>}
                          </div>
                          <span style={{fontSize:11,color:T.textMuted,whiteSpace:"nowrap",minWidth:50,textAlign:"right"}}>{a.updated}</span>
                          <span style={{color:T.textMuted,opacity:.4}}>{Ic.chevRight(12)}</span>
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            )}
            {/* Pagination */}
            {totalPages > 1 && (
              <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"12px 0 4px",borderTop:`1px solid ${T.border}`,marginTop:8}}>
                <span style={{fontSize:12,color:T.textMuted}}>
                  Showing {(page-1)*PAGE_SIZE+1}–{Math.min(page*PAGE_SIZE,filtered.length)} of {filtered.length} assets
                </span>
                <div style={{display:"flex",alignItems:"center",gap:4}}>
                  <button onClick={()=>setPage(p=>Math.max(1,p-1))} disabled={page===1}
                    style={{padding:"5px 10px",borderRadius:6,border:`1px solid ${T.border}`,background:T.bgElevated,color:page===1?T.textMuted:T.text,cursor:page===1?"default":"pointer",fontSize:12,transition:"all .1s"}}
                    onMouseEnter={e=>{if(page>1){e.currentTarget.style.borderColor=T.accent;e.currentTarget.style.color=T.accent;}}}
                    onMouseLeave={e=>{e.currentTarget.style.borderColor=T.border;e.currentTarget.style.color=page===1?T.textMuted:T.text;}}>
                    ← Prev
                  </button>
                  {Array.from({length:Math.min(7,totalPages)},(_,i)=>{
                    let pg; const half=3;
                    if(totalPages<=7) pg=i+1;
                    else if(page<=half+1) pg=i+1;
                    else if(page>=totalPages-half) pg=totalPages-6+i;
                    else pg=page-half+i;
                    return (
                      <button key={pg} onClick={()=>setPage(pg)}
                        style={{width:30,height:30,borderRadius:6,border:`1px solid ${pg===page?T.accent:T.border}`,background:pg===page?T.accentDim:T.bgElevated,color:pg===page?T.accent:T.text,cursor:"pointer",fontSize:12,fontWeight:pg===page?700:400,transition:"all .1s"}}
                        onMouseEnter={e=>{if(pg!==page){e.currentTarget.style.borderColor=T.accent;e.currentTarget.style.color=T.accent;}}}
                        onMouseLeave={e=>{if(pg!==page){e.currentTarget.style.borderColor=T.border;e.currentTarget.style.color=T.text;}}}>
                        {pg}
                      </button>
                    );
                  })}
                  <button onClick={()=>setPage(p=>Math.min(totalPages,p+1))} disabled={page===totalPages}
                    style={{padding:"5px 10px",borderRadius:6,border:`1px solid ${T.border}`,background:T.bgElevated,color:page===totalPages?T.textMuted:T.text,cursor:page===totalPages?"default":"pointer",fontSize:12,transition:"all .1s"}}
                    onMouseEnter={e=>{if(page<totalPages){e.currentTarget.style.borderColor=T.accent;e.currentTarget.style.color=T.accent;}}}
                    onMouseLeave={e=>{e.currentTarget.style.borderColor=T.border;e.currentTarget.style.color=page===totalPages?T.textMuted:T.text;}}>
                    Next →
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

