const PORTS_FLOW_NODE_TYPES={portInput:PortInputNode,portOutput:PortOutputNode,portProduct:PortProductNode};

const PortsLineageFlow=({inputPorts,outputPorts,pd})=>{
  const GAP_Y=90, X_IN=0, X_PROD=280, X_OUT=560;
  const nIn=inputPorts.length, nOut=outputPorts.length;
  const prodY=Math.max((nIn-1)*GAP_Y/2,(nOut-1)*GAP_Y/2);
  const inOffY=(nIn<=nOut)?((nOut-1)*GAP_Y-(nIn-1)*GAP_Y)/2:0;
  const outOffY=(nOut<=nIn)?((nIn-1)*GAP_Y-(nOut-1)*GAP_Y)/2:0;

  const initNodes=[
    ...inputPorts.map((p,i)=>({id:p.id,type:"portInput",position:{x:X_IN,y:inOffY+i*GAP_Y},data:{label:p.name,path:p.path.split(" / ").slice(-2).join(" / "),portType:p.type}})),
    {id:"__product__",type:"portProduct",position:{x:X_PROD,y:prodY-26},data:{label:pd.name||pd.displayName,icon:pd.icon,color:pd.color||"#6366f1"}},
    ...outputPorts.map((p,i)=>({id:p.id,type:"portOutput",position:{x:X_OUT,y:outOffY+i*GAP_Y},data:{label:p.name,path:p.path.split(" / ").slice(-2).join(" / "),portType:p.type}})),
  ];
  const initEdges=[
    ...inputPorts.map(p=>({id:`e-${p.id}-prod`,source:p.id,target:"__product__",type:"smoothstep",animated:true,style:{stroke:T.blue,strokeWidth:1.5},markerEnd:{type:MarkerType.ArrowClosed,color:T.blue,width:14,height:14}})),
    ...outputPorts.map(p=>({id:`e-prod-${p.id}`,source:"__product__",target:p.id,type:"smoothstep",animated:true,style:{stroke:"#7c3aed",strokeWidth:1.5},markerEnd:{type:MarkerType.ArrowClosed,color:"#7c3aed",width:14,height:14}})),
  ];
  const [nodes,,onNodesChange]=useNodesState(initNodes);
  const [edges,,onEdgesChange]=useEdgesState(initEdges);
  return(
    <div style={{height:Math.max(nIn,nOut)*GAP_Y+60,borderRadius:10,overflow:"hidden",border:`1px solid ${T.border}`,background:"#f8fafc"}}>
      <ReactFlow nodes={nodes} edges={edges} onNodesChange={onNodesChange} onEdgesChange={onEdgesChange}
        nodeTypes={PORTS_FLOW_NODE_TYPES} fitView fitViewOptions={{padding:0.2}} proOptions={{hideAttribution:true}}
        nodesDraggable={false} nodesConnectable={false} elementsSelectable={false}
        panOnDrag={false} zoomOnScroll={false} zoomOnPinch={false} colorMode="light"
        style={{background:"#f8fafc"}}>
        <Background color="#cbd5e1" gap={20} size={1} variant="dots"/>
        <Controls showInteractive={false} style={{background:"#fff",border:"1px solid #e2e8f0",borderRadius:8}}/>
      </ReactFlow>
    </div>
  );
};

// ─────────────────────────────────────────────
// PORTS TAB (shared between Domains + DataProducts)
// ─────────────────────────────────────────────
const PortsTab=({pd,allAssets,onPatch})=>{
  const inputPortIds  = pd.inputPortIds  || [];
  const outputPortIds = pd.outputPortIds || [];

  const inputPorts  = inputPortIds.map(id=>allAssets.find(a=>a.id===id)).filter(Boolean);
  const outputPorts = outputPortIds.map(id=>allAssets.find(a=>a.id===id)).filter(Boolean);

  const toFlowPort = a=>({id:`p-${a.id}`,name:a.name,path:a.db||a.connectionLabel||a.service,type:a.type});

  const [addTarget, setAddTarget] = useState(null);   // "input"|"output"|null
  const [addSearch, setAddSearch] = useState("");
  const [addSelected,setAddSelected]=useState(new Set());

  const openAdd=(kind)=>{setAddTarget(kind);setAddSearch("");setAddSelected(new Set());};
  const closeAdd=()=>{setAddTarget(null);setAddSearch("");setAddSelected(new Set());};

  const alreadyAdded = new Set([...inputPortIds,...outputPortIds]);
  const pickerAssets = allAssets.filter(a=>{
    if(addTarget==="input"  && inputPortIds.includes(a.id))  return false;
    if(addTarget==="output" && outputPortIds.includes(a.id)) return false;
    if(addSearch){
      const q=addSearch.toLowerCase();
      return a.name.toLowerCase().includes(q)||a.db.toLowerCase().includes(q)||(a.type||"").toLowerCase().includes(q);
    }
    return true;
  });

  const toggleSel=(id)=>setAddSelected(prev=>{
    const n=new Set(prev);
    n.has(id)?n.delete(id):n.add(id);
    return n;
  });

  const confirmAdd=()=>{
    if(addTarget==="input"){
      onPatch({inputPortIds:[...new Set([...inputPortIds,...addSelected])]});
    } else {
      onPatch({outputPortIds:[...new Set([...outputPortIds,...addSelected])]});
    }
    closeAdd();
  };

  const removePort=(id,kind)=>{
    if(kind==="input")  onPatch({inputPortIds:inputPortIds.filter(x=>x!==id)});
    else                onPatch({outputPortIds:outputPortIds.filter(x=>x!==id)});
  };

  const SVC_ICON={cdp:"🗄️",ecs:"📁",snowflake:"❄️",postgres:"🐘",databricks:"🔷",oracle:"🔶",mysql:"🐬",airflow:"🌀",s3:"🪣"};

  /* OM-style port card — matches screenshot exactly */
  const PortAssetCard=({asset,color,kind})=>{
    const pathFull=asset.db||"";
    const svcIcon=SVC_ICON[asset.service]||"❄️";
    const [menuOpen,setMenuOpen]=useState(false);
    return (
      <div style={{background:"#fff",border:`1px solid ${T.border}`,borderRadius:10,padding:"14px 16px",boxShadow:"0 1px 4px rgba(0,0,0,.06)",position:"relative"}}>
        {/* Row 1: service icon + full breadcrumb path + ⋮ menu */}
        <div style={{display:"flex",alignItems:"center",gap:7,marginBottom:10}}>
          <span style={{fontSize:14,flexShrink:0,lineHeight:1}}>{svcIcon}</span>
          <span style={{fontSize:12,color:T.textMuted,flex:1,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{pathFull||"—"}</span>
          <div style={{position:"relative",flexShrink:0}}>
            <button onClick={e=>{e.stopPropagation();setMenuOpen(p=>!p);}}
              style={{background:"none",border:"none",cursor:"pointer",color:T.textMuted,padding:"2px 5px",borderRadius:5,fontSize:16,lineHeight:1,display:"flex",alignItems:"center"}}
              onMouseEnter={e=>e.currentTarget.style.background=T.bgHover}
              onMouseLeave={e=>e.currentTarget.style.background="none"}>⋮</button>
            {menuOpen&&(
              <>
                <div onClick={()=>setMenuOpen(false)} style={{position:"fixed",inset:0,zIndex:900}}/>
                <div style={{position:"absolute",right:0,top:"calc(100% + 4px)",zIndex:901,background:T.bgSurface,border:`1px solid ${T.border}`,borderRadius:9,boxShadow:"0 6px 20px rgba(0,0,0,.15)",minWidth:140,overflow:"hidden"}}>
                  <button onClick={()=>{removePort(asset.id,kind);setMenuOpen(false);}}
                    style={{width:"100%",display:"flex",alignItems:"center",gap:8,padding:"9px 14px",background:"none",border:"none",cursor:"pointer",color:T.rose,fontSize:12.5,textAlign:"left"}}
                    onMouseEnter={e=>e.currentTarget.style.background="rgba(225,29,72,.06)"}
                    onMouseLeave={e=>e.currentTarget.style.background="none"}>
                    {Ic.trash(12)} Remove Port
                  </button>
                </div>
              </>
            )}
          </div>
        </div>
        {/* Row 2: schema/network icon + large blue name */}
        <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:8}}>
          <svg width="18" height="18" viewBox="0 0 20 20" fill="none" style={{flexShrink:0}}>
            <circle cx="10" cy="10" r="3" fill={color}/>
            <circle cx="3"  cy="4"  r="2" fill={color} opacity=".7"/>
            <circle cx="17" cy="4"  r="2" fill={color} opacity=".7"/>
            <circle cx="3"  cy="16" r="2" fill={color} opacity=".7"/>
            <circle cx="17" cy="16" r="2" fill={color} opacity=".7"/>
            <line x1="10" y1="10" x2="3"  y2="4"  stroke={color} strokeWidth="1.3" opacity=".7"/>
            <line x1="10" y1="10" x2="17" y2="4"  stroke={color} strokeWidth="1.3" opacity=".7"/>
            <line x1="10" y1="10" x2="3"  y2="16" stroke={color} strokeWidth="1.3" opacity=".7"/>
            <line x1="10" y1="10" x2="17" y2="16" stroke={color} strokeWidth="1.3" opacity=".7"/>
          </svg>
          <span style={{fontSize:16,fontWeight:700,color,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{asset.name}</span>
        </div>
        {/* Row 3: description */}
        <div style={{fontSize:12.5,color:T.textMuted,marginBottom:10,lineHeight:1.5}}>{asset.description||"No description"}</div>
        {/* Row 4: footer metadata */}
        <div style={{display:"flex",alignItems:"center",gap:6,fontSize:12,color:T.textMuted}}>
          <svg width="13" height="13" viewBox="0 0 14 14" fill="none"><circle cx="7" cy="7" r="5.5" stroke="currentColor" strokeWidth="1.2"/><path d="M7 4v3l2 1.5" stroke="currentColor" strokeWidth="1.2" strokeLinecap="round"/></svg>
          <span>No Domains</span>
          <span>·</span>
          <svg width="13" height="13" viewBox="0 0 14 14" fill="none"><circle cx="7" cy="5" r="2.5" stroke="currentColor" strokeWidth="1.2"/><path d="M2.5 12c0-2.485 2.015-4.5 4.5-4.5s4.5 2.015 4.5 4.5" stroke="currentColor" strokeWidth="1.2" strokeLinecap="round"/></svg>
          <span>No Owners</span>
          <span>·</span>
        </div>
      </div>
    );
  };

  const [inCollapsed,  setInCollapsed]  = useState(false);
  const [outCollapsed, setOutCollapsed] = useState(false);
  const hasAny=inputPorts.length>0||outputPorts.length>0;

  const ChevIcon=({open})=>(
    <svg width="13" height="13" viewBox="0 0 14 14" fill="none">
      <path d={open?"M3 9l4-4 4 4":"M3 5l4 4 4-4"} stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round"/>
    </svg>
  );

  return (
    <div style={{position:"relative"}}>
      {/* Ports Lineage */}
      {hasAny&&(
        <div style={{marginBottom:24}}>
          <div style={{fontSize:13,fontWeight:700,color:T.text,marginBottom:10}}>Ports Lineage</div>
          <PortsLineageFlow
            inputPorts={inputPorts.map(toFlowPort)}
            outputPorts={outputPorts.map(toFlowPort)}
            pd={pd}/>
        </div>
      )}

      {/* Input + Output columns — OM layout */}
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:20}}>
        {/* Input Ports */}
        <div>
          <div style={{display:"flex",alignItems:"center",gap:0,marginBottom:inCollapsed?0:14,padding:"10px 14px",background:"#fff",border:`1px solid ${T.border}`,borderRadius:inCollapsed?10:"10px 10px 0 0",borderBottom:inCollapsed?`1px solid ${T.border}`:"none"}}>
            <span style={{fontSize:13.5,fontWeight:700,color:T.text}}>Input Ports <span style={{fontWeight:400,color:T.textMuted}}>({inputPorts.length})</span></span>
            <div style={{marginLeft:"auto",display:"flex",alignItems:"center",gap:8}}>
              <button onClick={()=>openAdd("input")}
                style={{height:28,padding:"0 12px",borderRadius:7,background:"none",border:`1.5px solid ${T.blue}`,color:T.blue,fontSize:12,fontWeight:600,cursor:"pointer",display:"flex",alignItems:"center",gap:5,fontFamily:"inherit",transition:"all .12s"}}
                onMouseEnter={e=>{e.currentTarget.style.background=`${T.blue}10`;}}
                onMouseLeave={e=>{e.currentTarget.style.background="none";}}>
                Add
              </button>
              <button onClick={()=>setInCollapsed(p=>!p)} style={{background:"none",border:"none",cursor:"pointer",color:T.textMuted,padding:"2px 3px",display:"flex",borderRadius:5}} onMouseEnter={e=>e.currentTarget.style.color=T.text} onMouseLeave={e=>e.currentTarget.style.color=T.textMuted}>
                <ChevIcon open={!inCollapsed}/>
              </button>
            </div>
          </div>
          {!inCollapsed&&(
            <div style={{border:`1px solid ${T.border}`,borderTop:"none",borderRadius:"0 0 10px 10px",padding:12,background:"#fafafa",display:"flex",flexDirection:"column",gap:10}}>
              {inputPorts.length===0
                ? <div style={{padding:"24px 16px",textAlign:"center",color:T.textMuted,fontSize:12.5}}>
                    No input ports yet.{" "}
                    <span style={{color:T.blue,cursor:"pointer",fontWeight:600}} onClick={()=>openAdd("input")}>+ Add from catalog</span>
                  </div>
                : inputPorts.map(a=><PortAssetCard key={a.id} asset={a} color={T.blue} kind="input"/>)
              }
            </div>
          )}
        </div>

        {/* Output Ports */}
        <div>
          <div style={{display:"flex",alignItems:"center",gap:0,marginBottom:outCollapsed?0:14,padding:"10px 14px",background:"#fff",border:`1px solid ${T.border}`,borderRadius:outCollapsed?10:"10px 10px 0 0",borderBottom:outCollapsed?`1px solid ${T.border}`:"none"}}>
            <span style={{fontSize:13.5,fontWeight:700,color:T.text}}>Output Ports <span style={{fontWeight:400,color:T.textMuted}}>({outputPorts.length})</span></span>
            <div style={{marginLeft:"auto",display:"flex",alignItems:"center",gap:8}}>
              <button onClick={()=>openAdd("output")}
                style={{height:28,padding:"0 12px",borderRadius:7,background:"none",border:`1.5px solid ${T.border}`,color:T.textSub,fontSize:12,fontWeight:600,cursor:"pointer",display:"flex",alignItems:"center",gap:5,fontFamily:"inherit",transition:"all .12s"}}
                onMouseEnter={e=>{e.currentTarget.style.borderColor=T.textSub;}}
                onMouseLeave={e=>{e.currentTarget.style.borderColor=T.border;}}>
                Add
              </button>
              <button onClick={()=>setOutCollapsed(p=>!p)} style={{background:"none",border:"none",cursor:"pointer",color:T.textMuted,padding:"2px 3px",display:"flex",borderRadius:5}} onMouseEnter={e=>e.currentTarget.style.color=T.text} onMouseLeave={e=>e.currentTarget.style.color=T.textMuted}>
                <ChevIcon open={!outCollapsed}/>
              </button>
            </div>
          </div>
          {!outCollapsed&&(
            <div style={{border:`1px solid ${T.border}`,borderTop:"none",borderRadius:"0 0 10px 10px",padding:12,background:"#fafafa",display:"flex",flexDirection:"column",gap:10}}>
              {outputPorts.length===0
                ? <div style={{padding:"24px 16px",textAlign:"center",color:T.textMuted,fontSize:12.5}}>
                    No output ports yet.{" "}
                    <span style={{color:"#7c3aed",cursor:"pointer",fontWeight:600}} onClick={()=>openAdd("output")}>+ Add from catalog</span>
                  </div>
                : outputPorts.map(a=><PortAssetCard key={a.id} asset={a} color="#7c3aed" kind="output"/>)
              }
            </div>
          )}
        </div>
      </div>

      {/* Asset Picker Overlay */}
      {addTarget&&(
        <>
          {/* backdrop */}
          <div onClick={closeAdd} style={{position:"fixed",inset:0,background:"rgba(0,0,0,.35)",zIndex:1100}}/>
          {/* panel */}
          <div style={{position:"fixed",top:0,right:0,bottom:0,width:440,background:T.bgSurface,boxShadow:"-4px 0 32px rgba(0,0,0,.18)",zIndex:1101,display:"flex",flexDirection:"column"}}>
            {/* header */}
            <div style={{padding:"18px 20px 14px",borderBottom:`1px solid ${T.border}`,display:"flex",alignItems:"center",gap:10}}>
              <div style={{flex:1}}>
                <div style={{fontSize:15,fontWeight:700,color:T.text}}>Add {addTarget==="input"?"Input":"Output"} Port</div>
                <div style={{fontSize:11.5,color:T.textMuted,marginTop:2}}>Select assets from the data catalog</div>
              </div>
              <button onClick={closeAdd} style={{width:30,height:30,borderRadius:8,border:`1px solid ${T.border}`,background:T.bgElevated,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",color:T.textMuted}}>
                {Ic.x(13)}
              </button>
            </div>
            {/* search */}
            <div style={{padding:"12px 20px",borderBottom:`1px solid ${T.border}`}}>
              <div style={{position:"relative"}}>
                <span style={{position:"absolute",left:10,top:"50%",transform:"translateY(-50%)",color:T.textMuted,pointerEvents:"none"}}>{Ic.search(13)}</span>
                <input value={addSearch} onChange={e=>setAddSearch(e.target.value)} placeholder="Search assets…"
                  style={{width:"100%",height:34,padding:"0 10px 0 32px",borderRadius:8,border:`1px solid ${T.border}`,background:T.bgElevated,fontSize:12.5,color:T.text,fontFamily:"inherit",outline:"none",boxSizing:"border-box"}}/>
              </div>
            </div>
            {/* asset list */}
            <div style={{flex:1,overflowY:"auto",padding:"8px 0"}}>
              {pickerAssets.length===0
                ? <div style={{padding:"32px 20px",textAlign:"center",color:T.textMuted,fontSize:13}}>No assets found</div>
                : pickerAssets.map(a=>{
                    const sel=addSelected.has(a.id);
                    const parts=a.db?a.db.split(" / "):[];
                    const breadcrumb=parts.length>1?parts.slice(0,-1).join(" / "):(a.connectionLabel||"");
                    return (
                      <div key={a.id} onClick={()=>toggleSel(a.id)}
                        style={{padding:"10px 20px",cursor:"pointer",display:"flex",alignItems:"flex-start",gap:12,borderBottom:`1px solid ${T.border}`,background:sel?`${T.blue}06`:"transparent",transition:"background .1s"}}
                        onMouseEnter={e=>{if(!sel)e.currentTarget.style.background=T.bgElevated;}}
                        onMouseLeave={e=>{if(!sel)e.currentTarget.style.background="transparent";}}>
                        {/* checkbox */}
                        <div style={{width:16,height:16,borderRadius:4,border:`1.5px solid ${sel?T.blue:T.border}`,background:sel?T.blue:"transparent",flexShrink:0,marginTop:2,display:"flex",alignItems:"center",justifyContent:"center",transition:"all .12s"}}>
                          {sel&&<svg width="9" height="9" viewBox="0 0 10 10" fill="none"><path d="M1.5 5l3 3 4-4" stroke="#fff" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/></svg>}
                        </div>
                        {/* content */}
                        <div style={{flex:1,minWidth:0}}>
                          <div style={{display:"flex",alignItems:"center",gap:7,marginBottom:3}}>
                            <span style={{fontSize:9.5,fontWeight:700,padding:"1px 6px",borderRadius:4,background:`${T.blue}12`,color:T.blue,border:`1px solid ${T.blue}20`}}>{a.type}</span>
                            <span style={{fontSize:13,fontWeight:700,color:T.text,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{a.name}</span>
                          </div>
                          <div style={{fontSize:10.5,color:T.textMuted,fontFamily:"'Geist Mono',monospace",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{breadcrumb||a.db}</div>
                          <div style={{fontSize:11,color:T.textMuted,marginTop:2,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{a.description||"No description"}</div>
                        </div>
                      </div>
                    );
                  })
              }
            </div>
            {/* footer */}
            <div style={{padding:"14px 20px",borderTop:`1px solid ${T.border}`,display:"flex",alignItems:"center",gap:10}}>
              <span style={{fontSize:12,color:T.textMuted,flex:1}}>{addSelected.size>0?`${addSelected.size} asset${addSelected.size>1?"s":""} selected`:"Select assets to add"}</span>
              <button onClick={closeAdd} style={{height:34,padding:"0 14px",borderRadius:8,border:`1px solid ${T.border}`,background:T.bgElevated,color:T.textSub,fontSize:12.5,cursor:"pointer",fontFamily:"inherit"}}>Cancel</button>
              <button onClick={confirmAdd} disabled={addSelected.size===0}
                style={{height:34,padding:"0 16px",borderRadius:8,border:"none",background:addSelected.size>0?T.blue:"#94a3b8",color:"#fff",fontSize:12.5,fontWeight:600,cursor:addSelected.size>0?"pointer":"not-allowed",fontFamily:"inherit"}}>
                Add {addSelected.size>0?addSelected.size:""} Port{addSelected.size!==1?"s":""}
              </button>
            </div>
          </div>
        </>
      )}
    </div>
  );
};

