// Map connector display names → logo key
const LOGO_KEY_MAP = {
  "PostgreSQL":"postgres","MySQL":"mysql","Microsoft SQL":"mssql","Oracle":"oracle",
  "Snowflake":"snowflake","Google BigQuery":"bigquery","Amazon Redshift":"redshift",
  "Databricks":"databricks","Apache Airflow":"airflow","dbt":"dbt","dbt Cloud":"dbt",
  "Apache Spark":"spark","Fivetran":"fivetran","AWS Glue":"glue","Prefect":"prefect",
  "Apache Kafka":"kafka","Amazon Kinesis":"kinesis","Tableau":"tableau","Looker":"looker",
  "Power BI":"powerbi","Apache Superset":"superset","Metabase":"metabase","MLflow":"mlflow",
  "Amazon SageMaker":"sagemaker","Amazon S3":"s3","Google Cloud Storage":"gcs",
  "Azure Data Lake":"adls","Dagster":"dagster","Airbyte":"airbyte","Grafana":"grafana",
  "MongoDB":"mongodb","Elasticsearch":"elasticsearch","Vertex AI":"vertex","Redpanda":"redpanda",
};

const ConnectorLogo = ({name, color, size=40}) => {
  const logoFn = CONNECTOR_LOGOS[LOGO_KEY_MAP[name]];
  const bg = color || "#6366f1";
  if (logoFn) return (
    <div style={{width:size,height:size,borderRadius:Math.round(size*0.22),overflow:"hidden",flexShrink:0,boxShadow:"0 2px 8px rgba(0,0,0,.2)"}}>
      {logoFn(size)}
    </div>
  );
  return (
    <div style={{width:size,height:size,borderRadius:8,background:bg+"22",border:`1.5px solid ${bg}44`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:size*0.38,fontWeight:800,color:bg,flexShrink:0,letterSpacing:"-0.5px"}}>
      {name.slice(0,2).toUpperCase()}
    </div>
  );
};

