// ─────────────────────────────────────────────
// ROLE DEFINITIONS
// Each role defines:
//   nav    - which sidebar sections/items are visible
//   home   - which home widgets appear
//   badge  - display color
// ─────────────────────────────────────────────
// ─────────────────────────────────────────────
// RBAC — permission utility (OpenMetadata-style)
// ─────────────────────────────────────────────
const ROLE_PERMISSIONS = {
  admin: {
    glossary: ["view","create","edit","delete","approve","deprecate","resolve_conflict","manage_all_domains"],
    stewardship: ["view","create","edit","complete","reassign","escalate","manage_all"],
    catalog: ["view","edit","certify","delete"],
    settings: ["manage"],
  },
  steward: {
    // domain-scoped: steward can only govern terms/assets in their own domain
    glossary: ["view","create","edit","submit","approve_own_domain","deprecate_own_domain","resolve_conflict_own_domain"],
    stewardship: ["view","create","edit","complete","reassign"],
    catalog: ["view","edit","certify"],
    settings: [],
  },
  data_owner: {
    glossary: ["view","create","edit","submit"],
    stewardship: ["view","create"],
    catalog: ["view","edit"],
    settings: [],
  },
  analyst: {
    glossary: ["view","create","submit"],
    stewardship: ["view"],
    catalog: ["view"],
    settings: [],
  },
  engineer: {
    glossary: ["view"],
    stewardship: ["view"],
    catalog: ["view","edit"],
    settings: ["view"],
  },
  data_consumer: {
    glossary: ["view"],
    stewardship: [],
    catalog: ["view"],
    settings: [],
  },
  viewer: {
    glossary: ["view"],
    stewardship: [],
    catalog: ["view"],
    settings: [],
  },
};

const canPerform = (action, resource, userRole, userDomain=null, resourceDomain=null) => {
  const perms = ROLE_PERMISSIONS[userRole]?.[resource] || [];
  if(perms.includes("manage_all")||perms.includes("manage_all_domains")) return true;
  if(perms.includes(action)) return true;
  // Domain-scoped steward check
  if(userDomain&&resourceDomain&&userDomain===resourceDomain) {
    const domainPerm = `${action}_own_domain`;
    if(perms.includes(domainPerm)) return true;
  }
  return false;
};

