const LoginScreen = ({onLogin}) => {
  const [email,       setEmail]       = useState(()=>localStorage.getItem("solixSavedEmail")||"");
  const [password,    setPassword]    = useState(()=>localStorage.getItem("solixSavedPw")||"");
  const [rememberMe,  setRememberMe]  = useState(()=>!!localStorage.getItem("solixSavedEmail"));
  const [loading,     setLoading]     = useState(false);
  const [error,       setError]       = useState("");
  const [showPw,      setShowPw]      = useState(false);
  // forgot password flow: null | "form" | "sent"
  const [forgotMode,  setForgotMode]  = useState(null);
  const [resetEmail,  setResetEmail]  = useState("");
  const [resetError,  setResetError]  = useState("");
  const [resetLoading,setResetLoading]= useState(false);

  // Demo accounts mapped to roles
  const DEMO_ACCOUNTS = {
    "alex.rivera@jnj.com":  {role:"admin",    pw:"admin123"},
    "maya.chen@jnj.com":    {role:"steward",  pw:"steward123"},
    "dev.patel@jnj.com":    {role:"analyst",  pw:"analyst123"},
    "james.oh@jnj.com":     {role:"engineer", pw:"engineer123"},
    "sarah.kim@jnj.com":    {role:"viewer",   pw:"viewer123"},
  };

  const handleSubmit = () => {
    setError("");
    if(!email.trim()) { setError("Email is required"); return; }
    if(!password)     { setError("Password is required"); return; }
    setLoading(true);
    setTimeout(()=>{
      const account = DEMO_ACCOUNTS[email.toLowerCase().trim()];
      if(account && account.pw === password) {
        if(rememberMe) {
          localStorage.setItem("solixSavedEmail", email.toLowerCase().trim());
          localStorage.setItem("solixSavedPw", password);
        } else {
          localStorage.removeItem("solixSavedEmail");
          localStorage.removeItem("solixSavedPw");
        }
        onLogin(account.role);
      } else if(DEMO_ACCOUNTS[email.toLowerCase().trim()]) {
        setError("Incorrect password. Try the demo password shown below.");
        setLoading(false);
      } else {
        setError("No account found with that email.");
        setLoading(false);
      }
    }, 800);
  };

  const handleForgotSubmit = () => {
    setResetError("");
    if(!resetEmail.trim()) { setResetError("Email is required"); return; }
    if(!/\S+@\S+\.\S+/.test(resetEmail)) { setResetError("Enter a valid email address"); return; }
    setResetLoading(true);
    setTimeout(()=>{ setResetLoading(false); setForgotMode("sent"); }, 1200);
  };

  const quickLogin = (role) => {
    const cfg = ROLES_CONFIG[role];
    setEmail(cfg.email);
    setPassword(DEMO_ACCOUNTS[cfg.email].pw);
    setError("");
  };

  const leftPanel = (
    <div style={{
      width:"44%", background:`linear-gradient(145deg,#1a0505 0%,#2d0808 40%,#1a0505 100%)`,
      display:"flex", flexDirection:"column", justifyContent:"space-between",
      padding:"48px 52px", position:"relative", overflow:"hidden",
    }}>
      <div style={{position:"absolute",top:-120,right:-120,width:400,height:400,borderRadius:"50%",border:"1px solid rgba(238,36,36,0.3)",pointerEvents:"none"}}/>
      <div style={{position:"absolute",top:-60,right:-60,width:250,height:250,borderRadius:"50%",border:"1px solid rgba(238,36,36,0.2)",pointerEvents:"none"}}/>
      <div style={{position:"absolute",bottom:-80,left:-80,width:320,height:320,borderRadius:"50%",border:"1px solid rgba(238,36,36,0.15)",pointerEvents:"none"}}/>
      <div style={{display:"flex",alignItems:"center",gap:14,position:"relative",zIndex:1}}>
        <div style={{width:40,height:40,borderRadius:"50%",flexShrink:0,overflow:"hidden",boxShadow:"0 0 24px rgba(238,36,36,0.5)"}}>
          <svg width="40" height="40" viewBox="0 0 40 40" fill="none" xmlns="http://www.w3.org/2000/svg">
            <circle cx="20" cy="20" r="20" fill="#ee2424"/>
            <path d="M23 7L13 22h8l-4 11 14-16h-9l1-10z" fill="white"/>
          </svg>
        </div>
        <div>
          <div style={{fontSize:15,fontWeight:700,color:"#f4f4f5",letterSpacing:"-0.3px"}}>Solix</div>
          <div style={{fontSize:11,color:"rgba(255,255,255,0.45)",textTransform:"uppercase",letterSpacing:"0.1em",marginTop:1}}>Data Governance</div>
        </div>
      </div>
      <div style={{position:"relative",zIndex:1}}>
        <div style={{fontSize:32,fontWeight:700,color:"#f4f4f5",lineHeight:1.2,marginBottom:16,letterSpacing:"-0.5px"}}>
          Trusted data.<br/>
          <span style={{color:"#ee2424"}}>Governed</span> together.
        </div>
        <div style={{fontSize:14,color:"rgba(255,255,255,0.5)",lineHeight:1.7,marginBottom:40}}>
          One platform to discover, govern, and trust your data across every team and domain at Johnson &amp; Johnson.
        </div>
        <div style={{display:"flex",flexDirection:"column",gap:10}}>
          {[
            {icon:Ic.catalog(14), text:"6,724 assets indexed across 5 domains"},
            {icon:Ic.quality(14), text:"87.3% average data quality score"},
            {icon:Ic.compliance(14), text:"GDPR & HIPAA compliance tracked"},
          ].map((f,i)=>(
            <div key={i} style={{display:"flex",alignItems:"center",gap:10,padding:"10px 14px",background:"rgba(255,255,255,0.05)",borderRadius:9,border:"1px solid rgba(255,255,255,0.07)"}}>
              <span style={{color:"#ee2424",display:"flex",flexShrink:0}}>{f.icon}</span>
              <span style={{fontSize:12,color:"rgba(255,255,255,0.6)"}}>{f.text}</span>
            </div>
          ))}
        </div>
      </div>
      <div style={{fontSize:11,color:"rgba(255,255,255,0.25)",position:"relative",zIndex:1}}>
        © 2025 Johnson &amp; Johnson · Powered by Solix
      </div>
    </div>
  );

  /* ── Forgot password — email entry ── */
  if(forgotMode === "form") return (
    <div style={{minHeight:"100vh",display:"flex",background:T.bg,fontFamily:"'Geist',sans-serif"}}>
      {leftPanel}
      <div style={{flex:1,display:"flex",alignItems:"center",justifyContent:"center",padding:"40px 60px",overflowY:"auto"}}>
        <div style={{width:"100%",maxWidth:400}}>
          <button onClick={()=>{setForgotMode(null);setResetEmail("");setResetError("");}}
            style={{display:"flex",alignItems:"center",gap:6,background:"none",border:"none",color:T.textMuted,fontSize:12,cursor:"pointer",padding:0,marginBottom:28}}>
            <svg width="14" height="14" viewBox="0 0 16 16" fill="none"><path d="M10 3L5 8l5 5" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/></svg>
            Back to sign in
          </button>
          <div style={{marginBottom:28}}>
            <div style={{width:44,height:44,borderRadius:12,background:T.accentDim,border:`1px solid ${T.accent}33`,display:"flex",alignItems:"center",justifyContent:"center",marginBottom:16}}>
              <svg width="20" height="20" viewBox="0 0 20 20" fill="none"><rect x="2" y="5" width="16" height="12" rx="2" stroke={T.accent} strokeWidth="1.5"/><path d="M2 8l8 5 8-5" stroke={T.accent} strokeWidth="1.5"/></svg>
            </div>
            <div style={{fontSize:22,fontWeight:700,color:T.text,marginBottom:8,letterSpacing:"-0.4px"}}>Reset your password</div>
            <div style={{fontSize:13,color:T.textMuted,lineHeight:1.6}}>
              Enter your work email and we'll send a password reset link to your inbox.
            </div>
          </div>
          <div style={{marginBottom:16}}>
            <label style={{display:"block",fontSize:12,fontWeight:600,color:T.textSub,marginBottom:6}}>Work email</label>
            <input
              type="email" value={resetEmail} onChange={e=>{setResetEmail(e.target.value);setResetError("");}}
              onKeyDown={e=>e.key==="Enter"&&handleForgotSubmit()}
              placeholder="you@jnj.com" autoFocus
              style={{width:"100%",padding:"10px 13px",background:T.bgSurface,border:`1.5px solid ${resetError?T.rose:T.border}`,borderRadius:9,color:T.text,fontSize:13,outline:"none",boxSizing:"border-box",transition:"border-color .15s"}}
              onFocus={e=>e.target.style.borderColor=T.accent}
              onBlur={e=>e.target.style.borderColor=resetError?T.rose:T.border}
            />
          </div>
          {resetError && (
            <div style={{display:"flex",alignItems:"center",gap:7,padding:"8px 11px",background:T.roseDim,border:`1px solid ${T.rose}44`,borderRadius:7,marginBottom:16,fontSize:12,color:T.rose}}>
              {Ic.alert(12)}{resetError}
            </div>
          )}
          <button onClick={handleForgotSubmit} disabled={resetLoading} style={{
            width:"100%",padding:"11px",borderRadius:9,border:"none",
            background:resetLoading?"rgba(238,36,36,0.6)":"#ee2424",
            color:"#fff",fontSize:13,fontWeight:700,cursor:resetLoading?"default":"pointer",
            transition:"all .15s",boxShadow:resetLoading?"none":"0 2px 12px rgba(238,36,36,0.35)",
          }}
            onMouseEnter={e=>{if(!resetLoading)e.currentTarget.style.background="#d41f1f";}}
            onMouseLeave={e=>{if(!resetLoading)e.currentTarget.style.background="#ee2424";}}
          >
            {resetLoading
              ? <span style={{display:"flex",alignItems:"center",justifyContent:"center",gap:8}}>
                  <svg width="14" height="14" viewBox="0 0 14 14" fill="none" style={{animation:"spin 1s linear infinite"}}><circle cx="7" cy="7" r="5.5" stroke="rgba(255,255,255,0.3)" strokeWidth="1.5"/><path d="M7 1.5A5.5 5.5 0 0112.5 7" stroke="#fff" strokeWidth="1.5" strokeLinecap="round"/></svg>
                  Sending…
                </span>
              : "Send reset link"
            }
          </button>
        </div>
      </div>
    </div>
  );

  /* ── Forgot password — success ── */
  if(forgotMode === "sent") return (
    <div style={{minHeight:"100vh",display:"flex",background:T.bg,fontFamily:"'Geist',sans-serif"}}>
      {leftPanel}
      <div style={{flex:1,display:"flex",alignItems:"center",justifyContent:"center",padding:"40px 60px",overflowY:"auto"}}>
        <div style={{width:"100%",maxWidth:400,textAlign:"center"}}>
          <div style={{width:60,height:60,borderRadius:16,background:"rgba(52,211,153,0.1)",border:"1px solid rgba(52,211,153,0.25)",display:"flex",alignItems:"center",justifyContent:"center",margin:"0 auto 24px"}}>
            <svg width="26" height="26" viewBox="0 0 24 24" fill="none"><path d="M5 13l4 4L19 7" stroke="#34d399" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </div>
          <div style={{fontSize:22,fontWeight:700,color:T.text,marginBottom:10,letterSpacing:"-0.4px"}}>Check your inbox</div>
          <div style={{fontSize:13,color:T.textMuted,lineHeight:1.7,marginBottom:8}}>
            We've sent a password reset link to
          </div>
          <div style={{fontSize:13,fontWeight:600,color:T.text,marginBottom:24,fontFamily:"'Geist Mono',monospace"}}>
            {resetEmail}
          </div>
          <div style={{fontSize:12,color:T.textMuted,lineHeight:1.7,marginBottom:28,padding:"10px 13px",background:T.bgElevated,borderRadius:8,border:`1px solid ${T.border}`}}>
            Didn't get the email? Check your spam folder or contact your IT admin at <span style={{color:T.accent}}>itsupport@jnj.com</span>
          </div>
          <button onClick={()=>{setForgotMode(null);setResetEmail("");setResetError("");}}
            style={{background:"none",border:`1.5px solid ${T.border}`,borderRadius:9,padding:"10px 24px",color:T.text,fontSize:13,fontWeight:600,cursor:"pointer",transition:"border-color .15s"}}
            onMouseEnter={e=>e.currentTarget.style.borderColor=T.accent}
            onMouseLeave={e=>e.currentTarget.style.borderColor=T.border}
          >
            Back to sign in
          </button>
        </div>
      </div>
    </div>
  );

  /* ── Main login form ── */
  return (
    <div style={{
      minHeight:"100vh", display:"flex", background:T.bg,
      fontFamily:"'Geist',sans-serif",
    }}>
      {leftPanel}

      {/* Right panel — login form */}
      <div style={{flex:1,display:"flex",alignItems:"center",justifyContent:"center",padding:"40px 60px",overflowY:"auto"}}>
        <div style={{width:"100%",maxWidth:400}}>
          <div style={{marginBottom:32}}>
            <div style={{fontSize:24,fontWeight:700,color:T.text,marginBottom:8,letterSpacing:"-0.4px"}}>Sign in</div>
            <div style={{fontSize:13,color:T.textMuted}}>Access your J&amp;J data governance workspace</div>
          </div>

          {/* Email */}
          <div style={{marginBottom:16}}>
            <label style={{display:"block",fontSize:12,fontWeight:600,color:T.textSub,marginBottom:6}}>Work email</label>
            <input
              type="email" value={email} onChange={e=>{setEmail(e.target.value);setError("");}}
              onKeyDown={e=>e.key==="Enter"&&handleSubmit()}
              placeholder="you@jnj.com"
              style={{width:"100%",padding:"10px 13px",background:T.bgSurface,border:`1.5px solid ${error&&!email?T.rose:T.border}`,borderRadius:9,color:T.text,fontSize:13,outline:"none",boxSizing:"border-box",transition:"border-color .15s"}}
              onFocus={e=>e.target.style.borderColor=T.accent}
              onBlur={e=>e.target.style.borderColor=error&&!email?T.rose:T.border}
            />
          </div>

          {/* Password */}
          <div style={{marginBottom:12}}>
            <div style={{display:"flex",justifyContent:"space-between",marginBottom:6}}>
              <label style={{fontSize:12,fontWeight:600,color:T.textSub}}>Password</label>
              <button onClick={()=>{setForgotMode("form");setResetEmail(email);setResetError("");}}
                style={{background:"none",border:"none",fontSize:12,color:T.accent,cursor:"pointer",padding:0}}>
                Forgot password?
              </button>
            </div>
            <div style={{position:"relative"}}>
              <input
                type={showPw?"text":"password"} value={password} onChange={e=>{setPassword(e.target.value);setError("");}}
                onKeyDown={e=>e.key==="Enter"&&handleSubmit()}
                placeholder="••••••••"
                style={{width:"100%",padding:"10px 40px 10px 13px",background:T.bgSurface,border:`1.5px solid ${error&&!password?T.rose:T.border}`,borderRadius:9,color:T.text,fontSize:13,outline:"none",boxSizing:"border-box",transition:"border-color .15s"}}
                onFocus={e=>e.target.style.borderColor=T.accent}
                onBlur={e=>e.target.style.borderColor=error&&!password?T.rose:T.border}
              />
              <button onClick={()=>setShowPw(v=>!v)} style={{position:"absolute",right:10,top:"50%",transform:"translateY(-50%)",background:"none",border:"none",color:T.textMuted,cursor:"pointer",display:"flex",padding:4}}>
                {showPw
                  ? <svg width="15" height="15" viewBox="0 0 16 16" fill="none"><path d="M2 8s2.5-5 6-5 6 5 6 5-2.5 5-6 5-6-5-6-5z" stroke="currentColor" strokeWidth="1.3"/><circle cx="8" cy="8" r="2" stroke="currentColor" strokeWidth="1.3"/><path d="M3 3l10 10" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round"/></svg>
                  : <svg width="15" height="15" viewBox="0 0 16 16" fill="none"><path d="M2 8s2.5-5 6-5 6 5 6 5-2.5 5-6 5-6-5-6-5z" stroke="currentColor" strokeWidth="1.3"/><circle cx="8" cy="8" r="2" stroke="currentColor" strokeWidth="1.3"/></svg>
                }
              </button>
            </div>
          </div>

          {/* Remember me */}
          <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:8}}>
            <div onClick={()=>setRememberMe(v=>!v)} style={{
              width:16,height:16,borderRadius:4,border:`1.5px solid ${rememberMe?T.accent:T.border}`,
              background:rememberMe?T.accent:"transparent",cursor:"pointer",flexShrink:0,
              display:"flex",alignItems:"center",justifyContent:"center",transition:"all .15s",
            }}>
              {rememberMe && <svg width="10" height="10" viewBox="0 0 10 10" fill="none"><path d="M2 5l2.5 2.5L8 3" stroke="#fff" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/></svg>}
            </div>
            <span onClick={()=>setRememberMe(v=>!v)} style={{fontSize:12,color:T.textSub,cursor:"pointer",userSelect:"none"}}>Remember me on this device</span>
          </div>

          {/* Error */}
          {error && (
            <div style={{display:"flex",alignItems:"center",gap:7,padding:"8px 11px",background:T.roseDim,border:`1px solid ${T.rose}44`,borderRadius:7,marginBottom:16,fontSize:12,color:T.rose}}>
              {Ic.alert(12)}{error}
            </div>
          )}

          {/* Sign in button */}
          <button onClick={handleSubmit} disabled={loading} style={{
            width:"100%",padding:"11px",marginTop:8,borderRadius:9,border:"none",
            background:loading?"rgba(238,36,36,0.6)":"#ee2424",
            color:"#fff",fontSize:13,fontWeight:700,cursor:loading?"default":"pointer",
            transition:"all .15s",letterSpacing:"0.01em",
            boxShadow:loading?"none":"0 2px 12px rgba(238,36,36,0.35)",
          }}
            onMouseEnter={e=>{if(!loading)e.currentTarget.style.background="#d41f1f";}}
            onMouseLeave={e=>{if(!loading)e.currentTarget.style.background="#ee2424";}}
          >
            {loading
              ? <span style={{display:"flex",alignItems:"center",justifyContent:"center",gap:8}}>
                  <svg width="14" height="14" viewBox="0 0 14 14" fill="none" style={{animation:"spin 1s linear infinite"}}><circle cx="7" cy="7" r="5.5" stroke="rgba(255,255,255,0.3)" strokeWidth="1.5"/><path d="M7 1.5A5.5 5.5 0 0112.5 7" stroke="#fff" strokeWidth="1.5" strokeLinecap="round"/></svg>
                  Signing in…
                </span>
              : "Sign in"
            }
          </button>

          {/* Demo hint */}
          <div style={{marginTop:20,padding:"10px 13px",background:T.bgElevated,borderRadius:8,border:`1px solid ${T.border}`}}>
            <div style={{fontSize:11,color:T.textMuted,lineHeight:1.6}}>
              <strong style={{color:T.textSub}}>Demo accounts —</strong> use any demo email (e.g. <span style={{fontFamily:"'Geist Mono',monospace"}}>alex.rivera@jnj.com</span>) with its password (e.g. <span style={{fontFamily:"'Geist Mono',monospace"}}>admin123</span>). Your role is determined by your account.
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};


// ─── Settings helper constants & micro-components ───
const HEALTH_COLOR = {healthy:"#34d399", running:"#60a5fa", degraded:"#fbbf24", disconnected:"#f87171", warning:"#fbbf24"};
const STATUS_LABEL = {connected:"Connected", running:"Running", warning:"Warning", disconnected:"Disconnected"};

/* shared micro-components */
const SettSH = ({icon,title,desc,action}) => (
  <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",marginBottom:22}}>
    <div style={{display:"flex",alignItems:"center",gap:12}}>
      <div style={{width:34,height:34,borderRadius:9,background:T.accentDim,border:`1px solid ${T.accent}33`,display:"flex",alignItems:"center",justifyContent:"center",color:T.accent,flexShrink:0}}>
        {icon}
      </div>
      <div>
        <div style={{fontSize:15,fontWeight:700,color:T.text}}>{title}</div>
        <div style={{fontSize:12,color:T.textMuted,marginTop:1}}>{desc}</div>
      </div>
    </div>
    {action}
  </div>
);

const Toggle = ({on,onChange,disabled=false}) => (
  <div onClick={disabled?null:onChange} style={{width:36,height:20,borderRadius:10,flexShrink:0,cursor:disabled?"default":"pointer",transition:"background .2s",opacity:disabled?.5:1,
    background:on?T.accent:T.bgHover,border:`1px solid ${on?T.accent:T.border}`,position:"relative"}}>
    <div style={{position:"absolute",width:14,height:14,borderRadius:"50%",background:"#fff",top:2,transition:"left .18s",left:on?18:2,boxShadow:"0 1px 3px rgba(0,0,0,.3)"}}/>
  </div>
);

const AddBtn = ({label,onClick}) => (
  <button onClick={onClick} style={{display:"flex",alignItems:"center",gap:5,padding:"6px 12px",borderRadius:7,background:T.accent,border:"none",color:"#fff",fontSize:12,fontWeight:600,cursor:"pointer"}}
    onMouseEnter={e=>e.currentTarget.style.opacity=".85"} onMouseLeave={e=>e.currentTarget.style.opacity="1"}>
    <svg width="11" height="11" viewBox="0 0 12 12" fill="none"><path d="M6 1v10M1 6h10" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round"/></svg>{label}
  </button>
);

const HealthBadge = ({health,status}) => {
  const c=HEALTH_COLOR[health]||T.textMuted;
  return <span style={{display:"inline-flex",alignItems:"center",gap:4,fontSize:10.5,fontWeight:600,padding:"2px 9px",borderRadius:99,background:`${c}15`,border:`1px solid ${c}33`,color:c}}>
    <span style={{width:5,height:5,borderRadius:"50%",background:c,display:"inline-block"}}/>
    {STATUS_LABEL[status]||status}
  </span>;
};

// ─────────────────────────────────────────────
// SETTINGS HELPER COMPONENTS (top-level to satisfy Rules of Hooks)
// ─────────────────────────────────────────────
const RunRow = ({run, onShowLogs}) => {
  const [expanded, setExpanded] = useState(false);
  const sc = run.status==="success"?T.accent:run.status==="failed"?T.rose:run.status==="running"?"#60a5fa":T.amber;
  return (
    <div style={{background:T.bgElevated,border:`1px solid ${run.status==="failed"?T.rose+"44":T.border}`,borderRadius:9,overflow:"hidden"}}>
      <div onClick={()=>setExpanded(v=>!v)} style={{display:"flex",alignItems:"center",gap:10,padding:"10px 12px",cursor:"pointer"}}>
        <span style={{width:8,height:8,borderRadius:"50%",background:sc,flexShrink:0,boxShadow:`0 0 5px ${sc}`}}/>
        <div style={{flex:1}}>
          <div style={{display:"flex",alignItems:"center",gap:8}}>
            <span style={{fontSize:12,fontWeight:500,color:T.text}}>{run.ts}</span>
            <span style={{fontSize:10,color:T.textMuted,fontFamily:"'Geist Mono',monospace",background:T.bgSurface,border:`1px solid ${T.border}`,borderRadius:4,padding:"1px 5px"}}>{run.id}</span>
          </div>
          <div style={{display:"flex",gap:10,fontSize:10,color:T.textMuted,marginTop:2}}>
            {run.duration&&run.duration!=="—"&&<span>{run.duration}</span>}
            {run.records>0&&<span>{run.records.toLocaleString()} records</span>}
            {run.errors>0&&<span style={{color:T.rose}}>{run.errors} error{run.errors>1?"s":""}</span>}
            {run.warnings>0&&<span style={{color:T.amber}}>{run.warnings} warning{run.warnings>1?"s":""}</span>}
          </div>
        </div>
        <span style={{fontSize:10,fontWeight:700,color:sc,textTransform:"capitalize",flexShrink:0}}>{run.status}</span>
        <svg width="10" height="10" viewBox="0 0 10 10" fill="none" style={{transform:expanded?"rotate(180deg)":"none",transition:"transform .2s",color:T.textMuted,flexShrink:0}}>
          <path d="M2 3.5l3 3 3-3" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round"/>
        </svg>
      </div>
      {expanded&&(
        <div style={{borderTop:`1px solid ${T.border}`}}>
          {/* Stats row */}
          <div style={{display:"flex",gap:0,borderBottom:`1px solid ${T.border}`}}>
            {[{l:"Records",v:run.records?.toLocaleString()||"0"},{l:"Duration",v:run.duration||"—"},{l:"Errors",v:run.errors||0},{l:"Warnings",v:run.warnings||0}].map((m,i,a)=>(
              <div key={m.l} style={{flex:1,textAlign:"center",padding:"10px 0",borderRight:i<a.length-1?`1px solid ${T.border}`:"none"}}>
                <div style={{fontSize:13,fontWeight:700,color:m.l==="Errors"&&m.v>0?T.rose:m.l==="Warnings"&&m.v>0?T.amber:T.text}}>{m.v}</div>
                <div style={{fontSize:9.5,color:T.textMuted,marginTop:1}}>{m.l}</div>
              </div>
            ))}
          </div>
          {/* Error/warning message */}
          {(run.errorMsg||run.warnMsg)&&(
            <div style={{padding:"8px 12px",borderBottom:`1px solid ${T.border}`}}>
              <div style={{padding:"7px 10px",background:run.errorMsg?T.roseDim:T.amberDim,borderRadius:6,fontSize:11,color:run.errorMsg?T.rose:T.amber,fontFamily:"'Geist Mono',monospace"}}>
                {run.errorMsg||run.warnMsg}
              </div>
            </div>
          )}
          {/* View logs button */}
          {onShowLogs&&(
            <div style={{padding:"8px 12px",display:"flex",justifyContent:"flex-end"}}>
              <button onClick={e=>{e.stopPropagation();onShowLogs(run);}}
                style={{display:"inline-flex",alignItems:"center",gap:5,padding:"5px 12px",borderRadius:7,background:T.bgSurface,border:`1px solid ${T.border}`,color:T.textSub,fontSize:11.5,cursor:"pointer",fontWeight:500,transition:"all .12s"}}
                onMouseEnter={e=>{e.currentTarget.style.borderColor=T.accent;e.currentTarget.style.color=T.accent;}}
                onMouseLeave={e=>{e.currentTarget.style.borderColor=T.border;e.currentTarget.style.color=T.textSub;}}>
                <svg width="11" height="11" viewBox="0 0 12 12" fill="none"><rect x="1.5" y="2.5" width="9" height="7" rx="1.5" stroke="currentColor" strokeWidth="1.2"/><path d="M4 5.5h4M4 7.5h2.5" stroke="currentColor" strokeWidth="1.2" strokeLinecap="round"/></svg>
                View Full Logs
              </button>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

