const WF_CATS = ["All", "Ingestion", "Quality", "Lineage", "Governance", "Analytics"];

const TASK_TYPES = ["field_updated","stewardship_request","needs_attention","tag_review","certification_review","orphan_assignment"];
// Phase 3 — work-item categories (color-coded grouping by kind of work)
const TYPE_CATEGORY = {
  policy_violation:"violation", dq_alert:"violation",
  tag_review:"approval", certification_review:"approval",
  assigned:"ownership", stewardship_request:"ownership", needs_attention:"ownership", orphan_assignment:"ownership",
  field_updated:"curation",
};
const CATEGORY_META = {
  violation:     {label:"Violation",      color:"#dc2626"},
  approval:      {label:"Approval",       color:"#2563eb"},
  ownership:     {label:"Ownership",      color:"#0d9488"},
  curation:      {label:"Curation",       color:"#8b5cf6"},
  classification:{label:"Classification", color:"#d97706"},
};
const itemCategory = (item) => TYPE_CATEGORY[item?.type] || "curation";
// Role model — every work item is whose job: Steward DOES, Owner DECIDES, FYI = awareness.
const ITEM_ROLE = {
  tag_review:"steward", dq_alert:"steward", policy_violation:"steward",
  certification_review:"owner", stewardship_request:"owner", orphan_assignment:"owner", needs_attention:"owner",
  field_updated:"fyi", assigned:"fyi",
};
const ROLE_META = {
  steward:{label:"STEWARD", color:"#0d9488", bg:"rgba(13,148,136,0.12)"},
  owner:  {label:"OWNER",   color:"#b45309", bg:"rgba(180,83,9,0.12)"},
  fyi:    {label:"FYI",     color:"#64748b", bg:"rgba(100,116,139,0.12)"},
};
const itemRole = (item) => ITEM_ROLE[item?.type] || "steward";
// Phase 4 — work-item actions that actually write ownership fields on the asset.
const assignOwnership = (assetName, handle, role) => {
  const a = ASSETS.find(x => x.name===assetName);
  if(!a || !handle) return false;
  const field = role==="owner" ? "owners" : "stewards";
  if(!Array.isArray(a[field])) a[field] = a[field] ? [a[field]] : [];
  if(!a[field].includes(handle)) a[field].push(handle);
  if(role==="owner") a.owner = a.owners[0]; else a.steward = a.stewards[0];
  return true;
};
const certifyAsset = (assetName) => { const a=ASSETS.find(x=>x.name===assetName); if(a) a.cert="Approved"; return !!a; };
const InboxView = ({onToast}) => {
  const onNav = useNav();
  const [items,      setItems]      = useState([...POLICY_VIOLATION_INBOX, ...TAG_REVIEW_INBOX, ...CERT_REVIEW_INBOX, ...ORPHAN_INBOX, ...INBOX_DATA]);
  const [filter,     setFilter]     = useState("all");
  const [viewMode,   setViewMode]   = useState("list"); // "list" | "kanban"
  const [sel,          setSel]          = useState(null);
  const [assignOpen,   setAssignOpen]   = useState(false);
  const [filterOpen,   setFilterOpen]   = useState(false);
  const [secFilters,   setSecFilters]   = useState(new Set()); // section multiselect

  const unread = items.filter(i=>!i.readAt);
  const read   = items.filter(i=>!!i.readAt);
  const counts = {
    all:        unread.length,
    tasks:      unread.filter(i=>TASK_TYPES.includes(i.type)).length,
    alerts:     unread.filter(i=>i.type==="dq_alert").length,
    violations: unread.filter(i=>i.type==="policy_violation").length,
    assigned:   unread.filter(i=>i.type==="assigned").length,
    done:       read.length,
  };
  const secFilterActive = secFilters.size > 0;
  const shown = unread.filter(i=>{
    // tab filter
    if(filter==="tasks"     &&!TASK_TYPES.includes(i.type)) return false;
    if(filter==="alerts"    &&i.type!=="dq_alert")          return false;
    if(filter==="violations"&&i.type!=="policy_violation")  return false;
    if(filter==="assigned"  &&i.type!=="assigned")          return false;
    if(filter==="done")                                     return false;
    // section multiselect filter
    if(secFilterActive && !secFilters.has(i.section)) return false;
    return true;
  });
  const isDoneFilter = filter==="done";
  const SECTIONS = [
    {k:"catalog",  l:"Catalog"},
    {k:"quality",  l:"Data Quality"},
    {k:"policy",   l:"Policy"},
    {k:"glossary", l:"Glossary"},
    {k:"tags",     l:"Tags"},
    {k:"connections", l:"Connections"},
  ];
  const toggleSec = s => setSecFilters(prev=>{ const n=new Set(prev); n.has(s)?n.delete(s):n.add(s); return n; });

  const selItem = items.find(i=>i.id===sel)||null;
  const selIdx  = shown.findIndex(i=>i.id===sel);
  const navPrev = ()=>{ if(selIdx>0) { setSel(shown[selIdx-1].id); setAssignOpen(false); }};
  const navNext = ()=>{ if(selIdx<shown.length-1) { setSel(shown[selIdx+1].id); setAssignOpen(false); }};

  const ack     = (id,msg)=>{ setItems(p=>p.map(i=>i.id===id?{...i,readAt:new Date().toISOString()}:i)); setSel(null); setAssignOpen(false); onToast(msg||"Acknowledged","success"); };
  const dism    = id      =>{ setItems(p=>p.map(i=>i.id===id?{...i,readAt:new Date().toISOString()}:i)); setSel(null); setAssignOpen(false); };
  const markAll = ()      =>{ setItems(p=>p.map(i=>({...i,readAt:i.readAt||new Date().toISOString()}))); setSel(null); setAssignOpen(false); onToast("All caught up","success"); };

  const SEV = {
    high:  {c:T.rose,    bg:`${T.rose}12`,         label:"HIGH"},
    medium:{c:T.amber,   bg:`${T.amber}12`,         label:"MED"},
    low:   {c:T.blue,    bg:`${T.blue}0d`,          label:"INFO"},
    info:  {c:"#8b5cf6", bg:"rgba(139,92,246,.1)",  label:"NEW"},
  };
  const TYPE_META = {
    dq_alert:            {icon:sz=>Ic.quality(sz||12),  label:"DQ Alert",       shortLabel:"DQ Alert"},
    field_updated:       {icon:sz=>Ic.edit(sz||12),     label:"Field Updated",  shortLabel:"Updated"},
    assigned:            {icon:sz=>Ic.steward(sz||12),  label:"New Assignment", shortLabel:"Assigned"},
    needs_attention:     {icon:sz=>Ic.alert(sz||12),    label:"Needs Steward",  shortLabel:"Action"},
    stewardship_request: {icon:sz=>Ic.persona(sz||12),  label:"Access Request", shortLabel:"Request"},
    policy_violation:    {icon:sz=>Ic.policies(sz||12), label:"Policy Violation",shortLabel:"Violation"},
    tag_review:          {icon:sz=>Ic.tag(sz||12),     label:"Tag Review",     shortLabel:"Tag"},
    certification_review:{icon:sz=>Ic.cert(sz||12),    label:"Certification",  shortLabel:"Cert"},
    orphan_assignment:   {icon:sz=>Ic.steward(sz||12), label:"Orphan — Assign Owner", shortLabel:"Orphan"},
  };

  /* ── Action row — only inside detail panel ── */
  const ActionRow = ({item}) => {
    const btn = (label,onClick,primary=false,danger=false)=>(
      <button onClick={onClick} style={{padding:"7px 18px",borderRadius:7,background:primary?T.accent:"transparent",border:primary?"none":danger?`1px solid ${T.rose}55`:`1px solid ${T.border}`,color:primary?"#fff":danger?T.rose:T.textSub,fontSize:12,fontWeight:primary?600:500,cursor:"pointer",whiteSpace:"nowrap",transition:"opacity .1s"}}
        onMouseEnter={e=>e.currentTarget.style.opacity="0.8"} onMouseLeave={e=>e.currentTarget.style.opacity="1"}>
        {label}
      </button>
    );
    if(item.type==="dq_alert")
      return <>{btn("View DQ Dashboard",()=>onToast("Opening Data Quality","success"),true)}{btn("Dismiss",()=>dism(item.id))}</>;
    if(item.type==="field_updated")
      return <>{btn("Acknowledge",()=>ack(item.id),true)}{btn("Open Asset",()=>onToast("Opening asset","success"))}</>;
    if(item.type==="assigned")
      return <>{btn("View Asset",()=>onToast("Opening asset","success"),true)}{btn("Acknowledge",()=>ack(item.id))}</>;
    if(item.type==="stewardship_request")
      return <>{btn("Accept",()=>{const role=item.requestedRole==="Owner"?"owner":"steward";assignOwnership(item.asset.name,item.requestedBy,role);ack(item.id,`${item.requestedBy} added as ${item.requestedRole} of ${item.asset.name}`);},true)}{btn("Decline",()=>ack(item.id,"Request declined"),false,true)}</>;
    if(item.type==="needs_attention")
      return <>{btn("Assign Steward",()=>setAssignOpen(a=>!a),true)}{btn("Dismiss",()=>dism(item.id))}</>;
    if(item.type==="policy_violation")
      return <>{btn("View Policy",()=>{onNav&&onNav("policymanager",{policyId:item.policyId});},true)}{btn("Mark In Progress",()=>ack(item.id,"Violation moved to In Progress"))}</>;
    if(item.type==="tag_review")
      return <>{btn("Review in Tags",()=>{onNav&&onNav("tags");},true)}{btn("Approve",()=>ack(item.id,"Tag change approved"))}{btn("Dismiss",()=>dism(item.id))}</>;
    if(item.type==="certification_review")
      return <>{btn("Review & Certify",()=>{certifyAsset(item.asset.name);ack(item.id,`${item.asset.name} certified as Approved`);},true)}{btn("Defer",()=>dism(item.id))}</>;
    if(item.type==="orphan_assignment")
      return <>{btn("Assign Owner",()=>setAssignOpen(a=>!a),true)}{btn("Deprecate",()=>ack(item.id,"Asset deprecated"),false,true)}</>;
    return null;
  };

  /* ── Shared detail content (list + kanban) ── */
  const DetailContent = ({item}) => {
    if(!item) return null;
    const person = item.changedBy||item.assignedBy||item.requestedBy||null;
    const initials = person ? person.split(".").map(s=>s[0]?.toUpperCase()||"").join("").slice(0,2) : "?";
    const personRole = item.type==="field_updated"?"Made a field update":item.type==="assigned"?"Assigned this to you":item.type==="stewardship_request"?"Requested steward access":item.type==="needs_attention"?"Flagged for attention":"Last activity";
    return (
      <div style={{display:"flex",flexDirection:"column",height:"100%",overflow:"hidden"}}>
        {/* Scrollable body */}
        <div style={{flex:1,overflowY:"auto",padding:"16px 18px"}}>
          {/* Asset type + time row */}
          <div style={{display:"flex",alignItems:"center",gap:6,flexWrap:"wrap",marginBottom:14}}>
            <TypeBadge type={item.asset.type}/>
            <span style={{fontSize:11,color:T.textMuted}}>{item.timeAgo}</span>
          </div>

          {/* Person row */}
          {person&&(
            <div style={{display:"flex",alignItems:"center",gap:10,padding:"10px 13px",background:T.bgElevated,border:`1px solid ${T.border}`,borderRadius:8,marginBottom:16}}>
              <div style={{width:28,height:28,borderRadius:"50%",background:T.accent+"22",border:`1px solid ${T.accent}44`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:10,fontWeight:700,color:T.accent,flexShrink:0}}>{initials}</div>
              <div>
                <div style={{fontSize:12,fontWeight:600,color:T.text}}>{person}</div>
                <div style={{fontSize:10.5,color:T.textMuted,marginTop:1}}>{personRole}</div>
              </div>
            </div>
          )}

          {/* Body text */}
          {item.body&&<div style={{fontSize:12.5,color:T.textSub,lineHeight:1.65,marginBottom:16}}>{item.body}</div>}

          {/* DQ failures */}
          {item.failures&&(
            <div style={{marginBottom:16,background:`${T.rose}08`,borderRadius:8,padding:"12px 14px",border:`1px solid ${T.rose}22`}}>
              <div style={{fontSize:10,fontWeight:700,color:T.rose,textTransform:"uppercase",letterSpacing:"0.08em",marginBottom:9}}>Failed Checks</div>
              {item.failures.map((f,fi)=>(
                <div key={fi} style={{display:"flex",alignItems:"flex-start",gap:8,fontSize:12,color:T.textSub,marginBottom:fi<item.failures.length-1?8:0}}>
                  <span style={{width:5,height:5,borderRadius:"50%",background:T.rose,flexShrink:0,marginTop:5}}/>
                  {f}
                </div>
              ))}
            </div>
          )}

          {/* Field diff */}
          {item.diff&&(
            <div style={{marginBottom:16,background:T.bgElevated,borderRadius:8,padding:"12px 14px",border:`1px solid ${T.border}`}}>
              <div style={{fontSize:10,fontWeight:700,color:T.textMuted,textTransform:"uppercase",letterSpacing:"0.08em",marginBottom:9}}>{item.diff.field} changed</div>
              <div style={{display:"flex",flexDirection:"column",gap:6}}>
                <div style={{fontSize:12,color:T.rose,background:`${T.rose}0d`,borderRadius:5,padding:"7px 11px",borderLeft:`2px solid ${T.rose}`}}>
                  <span style={{fontSize:9.5,fontWeight:700,color:T.textMuted,marginRight:8,textTransform:"uppercase"}}>Before</span>{item.diff.before}
                </div>
                <div style={{fontSize:12,color:"#16a34a",background:"rgba(22,163,74,.08)",borderRadius:5,padding:"7px 11px",borderLeft:"2px solid #16a34a"}}>
                  <span style={{fontSize:9.5,fontWeight:700,color:T.textMuted,marginRight:8,textTransform:"uppercase"}}>After</span>{item.diff.after}
                </div>
              </div>
            </div>
          )}

          {/* Assign picker — needs_attention (steward) + orphan_assignment (owner) */}
          {(item.type==="needs_attention"||item.type==="orphan_assignment")&&assignOpen&&(()=>{
            const role = item.type==="orphan_assignment" ? "owner" : "steward";
            const roleL = role==="owner" ? "Owner" : "Steward";
            return (
            <div style={{marginBottom:16,background:T.bgElevated,borderRadius:8,padding:"12px 14px",border:`1px solid ${T.border}`}}>
              <div style={{fontSize:11,color:T.textSub,marginBottom:10}}>Assign {role} to <b style={{color:T.text}}>{item.asset.name}</b></div>
              <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
                {["priya.nair","dev.patel","maya.chen","sarah.kim","alex.wu","james.oh"].map(u=>(
                  <button key={u} onClick={()=>{const ok=assignOwnership(item.asset.name,u,role);setAssignOpen(false);ack(item.id,ok?`${u} assigned as ${roleL} of ${item.asset.name}`:`${u} assigned as ${roleL}`);}}
                    style={{padding:"5px 13px",borderRadius:6,background:T.bgSurface,border:`1px solid ${T.border}`,color:T.textSub,fontSize:12,cursor:"pointer",transition:"all .1s"}}
                    onMouseEnter={e=>{e.currentTarget.style.borderColor=T.accent;e.currentTarget.style.color=T.accent;}}
                    onMouseLeave={e=>{e.currentTarget.style.borderColor=T.border;e.currentTarget.style.color=T.textSub;}}>
                    {u}
                  </button>
                ))}
              </div>
            </div>
            );
          })()}
        </div>

        {/* Sticky action footer */}
        <div style={{borderTop:`1px solid ${T.border}`,padding:"12px 22px",display:"flex",gap:8,flexWrap:"wrap",flexShrink:0,background:T.bgSurface}}>
          <ActionRow item={item}/>
        </div>
      </div>
    );
  };

  /* ── Compact list tile (click to open detail, no inline actions) ── */
  const Tile = ({item, done=false}) => {
    const sev  = SEV[item.severity]||SEV.low;
    const meta = TYPE_META[item.type]||TYPE_META.field_updated;
    const isSel = sel===item.id;
    const rm = ROLE_META[itemRole(item)]||ROLE_META.steward;
    /* done = reviewed/completed — shown with a green indicator */
    const iconColor  = done ? T.green : sev.c;
    const labelColor = done ? T.green : sev.c;
    const titleColor = done ? T.textSub : T.text;
    const titleWeight= done ? 500 : 600;
    const catColor   = (CATEGORY_META[itemCategory(item)]||CATEGORY_META.curation).color;
    const borderLeft = done ? `3px solid ${T.green}` : `3px solid ${catColor}`;
    return (
      <div onClick={()=>{ setSel(isSel?null:item.id); setAssignOpen(false); }}
        style={{display:"flex",alignItems:"stretch",background:isSel?`${T.accent}08`:T.bgSurface,border:`1px solid ${isSel?T.accent+"44":T.border}`,borderLeft,borderRadius:8,cursor:"pointer",transition:"all .12s",overflow:"hidden",minHeight:64,opacity:1}}
        onMouseEnter={e=>{ if(!isSel)e.currentTarget.style.background=T.bgElevated; }}
        onMouseLeave={e=>{ if(!isSel)e.currentTarget.style.background=T.bgSurface; }}>
        <div style={{flex:1,padding:"10px 14px",minWidth:0}}>
          {/* Row 1: role chip + type label + done chip + time */}
          <div style={{display:"flex",alignItems:"center",gap:5,marginBottom:4}}>
            {!done&&<span style={{fontSize:8.5,fontWeight:800,letterSpacing:"0.04em",color:rm.color,background:rm.bg,borderRadius:4,padding:"1.5px 5px",flexShrink:0}}>{rm.label}</span>}
            <span style={{color:iconColor,display:"flex",alignItems:"center",flexShrink:0}}>{meta.icon()}</span>
            <span style={{fontSize:10.5,fontWeight:600,color:labelColor}}>{meta.label}</span>
            {done&&(
              <span style={{display:"flex",alignItems:"center",gap:3,fontSize:9.5,fontWeight:700,color:T.green,background:`${T.green}14`,border:`1px solid ${T.green}40`,borderRadius:4,padding:"1px 5px"}}>
                <svg width="8" height="8" viewBox="0 0 10 10" fill="none"><path d="M1.5 5.5L3.8 7.8L8.5 2.5" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round"/></svg>
                Done
              </span>
            )}
            <div style={{flex:1}}/>
            <span style={{fontSize:10.5,color:T.textMuted,flexShrink:0}}>{item.timeAgo}</span>
          </div>
          {/* Row 2: title */}
          <div style={{fontSize:12.5,fontWeight:titleWeight,color:titleColor,lineHeight:1.35,marginBottom:4,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{item.title}</div>
          {/* Row 3: asset path + type badge */}
          <div style={{display:"flex",alignItems:"center",gap:6}}>
            <span style={{fontSize:10.5,fontFamily:"'Geist Mono',monospace",color:T.textMuted,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",flex:1}}>{item.asset.path}</span>
            <TypeBadge type={item.asset.type}/>
          </div>
        </div>
        {/* Selected indicator strip */}
        {isSel&&<div style={{width:3,background:T.accent,flexShrink:0}}/>}
      </div>
    );
  };

  /* ── Compact kanban card (click to open detail, no inline actions) ── */
  const KCard = ({item,colC}) => {
    const sev  = SEV[item.severity]||SEV.low;
    const meta = TYPE_META[item.type]||TYPE_META.field_updated;
    const rm   = ROLE_META[itemRole(item)]||ROLE_META.steward;
    const isSel = sel===item.id;
    return (
      <div onClick={()=>{ setSel(isSel?null:item.id); setAssignOpen(false); }}
        style={{background:isSel?`${T.accent}0d`:T.bgSurface,border:`1px solid ${isSel?T.accent+"55":T.border}`,borderTop:`2px solid ${colC}`,borderRadius:8,padding:"11px 12px",marginBottom:7,cursor:"pointer",transition:"all .12s"}}
        onMouseEnter={e=>{ if(!isSel){e.currentTarget.style.boxShadow=`0 3px 12px rgba(0,0,0,.09)`;e.currentTarget.style.transform="translateY(-1px)";}}}
        onMouseLeave={e=>{e.currentTarget.style.boxShadow="none";e.currentTarget.style.transform="none";}}>
        {/* Type + time */}
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:6}}>
          <div style={{display:"flex",alignItems:"center",gap:5}}>
            <div style={{width:16,height:16,borderRadius:4,background:sev.bg,display:"flex",alignItems:"center",justifyContent:"center",color:sev.c,flexShrink:0}}>{meta.icon()}</div>
            <span style={{fontSize:10,fontWeight:700,color:sev.c}}>{meta.shortLabel}</span>
            <span style={{fontSize:8,fontWeight:800,letterSpacing:"0.03em",color:rm.color,background:rm.bg,borderRadius:3,padding:"1px 4px"}}>{rm.label}</span>
          </div>
          <span style={{fontSize:10,color:T.textMuted}}>{item.timeAgo}</span>
        </div>
        {/* Title */}
        <div style={{fontSize:12,fontWeight:600,color:T.text,lineHeight:1.4,marginBottom:5,display:"-webkit-box",WebkitLineClamp:2,WebkitBoxOrient:"vertical",overflow:"hidden"}}>{item.title}</div>
        {/* Asset path */}
        <div style={{fontSize:10.5,fontFamily:"'Geist Mono',monospace",color:T.textMuted,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{item.asset.path}</div>
        {/* Failure count badge */}
        {item.failures&&<div style={{marginTop:6,fontSize:10.5,color:T.rose,fontWeight:500}}>{item.failures.length} failed check{item.failures.length!==1?"s":""}</div>}
      </div>
    );
  };

  /* ── Kanban columns ── */
  const KANBAN_COLS = [
    {id:"assigned",   label:"New Assignments",  c:"#8b5cf6", types:["assigned"]},
    {id:"review",     label:"Pending Review",   c:T.blue,    types:["field_updated"]},
    {id:"action",     label:"Action Required",  c:T.amber,   types:["needs_attention","stewardship_request","tag_review","certification_review","orphan_assignment"]},
    {id:"violations", label:"Policy Violations",c:"#dc2626", types:["policy_violation"]},
    {id:"alerts",     label:"Alerts",           c:T.rose,    types:["dq_alert"]},
  ];

  /* ── Detail panel header — matches ServicePanel pattern ── */
  const DetailHeader = () => {
    if(!selItem) return null;
    const sev  = SEV[selItem.severity]||SEV.low;
    const meta = TYPE_META[selItem.type]||TYPE_META.field_updated;
    return (
      <div style={{padding:"16px 18px 14px",borderBottom:`1px solid ${T.border}`,flexShrink:0}}>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",gap:10}}>
          {/* Left: icon + title + subtitle */}
          <div style={{display:"flex",alignItems:"center",gap:10,minWidth:0}}>
            <div style={{width:36,height:36,borderRadius:9,background:sev.bg,border:`1px solid ${sev.c}22`,display:"flex",alignItems:"center",justifyContent:"center",color:sev.c,flexShrink:0}}>
              {meta.icon(15)}
            </div>
            <div style={{minWidth:0}}>
              <div style={{fontSize:13,fontWeight:700,color:T.text,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{selItem.title}</div>
              <div style={{display:"flex",alignItems:"center",gap:6,marginTop:3}}>
                {(()=>{const rm=ROLE_META[itemRole(selItem)]||ROLE_META.steward;return <span style={{fontSize:8.5,fontWeight:800,letterSpacing:"0.04em",color:rm.color,background:rm.bg,borderRadius:4,padding:"1.5px 5px",flexShrink:0}}>{rm.label}</span>;})()}
                <span style={{fontSize:10.5,color:T.textMuted,fontFamily:"'Geist Mono',monospace",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{meta.label} · {selItem.asset.path}</span>
              </div>
            </div>
          </div>
          {/* Right: severity badge + prev/next + close */}
          <div style={{display:"flex",gap:5,alignItems:"center",flexShrink:0}}>
            <span style={{fontSize:9.5,fontWeight:700,padding:"2px 7px",borderRadius:4,background:sev.bg,color:sev.c,border:`1px solid ${sev.c}30`,letterSpacing:"0.05em"}}>{sev.label}</span>
            <button onClick={navPrev} disabled={selIdx<=0}
              style={{width:26,height:26,borderRadius:6,background:T.bgHover,border:`1px solid ${T.border}`,display:"flex",alignItems:"center",justifyContent:"center",cursor:selIdx<=0?"default":"pointer",opacity:selIdx<=0?0.35:1,color:T.textSub,transition:"all .1s"}}
              onMouseEnter={e=>{if(selIdx>0)e.currentTarget.style.borderColor=T.accent;}}
              onMouseLeave={e=>e.currentTarget.style.borderColor=T.border}>
              <svg width="7" height="10" viewBox="0 0 7 10" fill="none"><path d="M5 1.5L2 5l3 3.5" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round" strokeLinejoin="round"/></svg>
            </button>
            <button onClick={navNext} disabled={selIdx>=shown.length-1}
              style={{width:26,height:26,borderRadius:6,background:T.bgHover,border:`1px solid ${T.border}`,display:"flex",alignItems:"center",justifyContent:"center",cursor:selIdx>=shown.length-1?"default":"pointer",opacity:selIdx>=shown.length-1?0.35:1,color:T.textSub,transition:"all .1s"}}
              onMouseEnter={e=>{if(selIdx<shown.length-1)e.currentTarget.style.borderColor=T.accent;}}
              onMouseLeave={e=>e.currentTarget.style.borderColor=T.border}>
              <svg width="7" height="10" viewBox="0 0 7 10" fill="none"><path d="M2 1.5L5 5 2 8.5" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round" strokeLinejoin="round"/></svg>
            </button>
            <button onClick={()=>{setSel(null);setAssignOpen(false);}}
              style={{width:26,height:26,borderRadius:6,background:T.bgHover,border:`1px solid ${T.border}`,display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer",color:T.textMuted,transition:"all .1s"}}
              onMouseEnter={e=>{e.currentTarget.style.borderColor=T.rose+"66";e.currentTarget.style.color=T.rose;}}
              onMouseLeave={e=>{e.currentTarget.style.borderColor=T.border;e.currentTarget.style.color=T.textMuted;}}>
              <svg width="10" height="10" viewBox="0 0 12 12" fill="none"><path d="M2 2l8 8M10 2L2 10" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/></svg>
            </button>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="fadeUp" style={{height:"100%",display:"flex",flexDirection:"column"}}>
      {/* Topbar — breadcrumb only */}
      <Topbar breadcrumb={[{label:"My Workspace"}]}/>

      {/* Tab bar — tabs (list only) + filter icon + view toggle */}
      <div style={{padding:"0 20px 0 28px",borderBottom:`1px solid ${T.border}`,display:"flex",alignItems:"center",flexShrink:0,background:T.bgSurface,minHeight:44}}>

        {/* Underline tabs — list view only */}
        {viewMode==="list"&&(
          <div style={{display:"flex",alignItems:"center"}}>
            {[["all","All"],["tasks","Tasks"],["alerts","Alerts"],["violations","Violations"],["assigned","Assigned"],["done","Done"]].map(([k,l])=>(
              <button key={k} onClick={()=>{ setFilter(k); setSel(null); setAssignOpen(false); setFilterOpen(false); }}
                style={{padding:"11px 14px",background:"transparent",border:"none",borderBottom:`2px solid ${filter===k?T.accent:"transparent"}`,color:filter===k?T.text:T.textMuted,fontSize:12.5,fontWeight:filter===k?600:400,cursor:"pointer",display:"flex",alignItems:"center",gap:5,transition:"all .12s",whiteSpace:"nowrap"}}>
                {l}
                {counts[k]>0&&<span style={{fontSize:10,fontWeight:700,borderRadius:10,padding:"1px 6px",
                  background: k==="done"?"rgba(22,163,74,.1)":(k==="alerts"||k==="violations")?`${T.rose}18`:T.bgHover,
                  color:      k==="done"?"#16a34a"           :(k==="alerts"||k==="violations")?T.rose        :T.textMuted}}>
                  {counts[k]}
                </span>}
              </button>
            ))}
          </div>
        )}

        <div style={{flex:1}}/>

        {/* Filter icon — list + kanban */}
        <div style={{position:"relative",marginRight:10}}>
            <button onClick={()=>setFilterOpen(o=>!o)}
              style={{display:"flex",alignItems:"center",gap:5,padding:"5px 10px",borderRadius:7,background:filterOpen||secFilterActive?T.accentDim:"transparent",border:`1px solid ${filterOpen||secFilterActive?T.accent:T.border}`,color:filterOpen||secFilterActive?T.accent:T.textSub,cursor:"pointer",fontSize:12,fontWeight:500,transition:"all .12s"}}>
              <svg width="12" height="12" viewBox="0 0 14 14" fill="none"><path d="M1 3h12M3 7h8M5 11h4" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/></svg>
              Filter
              {secFilterActive&&<span style={{fontSize:10,fontWeight:700,background:T.accent,color:"#fff",borderRadius:99,padding:"1px 6px",marginLeft:2}}>{secFilters.size}</span>}
            </button>
            {filterOpen&&(
              <div style={{position:"absolute",top:"calc(100% + 6px)",right:0,zIndex:300,background:T.bgSurface,border:`1px solid ${T.border}`,borderRadius:10,boxShadow:"0 8px 24px rgba(0,0,0,.15)",minWidth:200,padding:"10px 0"}}
                onClick={e=>e.stopPropagation()}>
                <div style={{padding:"4px 14px 8px",fontSize:10,fontWeight:700,color:T.textMuted,textTransform:"uppercase",letterSpacing:"0.08em"}}>Filter by Section</div>
                {SECTIONS.map(({k,l})=>{
                  const checked = secFilters.has(k);
                  return (
                    <label key={k} style={{display:"flex",alignItems:"center",gap:9,padding:"7px 14px",cursor:"pointer",transition:"background .1s"}}
                      onMouseEnter={e=>e.currentTarget.style.background=T.bgHover}
                      onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
                      <div onClick={()=>toggleSec(k)} style={{width:15,height:15,borderRadius:4,border:`1.5px solid ${checked?T.accent:T.border}`,background:checked?T.accent:"transparent",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,transition:"all .12s"}}>
                        {checked&&<svg width="9" height="9" viewBox="0 0 10 10" fill="none"><path d="M1.5 5.5L3.8 7.8L8.5 2.5" stroke="#fff" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round"/></svg>}
                      </div>
                      <span onClick={()=>toggleSec(k)} style={{fontSize:12.5,color:T.text}}>{l}</span>
                    </label>
                  );
                })}
                {secFilterActive&&(
                  <div style={{borderTop:`1px solid ${T.border}`,marginTop:6,padding:"8px 14px 2px"}}>
                    <button onClick={()=>setSecFilters(new Set())} style={{background:"none",border:"none",cursor:"pointer",color:T.rose,fontSize:12,padding:0}}>Clear filters</button>
                  </div>
                )}
              </div>
            )}
          </div>

        {/* View toggle */}
        <div style={{display:"flex",gap:1,background:T.bgElevated,borderRadius:7,border:`1px solid ${T.border}`,padding:2,marginRight:12}}>
          {[["list",<svg width="13" height="13" viewBox="0 0 14 14" fill="none"><path d="M2 4h10M2 7h10M2 10h10" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round"/></svg>],
            ["kanban",<svg width="13" height="13" viewBox="0 0 14 14" fill="none"><rect x="1" y="2" width="3.5" height="10" rx="1" stroke="currentColor" strokeWidth="1.2"/><rect x="5.25" y="2" width="3.5" height="7" rx="1" stroke="currentColor" strokeWidth="1.2"/><rect x="9.5" y="2" width="3.5" height="8.5" rx="1" stroke="currentColor" strokeWidth="1.2"/></svg>]
          ].map(([mode,icon])=>(
            <button key={mode} onClick={()=>{setViewMode(mode);setSel(null);setAssignOpen(false);setFilterOpen(false);}}
              style={{width:28,height:26,borderRadius:5,background:viewMode===mode?T.bgSurface:"transparent",border:viewMode===mode?`1px solid ${T.border}`:"none",display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer",color:viewMode===mode?T.text:T.textMuted,boxShadow:viewMode===mode?"0 1px 3px rgba(0,0,0,.08)":"none",transition:"all .12s"}}>
              {icon}
            </button>
          ))}
        </div>
      </div>

      {/* ── Main content + unified detail panel ── */}
      <div style={{flex:1,display:"flex",overflow:"hidden"}}>

        {/* Left: list or kanban (both fill flex:1) */}
        <div style={{flex:1,overflow:"hidden",display:"flex",flexDirection:"column"}}>

          {/* ── LIST VIEW ── */}
          {viewMode==="list"&&(
            <div style={{flex:1,overflowY:"auto",padding:"20px 24px"}} onClick={()=>filterOpen&&setFilterOpen(false)}>

              {/* Active section filter chips */}
              {secFilterActive&&(
                <div style={{display:"flex",alignItems:"center",gap:6,flexWrap:"wrap",marginBottom:14}}>
                  <span style={{fontSize:11,color:T.textMuted}}>Filtered by:</span>
                  {[...secFilters].map(s=>{
                    const label = SECTIONS.find(x=>x.k===s)?.l||s;
                    return (
                      <span key={s} style={{display:"flex",alignItems:"center",gap:4,fontSize:11.5,fontWeight:500,padding:"3px 10px",borderRadius:99,background:T.accentDim,border:`1px solid ${T.accent}44`,color:T.accent}}>
                        {label}
                        <button onClick={()=>toggleSec(s)} style={{background:"none",border:"none",cursor:"pointer",color:T.accent,fontSize:14,lineHeight:1,padding:0,marginLeft:2}}>×</button>
                      </span>
                    );
                  })}
                  <button onClick={()=>setSecFilters(new Set())} style={{background:"none",border:"none",cursor:"pointer",color:T.textMuted,fontSize:11.5,textDecoration:"underline",padding:0}}>Clear all</button>
                </div>
              )}

              {/* Done tab */}
              {isDoneFilter&&(
                read.length===0?(
                  <div style={{display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",height:220,gap:12}}>
                    <div style={{width:44,height:44,borderRadius:12,background:T.bgElevated,border:`1px solid ${T.border}`,display:"flex",alignItems:"center",justifyContent:"center",color:T.textMuted}}>
                      <svg width="20" height="20" viewBox="0 0 22 22" fill="none"><path d="M3 12L8 17L19 6" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"/></svg>
                    </div>
                    <div style={{fontSize:13,fontWeight:600,color:T.textSub}}>Nothing completed yet</div>
                    <div style={{fontSize:12,color:T.textMuted}}>Completed tasks will appear here</div>
                  </div>
                ):(
                  <div style={{display:"flex",flexDirection:"column",gap:5,maxWidth:sel?9999:820}}>
                    {read.map(item=><Tile key={item.id} item={item} done={true}/>)}
                  </div>
                )
              )}

              {/* All / Tasks / Alerts / Assigned tabs */}
              {!isDoneFilter&&(
                shown.length===0?(
                  <div style={{display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",height:220,gap:12}}>
                    <div style={{width:44,height:44,borderRadius:12,background:T.bgElevated,border:`1px solid ${T.border}`,display:"flex",alignItems:"center",justifyContent:"center",color:T.textMuted}}>{Ic.inbox(20)}</div>
                    <div style={{fontSize:13,fontWeight:600,color:T.textSub}}>You're all caught up</div>
                    <div style={{fontSize:12,color:T.textMuted}}>No pending items</div>
                  </div>
                ):(
                  <div style={{display:"flex",flexDirection:"column",gap:5,maxWidth:sel?9999:820}}>
                    {shown.map(item=><Tile key={item.id} item={item}/>)}
                  </div>
                )
              )}
            </div>
          )}

          {/* ── KANBAN VIEW ── */}
          {viewMode==="kanban"&&(
            <div style={{flex:1,overflowX:"auto",overflowY:"hidden",padding:"18px 20px",display:"flex",gap:12,alignItems:"flex-start"}}>
              {KANBAN_COLS.map(col=>{
                const colItems = unread.filter(i=>col.types.includes(i.type) && (!secFilterActive || secFilters.has(i.section)));
                return (
                  <div key={col.id} style={{width:248,flexShrink:0,display:"flex",flexDirection:"column",height:"100%"}}>
                    <div style={{display:"flex",alignItems:"center",gap:7,padding:"9px 12px",background:T.bgSurface,border:`1px solid ${T.border}`,borderTop:`3px solid ${col.c}`,borderRadius:"8px 8px 0 0",flexShrink:0}}>
                      <span style={{fontSize:12,fontWeight:700,color:T.text,flex:1}}>{col.label}</span>
                      <span style={{fontSize:10,fontWeight:700,background:colItems.length>0?`${col.c}18`:T.bgElevated,color:colItems.length>0?col.c:T.textMuted,borderRadius:10,padding:"1px 7px",border:`1px solid ${colItems.length>0?col.c+"33":T.border}`}}>{colItems.length}</span>
                    </div>
                    <div style={{flex:1,overflowY:"auto",background:T.bgElevated,border:`1px solid ${T.border}`,borderTop:"none",borderRadius:"0 0 8px 8px",padding:"9px 8px 4px"}}>
                      {colItems.length===0?(
                        <div style={{display:"flex",alignItems:"center",justifyContent:"center",height:80,opacity:0.4}}>
                          <span style={{fontSize:11,color:T.textMuted}}>No items</span>
                        </div>
                      ):(
                        colItems.map(item=><KCard key={item.id} item={item} colC={col.c}/>)
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>

        {/* Right: unified detail panel — same width + same header for both list and kanban */}
        {sel&&selItem&&(
          <div className="slideIn" style={{width:440,flexShrink:0,borderLeft:`1px solid ${T.border}`,display:"flex",flexDirection:"column",background:T.bgSurface,overflow:"hidden",boxShadow:"-4px 0 16px rgba(0,0,0,.06)"}}>
            <DetailHeader/>
            <DetailContent item={selItem}/>
          </div>
        )}

      </div>
    </div>
  );
};

const WorkflowView = ({onToast}) => {
  const [cat,      setCat]      = useState("All");
  const [selected, setSelected] = useState(null);
  const [search,   setSearch]   = useState("");
  const [running,  setRunning]  = useState({});

  const wf = selected ? WF_DATA.find(w=>w.id===selected) : null;

  const filtered = WF_DATA.filter(w =>
    (cat==="All" || w.category===cat) &&
    w.name.toLowerCase().includes(search.toLowerCase())
  );

  const statusColor = {success:T.green, running:T.blue, warning:T.amber, failed:T.red};
  const statusBg    = {success:"rgba(74,222,128,.1)", running:"rgba(125,211,252,.1)", warning:"rgba(251,191,36,.1)", failed:"rgba(248,113,113,.1)"};
  const catColor    = {Ingestion:T.blue, Quality:T.amber, Lineage:T.violet, Governance:T.accent, Analytics:T.rose};

  const triggerRun = (id) => {
    setRunning(r=>({...r,[id]:true}));
    onToast("Workflow triggered — running now","success");
    setTimeout(()=>setRunning(r=>{const n={...r};delete n[id];return n;}),3000);
  };

  const StageBar = ({stages, current}) => (
    <div style={{display:"flex",gap:2,marginTop:8}}>
      {stages.map((s,i)=>{
        const done = current===null ? true : i < current;
        const active = i===current;
        return (
          <div key={s} style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",gap:3}}>
            <div style={{height:3,width:"100%",background:active?T.blue:done?T.accent:T.bgHover,borderRadius:2,transition:"background .3s"}}/>
            <span style={{fontSize:9,color:active?T.blue:done?T.accent:T.textMuted,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis",maxWidth:"100%"}}>{s}</span>
          </div>
        );
      })}
    </div>
  );

  return (
    <div className="fadeUp" style={{height:"100%",display:"flex",flexDirection:"column"}}>
      <Topbar breadcrumb={[{label:"Workflow Center"}]} actions={
        <div style={{display:"flex",gap:8}}>
          <Btn small ghost icon={Ic.refresh(12)} onClick={()=>onToast("Workflows refreshed","success")}>Refresh</Btn>
          <Btn icon={Ic.plus(12)} variant="primary" onClick={()=>onToast("New workflow dialog","success")}>New Workflow</Btn>
        </div>
      }/>

      {/* Top stats bar */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(5,1fr)",gap:12,padding:"16px 28px",borderBottom:`1px solid ${T.border}`,flexShrink:0}}>
        {[
          {label:"Total Workflows", value:String(WF_DATA.length),           color:T.text},
          {label:"Running Now",     value:String(WF_DATA.filter(w=>w.status==="running").length), color:T.blue},
          {label:"Healthy",         value:String(WF_DATA.filter(w=>w.status==="success").length), color:T.green},
          {label:"Warnings",        value:String(WF_DATA.filter(w=>w.status==="warning").length), color:T.amber},
          {label:"Failed",          value:String(WF_DATA.filter(w=>w.status==="failed").length),  color:T.red},
        ].map(m=>(
          <div key={m.label} style={{textAlign:"center"}}>
            <div style={{fontSize:22,fontWeight:700,color:m.color,fontFamily:"'Geist Mono',monospace",letterSpacing:"-0.04em"}}>{m.value}</div>
            <div style={{fontSize:10.5,color:T.textMuted,marginTop:2,textTransform:"uppercase",letterSpacing:"0.06em"}}>{m.label}</div>
          </div>
        ))}
      </div>

      <div style={{flex:1,display:"flex",overflow:"hidden"}}>

        {/* ── Left: workflow list ── */}
        <div style={{width:wf?320:undefined,flex:wf?undefined:1,borderRight:wf?`1px solid ${T.border}`:"none",display:"flex",flexDirection:"column",overflow:"hidden"}}>
          {/* Search + category filter */}
          <div style={{padding:"12px 16px",borderBottom:`1px solid ${T.border}`,flexShrink:0}}>
            <div style={{marginBottom:10}}>
              <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search workflows…"
                style={{width:"100%",padding:"7px 12px",background:T.bgElevated,border:`1px solid ${T.border}`,borderRadius:7,color:T.text,fontSize:12,outline:"none",boxSizing:"border-box"}}
                onFocus={e=>e.target.style.borderColor=T.accent} onBlur={e=>e.target.style.borderColor=T.border}/>
            </div>
            <div style={{display:"flex",gap:4,flexWrap:"wrap"}}>
              {WF_CATS.map(c=>(
                <button key={c} onClick={()=>setCat(c)} style={{padding:"3px 10px",fontSize:11,fontWeight:500,borderRadius:99,border:`1px solid ${cat===c?catColor[c]||T.accent:T.border}`,background:cat===c?`rgba(${cat===c&&catColor[c]?catColor[c].replace(/[^\d,]/g,""):"110,231,183"},.12)`:"transparent",color:cat===c?catColor[c]||T.accent:T.textSub,cursor:"pointer",transition:"all .15s"}}>
                  {c}
                </button>
              ))}
            </div>
          </div>

          {/* Workflow cards */}
          <div style={{flex:1,overflowY:"auto",padding:"8px 0"}}>
            {filtered.map(w=>{
              const isSelected = selected===w.id;
              const isRunning  = running[w.id] || w.status==="running";
              return (
                <div key={w.id} onClick={()=>setSelected(isSelected?null:w.id)}
                  style={{padding:"12px 16px",borderBottom:`1px solid ${T.border}`,cursor:"pointer",background:isSelected?T.bgHover:"transparent",borderLeft:`3px solid ${isSelected?T.accent:"transparent"}`,transition:"all .15s"}}
                  onMouseEnter={e=>{if(!isSelected)e.currentTarget.style.background=T.bgElevated;}}
                  onMouseLeave={e=>{if(!isSelected)e.currentTarget.style.background="transparent";}}>

                  <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",gap:8,marginBottom:6}}>
                    <div style={{flex:1,minWidth:0}}>
                      <div style={{fontSize:12.5,fontWeight:600,color:T.text,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{w.name}</div>
                      <div style={{fontSize:10.5,color:T.textMuted,marginTop:1}}>{w.scheduleLabel} · {w.owner}</div>
                    </div>
                    <div style={{display:"flex",alignItems:"center",gap:5,padding:"2px 8px",borderRadius:99,background:statusBg[isRunning?"running":w.status],border:`1px solid ${statusColor[isRunning?"running":w.status]}30`,flexShrink:0}}>
                      {isRunning&&<span style={{width:6,height:6,borderRadius:"50%",background:T.blue,display:"inline-block",animation:"pulse2 1.2s ease infinite"}}/>}
                      <span style={{fontSize:10.5,fontWeight:600,color:statusColor[isRunning?"running":w.status]}}>{isRunning?"Running":w.status}</span>
                    </div>
                  </div>

                  <div style={{display:"flex",gap:12,fontSize:11,color:T.textMuted,marginBottom:6}}>
                    <span>Last: <b style={{color:T.textSub}}>{w.lastRun}</b></span>
                    <span>Next: <b style={{color:T.textSub}}>{w.nextRun}</b></span>
                  </div>

                  {/* Success rate bar */}
                  <div style={{display:"flex",alignItems:"center",gap:6}}>
                    <div style={{flex:1,height:3,background:T.bgHover,borderRadius:2}}>
                      <div style={{height:"100%",width:`${w.successRate}%`,background:w.successRate>=95?T.green:w.successRate>=80?T.amber:T.red,borderRadius:2}}/>
                    </div>
                    <span style={{fontSize:10.5,color:w.successRate>=95?T.green:w.successRate>=80?T.amber:T.red,fontFamily:"'Geist Mono',monospace",minWidth:28,textAlign:"right"}}>{w.successRate}%</span>
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* ── Right: workflow detail ── */}
        {wf && (
          <div className="slideIn" style={{flex:1,display:"flex",flexDirection:"column",overflow:"hidden"}}>
            {/* Detail header */}
            <div style={{padding:"16px 24px",borderBottom:`1px solid ${T.border}`,flexShrink:0}}>
              <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",gap:12}}>
                <div>
                  <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:4}}>
                    <span style={{padding:"2px 8px",fontSize:11,fontWeight:600,borderRadius:99,background:`${catColor[wf.category]||T.accent}18`,color:catColor[wf.category]||T.accent,border:`1px solid ${catColor[wf.category]||T.accent}30`}}>{wf.category}</span>
                    {wf.tags.map(t=><span key={t} style={{padding:"2px 7px",fontSize:10,borderRadius:99,background:T.bgHover,color:T.textMuted,border:`1px solid ${T.border}`}}>{t}</span>)}
                  </div>
                  <div style={{fontSize:16,fontWeight:700,color:T.text,marginBottom:3}}>{wf.name}</div>
                  <div style={{fontSize:12,color:T.textSub,lineHeight:1.6}}>{wf.description}</div>
                </div>
                <div style={{display:"flex",gap:8,flexShrink:0}}>
                  <Btn small ghost onClick={()=>onToast("Workflow paused","success")}>Pause</Btn>
                  <Btn small ghost onClick={()=>onToast("Schedule editor opened","success")}>Schedule</Btn>
                  <Btn small variant="primary" icon={Ic.refresh(12)} onClick={()=>triggerRun(wf.id)}>Run Now</Btn>
                </div>
              </div>

              {/* Stage pipeline */}
              <div style={{marginTop:14,padding:"10px 14px",background:T.bgElevated,border:`1px solid ${T.border}`,borderRadius:8}}>
                <div style={{fontSize:10.5,color:T.textMuted,marginBottom:6,textTransform:"uppercase",letterSpacing:"0.07em"}}>Pipeline Stages</div>
                <StageBar stages={wf.stages} current={wf.currentStage}/>
              </div>
            </div>

            <div style={{flex:1,overflowY:"auto",padding:"16px 24px"}}>

              {/* Stats row */}
              <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10,marginBottom:20}}>
                {[
                  {l:"Success Rate", v:`${wf.successRate}%`, c:wf.successRate>=95?T.green:wf.successRate>=80?T.amber:T.red},
                  {l:"Total Runs",   v:wf.totalRuns,         c:T.blue},
                  {l:"Last Duration",v:wf.duration,          c:T.text},
                  {l:"Owner",        v:wf.owner,             c:T.textSub},
                ].map(s=>(
                  <Card2 key={s.l} style={{padding:"10px 14px"}}>
                    <div style={{fontSize:10,color:T.textMuted,textTransform:"uppercase",letterSpacing:"0.07em",marginBottom:4}}>{s.l}</div>
                    <div style={{fontSize:14,fontWeight:700,color:s.c,fontFamily:"'Geist Mono',monospace"}}>{s.v}</div>
                  </Card2>
                ))}
              </div>

              {/* Run History */}
              <div style={{marginBottom:16}}>
                <div style={{fontSize:12,fontWeight:600,color:T.text,marginBottom:10}}>Run History</div>
                <Card2 style={{overflow:"hidden",padding:0}}>
                  {wf.history.map((r,i)=>(
                    <div key={i} style={{display:"flex",alignItems:"center",gap:12,padding:"10px 16px",borderBottom:i<wf.history.length-1?`1px solid ${T.border}`:"none"}}>
                      {/* Status dot */}
                      <div style={{width:8,height:8,borderRadius:"50%",background:statusColor[r.status],flexShrink:0}}/>
                      {/* Timestamp */}
                      <span style={{fontSize:12,color:T.textSub,minWidth:120,fontFamily:"'Geist Mono',monospace"}}>{r.ts}</span>
                      {/* Status label */}
                      <span style={{fontSize:11,fontWeight:600,color:statusColor[r.status],minWidth:60}}>{r.status}</span>
                      {/* Duration */}
                      <span style={{fontSize:11,color:T.textMuted,minWidth:70,fontFamily:"'Geist Mono',monospace"}}>{r.duration}</span>
                      {/* Records */}
                      {r.records>0&&<span style={{fontSize:11,color:T.textMuted,fontFamily:"'Geist Mono',monospace"}}>{r.records.toLocaleString()} records</span>}
                      {/* Error msg */}
                      {r.msg&&<span style={{fontSize:11,color:T.amber,flex:1,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>⚠ {r.msg}</span>}
                      {/* Spacer */}
                      {!r.msg&&<div style={{flex:1}}/>}
                      {/* Logs btn */}
                      <button style={{background:"transparent",color:T.textMuted,cursor:"pointer",fontSize:11,padding:"2px 8px",borderRadius:5,border:`1px solid ${T.border}`}} onClick={()=>onToast("Opening run logs…","success")}>Logs</button>
                    </div>
                  ))}
                </Card2>
              </div>

              {/* Config */}
              <div>
                <div style={{fontSize:12,fontWeight:600,color:T.text,marginBottom:10}}>Configuration</div>
                <Card2>
                  <div style={{padding:16}}>
                    {[
                      {l:"Source",    v:wf.source},
                      {l:"Schedule",  v:wf.schedule},
                      {l:"Schedule (human)", v:wf.scheduleLabel},
                      {l:"Category",  v:wf.category},
                      {l:"Owner",     v:wf.owner},
                    ].map(c=>(
                      <div key={c.l} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"7px 0",borderBottom:`1px solid ${T.border}`,fontSize:12}}>
                        <span style={{color:T.textMuted}}>{c.l}</span>
                        <span style={{color:T.text,fontFamily:"'Geist Mono',monospace"}}>{c.v}</span>
                      </div>
                    ))}
                    <div style={{marginTop:14,display:"flex",gap:8}}>
                      <Btn small icon={Ic.edit(11)} onClick={()=>onToast("Config editor opened","success")}>Edit Config</Btn>
                      <Btn small variant="danger" onClick={()=>onToast("Workflow deleted","error")}>Delete Workflow</Btn>
                    </div>
                  </div>
                </Card2>
              </div>
            </div>
          </div>
        )}

        {/* Empty state when no workflow selected */}
        {!wf && (
          <div style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",color:T.textMuted,gap:12}}>
            {Ic.workflow(40)}
            <div style={{fontSize:14,fontWeight:500,color:T.textSub}}>Select a workflow to view details</div>
            <div style={{fontSize:12,color:T.textMuted}}>Click any workflow in the list to inspect runs, config, and history</div>
          </div>
        )}
      </div>
    </div>
  );
};

// ─────────────────────────────────────────────
// ─────────────────────────────────────────────
// TAG POLICIES SECTION — inside Settings
// ─────────────────────────────────────────────
const TagPoliciesSection = ({onToast}) => {
  const { tagPolicies, updateTagPolicies } = useTagCtx();
  const [draft, setDraft] = useState({...tagPolicies});
  const [saved, setSaved] = useState(false);

  const doSave = () => {
    updateTagPolicies(draft);
    setSaved(true);
    setTimeout(()=>setSaved(false), 2000);
    onToast('Tag policies saved','success');
  };

  const SH = ({label})=><div style={{fontSize:10.5,fontWeight:700,color:T.textMuted,textTransform:'uppercase',letterSpacing:'0.08em',marginBottom:12,marginTop:20}}>{label}</div>;
  const Row = ({label,desc,right})=>(
    <div style={{display:'flex',alignItems:'flex-start',justifyContent:'space-between',padding:'12px 14px',background:T.bgSurface,border:`1px solid ${T.border}`,borderRadius:8,marginBottom:8}}>
      <div style={{flex:1,marginRight:16}}>
        <div style={{fontSize:12.5,fontWeight:500,color:T.text,marginBottom:2}}>{label}</div>
        <div style={{fontSize:11.5,color:T.textMuted}}>{desc}</div>
      </div>
      {right}
    </div>
  );
  const Toggle = ({on,onChange})=>(
    <div onClick={onChange} style={{width:36,height:20,borderRadius:10,background:on?T.accent:T.border,position:'relative',cursor:'pointer',transition:'background .2s',flexShrink:0}}>
      <div style={{position:'absolute',top:4,left:on?16:4,width:12,height:12,borderRadius:'50%',background:'#fff',transition:'left .2s'}}/>
    </div>
  );

  return (
    <div style={{position:'relative',paddingBottom:80}}>
      <div style={{marginBottom:8}}>
        <div style={{fontSize:15,fontWeight:700,color:T.text}}>Tag policies</div>
        <div style={{fontSize:12,color:T.textSub,marginTop:2}}>Org-wide rules for tag creation, propagation, and stewardship</div>
      </div>

      <SH label="Access control"/>
      <Row label="Who can create custom tags" desc="Controls who can create free-form custom tags to avoid tag sprawl"
        right={<select value={draft.whoCanCreateCustom} onChange={e=>setDraft(d=>({...d,whoCanCreateCustom:e.target.value}))} style={{padding:'5px 9px',borderRadius:6,border:`1px solid ${T.border}`,background:T.bgElevated,color:T.text,fontSize:12,outline:'none'}}>
          <option value="any">Any user</option>
          <option value="stewards">Data stewards only</option>
          <option value="admins">Admins only</option>
        </select>}/>
      <Row label="Who can create business tags" desc="Business tags define domain ownership. Keep creation controlled."
        right={<select style={{padding:'5px 9px',borderRadius:6,border:`1px solid ${T.border}`,background:T.bgElevated,color:T.text,fontSize:12,outline:'none'}}>
          <option>Data stewards only</option>
          <option>Admins only</option>
        </select>}/>
      <Row label="Sensitivity tag application" desc="PII, PHI, PCI-DSS — who can apply these without steward approval"
        right={<select style={{padding:'5px 9px',borderRadius:6,border:`1px solid ${T.border}`,background:T.bgElevated,color:T.text,fontSize:12,outline:'none'}}>
          <option>Data stewards only (recommended)</option>
          <option>Any user (requires approval)</option>
        </select>}/>

      <SH label="Propagation rules"/>
      <Row label="Confirmation threshold" desc="Show impact preview and require explicit confirmation when propagation affects more than N assets"
        right={<div style={{display:'flex',alignItems:'center',gap:6}}>
          <input type="number" value={draft.propagationThreshold} min={1} onChange={e=>setDraft(d=>({...d,propagationThreshold:Number(e.target.value)}))} style={{width:60,padding:'5px 8px',borderRadius:6,border:`1px solid ${T.border}`,background:T.bgElevated,color:T.text,fontSize:12,outline:'none',textAlign:'center'}}/>
          <span style={{fontSize:12,color:T.textMuted}}>assets</span>
        </div>}/>

      {/* Propagation defaults table */}
      <div style={{border:`1px solid ${T.border}`,borderRadius:8,overflow:'hidden',marginBottom:8}}>
        <table style={{width:'100%',borderCollapse:'collapse'}}>
          <thead>
            <tr style={{background:T.bgElevated}}>
              {['Category','Default mode','Stewards can change?','Confirm above'].map(h=>(
                <th key={h} style={{padding:'8px 12px',textAlign:'left',fontSize:10,fontWeight:700,color:T.textMuted,textTransform:'uppercase',letterSpacing:'0.06em'}}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {[
              {cat:'sensitivity',catLabel:'Sensitivity',mode:'both',   modeFixed:true, changeable:'No (locked)',   changeFixed:true,  confirm:'Any propagation', confirmFixed:true},
              {cat:'regulatory', catLabel:'Regulatory', mode:'lineage', modeFixed:false,changeable:'Yes',          changeFixed:false, confirm:'5+ assets',       confirmFixed:false},
              {cat:'business',   catLabel:'Business',   mode:'hierarchy',modeFixed:false,changeable:'Yes',         changeFixed:false, confirm:'10+ assets',      confirmFixed:false},
              {cat:'custom',     catLabel:'Custom',     mode:'none',    modeFixed:true, changeable:'No (locked)',   changeFixed:true,  confirm:'N/A',             confirmFixed:true},
            ].map((row,i,arr)=>{
              const catColors2 = {sensitivity:{bg:T.accentDim,color:T.accent},regulatory:{bg:T.blueDim,color:T.blue},business:{bg:T.amberDim,color:T.amber},custom:{bg:T.bgElevated,color:T.textSub}};
              const cc = catColors2[row.cat];
              return (
                <tr key={row.cat} style={{borderTop:`1px solid ${T.border}`}}>
                  <td style={{padding:'9px 12px'}}><span style={{fontSize:11,padding:'2px 8px',borderRadius:4,background:cc.bg,color:cc.color,fontWeight:500,textTransform:'capitalize'}}>{row.catLabel}</span></td>
                  <td style={{padding:'9px 12px'}}>
                    {row.modeFixed ? <span style={{fontSize:12,color:T.textSub}}>{row.mode}</span> : (
                      <select defaultValue={row.mode} style={{padding:'3px 7px',borderRadius:5,border:`1px solid ${T.border}`,background:T.bgElevated,color:T.text,fontSize:11,outline:'none'}}>
                        <option value="none">None</option>
                        <option value="hierarchy">Hierarchy</option>
                        <option value="lineage">Lineage</option>
                        <option value="both">H + L</option>
                      </select>
                    )}
                  </td>
                  <td style={{padding:'9px 12px'}}>
                    {row.changeFixed ? <span style={{fontSize:12,color:T.textMuted}}>{row.changeable}</span> : (
                      <select defaultValue="Yes" style={{padding:'3px 7px',borderRadius:5,border:`1px solid ${T.border}`,background:T.bgElevated,color:T.text,fontSize:11,outline:'none'}}>
                        <option>Yes</option><option>No</option>
                      </select>
                    )}
                  </td>
                  <td style={{padding:'9px 12px',fontSize:12,color:row.confirmFixed?T.textMuted:T.textSub}}>{row.confirm}</td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      <SH label="Stewardship automation"/>
      <Row label="Auto-assign steward on sensitivity tag" desc="Applying PII, PHI, or PCI-DSS auto-assigns the domain steward if none exists"
        right={<Toggle on={draft.sensitivityAutoAssign} onChange={()=>setDraft(d=>({...d,sensitivityAutoAssign:!d.sensitivityAutoAssign}))}/>}/>
      <Row label="Require approval to remove tags from certified assets" desc="Prevents removing compliance tags from Gold-certified datasets without steward sign-off"
        right={<Toggle on={draft.removalFromCertified==='approval'} onChange={()=>setDraft(d=>({...d,removalFromCertified:d.removalFromCertified==='approval'?'free':'approval'}))}/>}/>
      <Row label="Audit log" desc="Record every tag event in the immutable audit trail"
        right={<Toggle on={draft.auditLogEnabled} onChange={()=>setDraft(d=>({...d,auditLogEnabled:!d.auditLogEnabled}))}/>}/>
      <Row label="Notify steward on large propagation" desc={`In-app notification when a tag propagates to more than ${draft.propagationThreshold} assets`}
        right={<Toggle on={draft.notifyOnLargePropagate} onChange={()=>setDraft(d=>({...d,notifyOnLargePropagate:!d.notifyOnLargePropagate}))}/>}/>

      {/* Sticky save bar */}
      <div style={{position:'sticky',bottom:0,background:T.bgSurface,borderTop:`1px solid ${T.border}`,padding:'12px 0',display:'flex',alignItems:'center',gap:12,marginTop:16}}>
        <button onClick={doSave} style={{padding:'7px 20px',background:T.accent,color:'#fff',border:'none',borderRadius:6,fontSize:12.5,fontWeight:600,cursor:'pointer'}}>Save changes</button>
        <button onClick={()=>setDraft({...tagPolicies})} style={{background:'none',border:'none',color:T.textMuted,fontSize:12,cursor:'pointer'}}>Reset to defaults</button>
        {saved&&<span style={{fontSize:12,color:T.green,fontWeight:500}}>Saved ✓</span>}
      </div>
    </div>
  );
};

